      const userBefore = await repository.findById(userId);
      const vaultKeyBefore = userBefore?.encryptedVaultKey;

      await repository.changeMasterPassword(userId, oldPassword, newPassword);

      const userAfter = await repository.findById(userId);
      const vaultKeyAfter = userAfter?.encryptedVaultKey;

      expect(vaultKeyBefore).not.toBe(vaultKeyAfter);
    });
  });

  describe('hasAnyUsers()', () => {
    it('should return false when no users exist', async () => {
      await db.users.clear();
      const hasUsers = await repository.hasAnyUsers();
      expect(hasUsers).toBe(false);
    });

    it('should return true when users exist', async () => {
      await repository.createUser('test@example.com', 'Password123!');
      const hasUsers = await repository.hasAnyUsers();
      expect(hasUsers).toBe(true);
    });
  });

  describe('Edge cases and error handling', () => {
    it('should handle concurrent user creation with same email', async () => {
      const email = 'concurrent@example.com';

      const promise1 = repository.createUser(email, 'Password1');
      const promise2 = repository.createUser(email, 'Password2');

      const results = await Promise.allSettled([promise1, promise2]);

      const successes = results.filter((r) => r.status === 'fulfilled');
      const failures = results.filter((r) => r.status === 'rejected');

      // At least one should succeed and one should fail
      expect(successes.length).toBeGreaterThanOrEqual(1);
      expect(failures.length).toBeGreaterThanOrEqual(0);
      // Both shouldn't succeed
      expect(successes.length).toBeLessThanOrEqual(1);
    });

    it('should handle very long email addresses', async () => {
      const longEmail = 'a'.repeat(200) + '@example.com';

      const user = await repository.createUser(longEmail, 'Password123!');

      expect(user.email).toBe(longEmail);
    });

    it('should handle very long passwords', async () => {
      const longPassword = 'P@ssw0rd' + 'a'.repeat(500);

      const user = await repository.createUser('test@example.com', longPassword);

      expect(user).toBeDefined();

      const session = await repository.authenticateWithPassword('test@example.com', longPassword);

      expect(session).toBeDefined();
    });
  });
});

/**
 * Breach Results Repository
 * Manages persistent storage of breach check results in IndexedDB
 */

import { db, type StoredBreachResult } from '@/data/storage/database';
import type { BreachCheckResult, BreachData, BreachSeverity } from '@/core/breach/breachTypes';

const CACHE_DURATION = 24 * 60 * 60 * 1000; // 24 hours

/**
 * Saves a breach check result to the database
 */
export async function saveBreachResult(
  credentialId: string,
  checkType: 'password' | 'email',
  result: BreachCheckResult
): Promise<void> {
  const now = Date.now();
  const expiresAt = now + CACHE_DURATION;

  const storedResult: StoredBreachResult = {
    id: `${credentialId}-${checkType}-${now}`,
    credentialId,
    checkType,
    breached: result.breached,
    breachCount: result.breachCount || result.breaches.length,
    severity: result.severity,
    breachNames: result.breaches.map(b => b.name),
    breachData: result.breaches.length > 0 ? JSON.stringify(result.breaches) : '',
    checkedAt: result.checkedAt,
    expiresAt,
  };

  await db.breachResults.put(storedResult);
}

/**
 * Gets the latest breach result for a credential
 */
export async function getBreachResult(
  credentialId: string,
  checkType: 'password' | 'email'
): Promise<BreachCheckResult | null> {
  const results = await db.breachResults
    .where('credentialId')
    .equals(credentialId)
    .and(r => r.checkType === checkType)
    .reverse()
    .sortBy('checkedAt');

  if (results.length === 0) {
    return null;
  }

  const latest = results[0];
  if (!latest) {
    return null;
  }

  // Check if expired
  if (Date.now() >= latest.expiresAt) {
    // Expired - remove it and return null
    await db.breachResults.delete(latest.id);
    return null;
  }

  // Convert stored result back to BreachCheckResult
  return {
    breached: latest.breached,
    breaches: latest.breachData && latest.breachData.length > 0 ? JSON.parse(latest.breachData) as BreachData[] : [],
    severity: latest.severity,
    checkedAt: latest.checkedAt,
    breachCount: latest.breachCount,
  };
}

/**
 * Gets all breach results for a credential (password and email)
 */
export async function getAllBreachResultsForCredential(
  credentialId: string
): Promise<{
  password: BreachCheckResult | null;
  email: BreachCheckResult | null;
}> {
  const [password, email] = await Promise.all([
    getBreachResult(credentialId, 'password'),
    getBreachResult(credentialId, 'email'),
  ]);

  return { password, email };
}

/**
 * Gets all breached credentials with their results
 */
export async function getAllBreachedCredentials(): Promise<
  Array<{
    credentialId: string;
    checkType: 'password' | 'email';
    severity: BreachSeverity;
    breachCount: number;
    breachNames: string[];
    checkedAt: number;
  }>
> {
  const results = await db.breachResults
    .where('breached')
    .equals(1) // IndexedDB stores boolean as 1/0
    .toArray();

  // Filter out expired results
  const now = Date.now();
  const validResults = results.filter(r => now < r.expiresAt);

  // Remove expired results
  const expiredIds = results.filter(r => now >= r.expiresAt).map(r => r.id);
  if (expiredIds.length > 0) {
    await db.breachResults.bulkDelete(expiredIds);
  }

  // Group by credential and get the latest result for each
  const grouped = new Map<string, StoredBreachResult>();

  for (const result of validResults) {
    const key = `${result.credentialId}-${result.checkType}`;
    const existing = grouped.get(key);

    if (!existing || result.checkedAt > existing.checkedAt) {
      grouped.set(key, result);
    }
  }

  return Array.from(grouped.values()).map(r => ({
    credentialId: r.credentialId,
    checkType: r.checkType,
    severity: r.severity,
    breachCount: r.breachCount,
    breachNames: r.breachNames,
    checkedAt: r.checkedAt,
  }));
}

/**
 * Gets breach statistics
 */
export async function getBreachStatistics(): Promise<{
  total: number;
  breached: number;
  safe: number;
  bySeverity: {
    critical: number;
    high: number;
    medium: number;
    low: number;
    safe: number;
  };
}> {
  const allResults = await db.breachResults.toArray();

  // Filter out expired
  const now = Date.now();
  const validResults = allResults.filter(r => now < r.expiresAt);

  // Group by credential to avoid counting duplicates
  const latestByCredential = new Map<string, StoredBreachResult>();

  for (const result of validResults) {
    const key = `${result.credentialId}-${result.checkType}`;
    const existing = latestByCredential.get(key);

    if (!existing || result.checkedAt > existing.checkedAt) {
      latestByCredential.set(key, result);
    }
  }

  const results = Array.from(latestByCredential.values());

  const breached = results.filter(r => r.breached).length;
  const safe = results.filter(r => !r.breached).length;

  const bySeverity = {
    critical: results.filter(r => r.severity === 'critical').length,
    high: results.filter(r => r.severity === 'high').length,
    medium: results.filter(r => r.severity === 'medium').length,
    low: results.filter(r => r.severity === 'low').length,
    safe: results.filter(r => r.severity === 'safe').length,
  };

  return {
    total: results.length,
    breached,
    safe,
    bySeverity,
  };
}

/**
 * Deletes all breach results for a credential
 */
export async function deleteBreachResults(credentialId: string): Promise<void> {
  const results = await db.breachResults.where('credentialId').equals(credentialId).toArray();
  const ids = results.map(r => r.id);

  if (ids.length > 0) {
    await db.breachResults.bulkDelete(ids);
  }
}

/**
 * Cleans up expired breach results
 */
export async function cleanupExpiredResults(): Promise<number> {
  const now = Date.now();
  const expired = await db.breachResults.where('expiresAt').below(now).toArray();

  if (expired.length > 0) {
    const ids = expired.map(r => r.id);
    await db.breachResults.bulkDelete(ids);
  }

  return expired.length;
}

/**
 * Clears all breach results (for testing or reset)
 */
export async function clearAllBreachResults(): Promise<void> {
  await db.breachResults.clear();
}

/**
 * Secure Storage Service using IndexedDB with Dexie
 * Implements encrypted credential storage with Dexie-encrypted
 * 
 * Features:
 * - Transparent encryption/decryption
 * - Offline-first storage
 * - Efficient indexing and querying
 * - Automatic versioning
 */

import Dexie, { type Table } from 'dexie';
import { User, SecuritySettings } from '@/domain/entities/User';

// Database schema interfaces
import type { CredentialCategory } from '@/domain/entities/Credential';

export interface StoredCredential {
  id: string;
  title: string;
  username: string;
  encryptedPassword: string;
  encryptedTotpSecret?: string | undefined; // Encrypted TOTP secret
  encryptedNotes?: string | undefined; // Encrypted notes
  url?: string | undefined;
  notes?: string | undefined; // Legacy unencrypted notes (for backward compat)
  category: CredentialCategory;
  tags: string[];
  createdAt: number; // Store as timestamp
  updatedAt: number;
  lastAccessedAt?: number | undefined;
  isFavorite: boolean;
  securityScore?: number | undefined;

  // Card-specific fields (encrypted)
  encryptedCardNumber?: string | undefined;
  cardholderName?: string | undefined;
  expiryMonth?: string | undefined;
  expiryYear?: string | undefined;
  encryptedCvv?: string | undefined;
  cardType?: 'visa' | 'mastercard' | 'amex' | 'discover' | 'other' | undefined;
  billingAddress?: string | undefined;
}

export interface StoredUser extends Omit<User, 'createdAt' | 'lastLoginAt'> {
  createdAt: number;
  lastLoginAt: number;
}

export interface StoredSession {
  id: string;
  userId: string;
  encryptedVaultKey: string; // Stored encrypted, decrypted in memory
  expiresAt: number;
  isLocked: boolean;
  createdAt: number;
}

export interface StoredBreachResult {
  id: string;
  credentialId: string;
  checkType: 'password' | 'email';
  breached: boolean;
  breachCount: number;
  severity: 'critical' | 'high' | 'medium' | 'low' | 'safe';
  breachNames: string[];
  breachData: string; // JSON stringified BreachData[] (empty string if no data)
  checkedAt: number;
  expiresAt: number;
}

/**
 * TrustVault Database
 * Manages all local storage with encryption
 */
export class TrustVaultDB extends Dexie {
  credentials!: Table<StoredCredential, string>;
  users!: Table<StoredUser, string>;
  sessions!: Table<StoredSession, string>;
  settings!: Table<{ id: string; data: SecuritySettings }, string>;
  breachResults!: Table<StoredBreachResult, string>;

  constructor() {
    super('TrustVaultDB');

    const credentialStoreSchema =
      'id, title, username, category, isFavorite, *tags, createdAt, updatedAt';
    const userStoreSchema = 'id, email, createdAt, biometricEnabled';
    const sessionStoreSchema = 'id, userId, expiresAt, isLocked';
    const breachStoreSchema =
      'id, credentialId, checkType, breached, severity, checkedAt, expiresAt';

    // Define database schema - version 1
    this.version(1).stores({
      credentials: credentialStoreSchema,
      users: 'id, email, createdAt',
      sessions: sessionStoreSchema,
      settings: 'id',
    });

    // Version 2 - Add breach results table
    this.version(2).stores({
      credentials: credentialStoreSchema,
      users: 'id, email, createdAt',
      sessions: sessionStoreSchema,
      settings: 'id',
      breachResults: breachStoreSchema,
    });

    // Version 3 - Index biometricEnabled flag for fast lookups
    this.version(3)
      .stores({
        credentials: credentialStoreSchema,
        users: userStoreSchema,
        sessions: sessionStoreSchema,
        settings: 'id',
        breachResults: breachStoreSchema,
      })
      .upgrade(async (tx) => {
        // Ensure legacy entries have a boolean flag defined so the new index is populated
        await tx
          .table<StoredUser>('users')
          .toCollection()
          .modify((user) => {
            if (typeof user.biometricEnabled !== 'boolean') {
              user.biometricEnabled = Boolean(user.biometricEnabled);
            }
          });
    });
  }

  /**
   * Clears all data from the database (for security wipe)
   */
  async clearAll(): Promise<void> {
    await this.credentials.clear();
    await this.sessions.clear();
    await this.breachResults.clear();
    // Keep users table for re-login
  }

  /**
   * Exports database to JSON (for backup)
   */
  async exportToJSON(): Promise<string> {
    const data = {
      credentials: await this.credentials.toArray(),
      users: await this.users.toArray(),
      settings: await this.settings.toArray(),
      exportedAt: Date.now(),
      version: this.verno,
    };

    return JSON.stringify(data);
  }

  /**
   * Imports database from JSON (for restore)
   */
  async importFromJSON(jsonData: string): Promise<void> {
    try {
      const data = JSON.parse(jsonData) as {
        credentials: StoredCredential[];
        users: StoredUser[];
        settings: { id: string; data: SecuritySettings }[];
      };

      await this.transaction('rw', this.credentials, this.users, this.settings, async () => {
        if (data.credentials && data.credentials.length > 0) {
          await this.credentials.bulkAdd(data.credentials);
        }
        if (data.users && data.users.length > 0) {
          await this.users.bulkAdd(data.users);
        }
        if (data.settings && data.settings.length > 0) {
          await this.settings.bulkAdd(data.settings);
        }
      });
    } catch (error) {
      console.error('Failed to import data:', error);
      throw new Error('Invalid backup data');
    }
  }

  /**
   * Gets database size information
   */
  async getDatabaseSize(): Promise<{
    credentials: number;
    users: number;
    sessions: number;
    breachResults: number;
  }> {
    return {
      credentials: await this.credentials.count(),
      users: await this.users.count(),
      sessions: await this.sessions.count(),
      breachResults: await this.breachResults.count(),
    };
  }
}

