function AppRoutes() {
  const { user, isAuthenticated, isLocked, vaultKey, lockVault } = useAuthStore();

  // Setup auto-lock with user's security settings (must be inside BrowserRouter)
  const autoLockConfig = useMemo(
    () => getDefaultAutoLockConfig(user?.securitySettings?.sessionTimeoutMinutes),
    [user?.securitySettings?.sessionTimeoutMinutes]
  );
  useAutoLock(autoLockConfig);

  // Auto-lock vault when user is authenticated but vaultKey is missing (e.g., after page refresh)
  // The vaultKey cannot be persisted (CryptoKey is not serializable), so we need to redirect to unlock
  useEffect(() => {
    if (isAuthenticated && !isLocked && !vaultKey) {
      console.log('[AppRoutes] Detected authenticated user without vault key, locking vault');
      lockVault();
    }
  }, [isAuthenticated, isLocked, vaultKey, lockVault]);

  // Consider vault locked if no vault key is available (even if isLocked is false)
  const effectivelyLocked = isLocked || (isAuthenticated && !vaultKey);

  return (
    <>
      {/* Global components */}
      <ClipboardNotification />
      <MobileNavigation />

      {/* Onboarding tour - only for authenticated users with vault unlocked */}
      {isAuthenticated && !effectivelyLocked && <OnboardingTour autoStart delay={1500} />}

      <Suspense fallback={<PageLoader />}>
        <Routes>
        {/* Signin route */}
        <Route
          path="/signin"
          element={!isAuthenticated ? <SigninPage /> : <Navigate to="/dashboard" replace />}
        />

        {/* Signup route */}
        <Route
          path="/signup"
          element={!isAuthenticated ? <SignupPage /> : <Navigate to="/dashboard" replace />}
        />

        {/* Unlock route - shown when authenticated but locked */}
        <Route
          path="/unlock"
          element={
            isAuthenticated && effectivelyLocked ? (
              <UnlockPage />
            ) : isAuthenticated ? (
              <Navigate to="/dashboard" replace />
            ) : (
              <Navigate to="/signin" replace />
            )
          }
        />

        {/* Dashboard route */}
        <Route
          path="/dashboard"
          element={
            isAuthenticated && !effectivelyLocked ? (
              <Box sx={{ pb: { xs: 8, md: 0 } }}>
                <DashboardPage />
              </Box>
            ) : isAuthenticated && effectivelyLocked ? (
              <Navigate to="/unlock" replace />
            ) : (
              <Navigate to="/signin" replace />
            )
          }
        />

        {/* Add Credential route */}
        <Route
          path="/credentials/add"
          element={
            isAuthenticated && !effectivelyLocked ? (
              <Box sx={{ pb: { xs: 8, md: 0 } }}>
                <AddCredentialPage />
              </Box>
            ) : isAuthenticated && effectivelyLocked ? (
              <Navigate to="/unlock" replace />
            ) : (
              <Navigate to="/signin" replace />
            )
          }
        />

        {/* Edit Credential route */}
        <Route
          path="/credentials/:id/edit"
          element={
            isAuthenticated && !effectivelyLocked ? (
              <Box sx={{ pb: { xs: 8, md: 0 } }}>
                <EditCredentialPage />
              </Box>
            ) : isAuthenticated && effectivelyLocked ? (
              <Navigate to="/unlock" replace />
            ) : (
              <Navigate to="/signin" replace />
            )
          }
        />

        {/* Settings route */}
        <Route
          path="/settings"
          element={
            isAuthenticated && !effectivelyLocked ? (
              <Box sx={{ pb: { xs: 8, md: 0 } }}>
                <SettingsPage />
              </Box>
            ) : isAuthenticated && effectivelyLocked ? (
              <Navigate to="/unlock" replace />
            ) : (
              <Navigate to="/signin" replace />
            )
          }
        />

        {/* Security Audit route */}
        <Route
          path="/security-audit"
          element={
            isAuthenticated && !effectivelyLocked ? (
              <Box sx={{ pb: { xs: 8, md: 0 } }}>
                <SecurityAuditPage />
              </Box>
            ) : isAuthenticated && effectivelyLocked ? (
              <Navigate to="/unlock" replace />
            ) : (
              <Navigate to="/signin" replace />
            )
          }
        />

        {/* Favorites route */}
        <Route
          path="/favorites"
          element={
            isAuthenticated && !effectivelyLocked ? (
              <Box sx={{ pb: { xs: 8, md: 0 } }}>
                <FavoritesPage />
              </Box>
            ) : isAuthenticated && effectivelyLocked ? (
              <Navigate to="/unlock" replace />
            ) : (
              <Navigate to="/signin" replace />
            )
          }
        />

        {/* Password Generator route */}
        <Route
          path="/password-generator"
          element={
            isAuthenticated && !effectivelyLocked ? (
              <Box sx={{ pb: { xs: 8, md: 0 } }}>
                <PasswordGeneratorPage />
              </Box>
            ) : isAuthenticated && effectivelyLocked ? (
              <Navigate to="/unlock" replace />
            ) : (
              <Navigate to="/signin" replace />
            )
          }
        />

        {/* Legacy /login redirect to /signin */}
        <Route path="/login" element={<Navigate to="/signin" replace />} />

        {/* Root redirect */}
        <Route path="/" element={<Navigate to={isAuthenticated ? "/dashboard" : "/signin"} replace />} />

        {/* Catch all */}
        <Route path="*" element={<Navigate to="/signin" replace />} />
      </Routes>
      </Suspense>
    </>
  );
}

function AppContent() {
  const { isAuthenticated, isLocked } = useAuthStore();
  const [isInitialized, setIsInitialized] = useState(false);
  const [cryptoAPIAvailable, setCryptoAPIAvailable] = useState<boolean | null>(null);

  // Check if Web Crypto API is available (required for encryption)
  useEffect(() => {
    const isAvailable = typeof crypto !== 'undefined' && !!crypto.subtle;
    setCryptoAPIAvailable(isAvailable);

    if (!isAvailable) {
      console.error('Web Crypto API not available. HTTPS or localhost required.');
    }
  }, []);

  // Initialize performance monitoring (development only)
  useEffect(() => {
    initPerformanceMonitoring();
  }, []);

  // Prefetch Tesseract OCR assets on idle for faster first-scan UX
  useEffect(() => {
    if (!isInitialized) return;

    // Use requestIdleCallback to prefetch during browser idle time
    const prefetch = () => {
      prefetchTesseractAssets().catch(() => {
        // Best-effort; ignore failures
      });
    };

    if ('requestIdleCallback' in window) {
      const handle = window.requestIdleCallback(prefetch, { timeout: 5000 });
      return () => { window.cancelIdleCallback(handle); };
    } else {
      // Fallback for Safari: use setTimeout with delay
      const handle = setTimeout(prefetch, 3000);
      return () => { clearTimeout(handle); };
    }
  }, [isInitialized]);

  useEffect(() => {
    console.log('App mounted, initializing database...');

    let mounted = true;
    let hasCompleted = false;

    const completeInitialization = (source: string) => {
      if (mounted && !hasCompleted) {
        hasCompleted = true;
        console.log(`Database initialization completed via ${source}`);
        setIsInitialized(true);
      }
    };

    // Initialize database with a timeout (2 seconds max)
    const initTimeout = setTimeout(() => {
      console.warn('Database initialization timeout - proceeding without persistence');
      completeInitialization('timeout');
    }, 2000);

    // Try to initialize database
    initializeDatabase()
      .then(() => {
        clearTimeout(initTimeout);
        completeInitialization('success');
      })
      .catch((error) => {
        console.error('Database initialization error:', error);
        clearTimeout(initTimeout);
        completeInitialization('error');
      });

    // Cleanup
    return () => {
      mounted = false;
      clearTimeout(initTimeout);
    };
  }, []);

  console.log('App rendering - isAuthenticated:', isAuthenticated, 'isLocked:', isLocked, 'isInitialized:', isInitialized, 'cryptoAPIAvailable:', cryptoAPIAvailable);

  // Show error if crypto API not available
  if (cryptoAPIAvailable === false) {
    return <CryptoAPIError currentUrl={window.location.href} />;
  }

  // Show loading while checking crypto API
  if (cryptoAPIAvailable === null) {
    return (
      <Box
        sx={{
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          minHeight: '100vh',
          backgroundColor: '#121212',
        }}
      >
        <CircularProgress />
      </Box>
    );
  }

  if (!isInitialized) {
    return (
      <Box
        sx={{
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          minHeight: '100vh',
          backgroundColor: '#121212',
          flexDirection: 'column',
          gap: 2,
        }}
      >
        <CircularProgress />
        <Box sx={{ color: 'white', textAlign: 'center' }}>
          <div>Initializing TrustVault...</div>
        </Box>
      </Box>
    );
  }

  // Get base path for routing
  // Vercel uses root path '/', GitHub Pages uses '/TrustVault-PWA/'
  // Check if we're on Vercel by looking for vercel.app domain
  const isVercel = typeof window !== 'undefined' && window.location.hostname.includes('vercel.app');
  const basename = import.meta.env.PROD && !isVercel ? '/TrustVault-PWA' : '';

  return (
    <div style={{ display: 'flex', width: '100%', minHeight: '100vh', flexDirection: 'column' }}>
      <BrowserRouter basename={basename}>
        <AppRoutes />
        {/* PWA helpers */}
        <InstallPrompt />
        <OfflineIndicator />
        <UpdateNotification />
      </BrowserRouter>
    </div>
  );
}

function App() {
  const { mode } = useThemeStore();

  // Create theme based on current mode
  const theme = useMemo(() => createAppTheme(mode), [mode]);

  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <AppContent />
    </ThemeProvider>
  );
}

export default App;

/**
 * Auto-Lock Settings Component
 * Configure automatic session locking behavior
 */

import { useState } from 'react';
import {
  Box,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  FormControlLabel,
  Switch,
  Typography,
  Paper,
  Alert,
  Button,
} from '@mui/material';
import { Lock, LockClock, Visibility } from '@mui/icons-material';

interface AutoLockSettingsProps {
  sessionTimeoutMinutes: number;
  lockOnTabHidden?: boolean;
  onSave: (settings: { sessionTimeoutMinutes: number; lockOnTabHidden: boolean }) => void;
}

const TIMEOUT_OPTIONS = [
  { value: 1, label: '1 minute' },
  { value: 5, label: '5 minutes' },
  { value: 15, label: '15 minutes (recommended)' },
  { value: 30, label: '30 minutes' },
  { value: 60, label: '1 hour' },
  { value: 0, label: 'Never (not recommended)' },
];

export default function AutoLockSettings({
  sessionTimeoutMinutes,
  lockOnTabHidden = false,
  onSave,
}: AutoLockSettingsProps) {
  const [timeout, setTimeout] = useState(sessionTimeoutMinutes);
  const [lockOnHidden, setLockOnHidden] = useState(lockOnTabHidden);
  const [hasChanges, setHasChanges] = useState(false);

  const handleTimeoutChange = (value: number) => {
    setTimeout(value);
    setHasChanges(true);
  };

  const handleLockOnHiddenChange = (checked: boolean) => {
    setLockOnHidden(checked);
    setHasChanges(true);
  };

  const handleSave = () => {
    onSave({
      sessionTimeoutMinutes: timeout,
      lockOnTabHidden: lockOnHidden,
    });
    setHasChanges(false);
  };

  const handleReset = () => {
    setTimeout(sessionTimeoutMinutes);
    setLockOnHidden(lockOnTabHidden);
    setHasChanges(false);
  };

  return (
    <Paper sx={{ p: 3, mb: 3 }}>
      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2 }}>
        <LockClock color="primary" />
        <Typography variant="h6">Auto-Lock</Typography>
      </Box>

      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        Automatically lock your vault after a period of inactivity to protect your credentials.
      </Typography>

      {/* Session Timeout Selector */}
      <FormControl fullWidth sx={{ mb: 3 }}>
        <InputLabel id="timeout-select-label">Session Timeout</InputLabel>
        <Select
          labelId="timeout-select-label"
          value={timeout}
          label="Session Timeout"
          onChange={(e) => { handleTimeoutChange(Number(e.target.value)); }}
        >
          {TIMEOUT_OPTIONS.map((option) => (
            <MenuItem key={option.value} value={option.value}>
              {option.label}
            </MenuItem>
          ))}
        </Select>
      </FormControl>

      {/* Lock on Tab Hidden */}
      <FormControlLabel
        control={
          <Switch
            checked={lockOnHidden}
            onChange={(e) => { handleLockOnHiddenChange(e.target.checked); }}
          />
        }
        label={
          <Box>
            <Typography variant="body2">Lock when tab is hidden</Typography>
            <Typography variant="caption" color="text.secondary">
              Automatically lock vault when you switch to another tab or window
            </Typography>
          </Box>
        }
        sx={{ mb: 2, alignItems: 'flex-start' }}
      />

      {/* Warning for "Never" setting */}
      {timeout === 0 && (
        <Alert severity="warning" icon={<Lock />} sx={{ mb: 2 }}>
          <Typography variant="body2" fontWeight={600} gutterBottom>
            Security Warning
          </Typography>
          <Typography variant="caption">
            Disabling auto-lock is not recommended. Your credentials will remain unlocked
            indefinitely, which could expose them if you leave your device unattended.
          </Typography>
        </Alert>
      )}

      {/* Info box */}
      <Alert severity="info" icon={<Visibility />} sx={{ mb: 2 }}>
        <Typography variant="caption">
          Activity is tracked through mouse movements, keyboard input, scrolling, and touch events.
          The timer resets with each interaction.
        </Typography>
      </Alert>

      {/* Save/Reset buttons */}
      {hasChanges && (
        <Box sx={{ display: 'flex', gap: 2, mt: 3 }}>
          <Button variant="outlined" onClick={handleReset} fullWidth>
            Reset
          </Button>
          <Button variant="contained" onClick={handleSave} fullWidth>
            Save Changes
          </Button>
        </Box>
      )}

      {/* Current Status */}
      <Box sx={{ mt: 3, p: 2, backgroundColor: 'action.hover', borderRadius: 1 }}>
        <Typography variant="caption" color="text.secondary" display="block" gutterBottom>
          Current Configuration:
        </Typography>
        <Typography variant="body2">
          • Auto-lock after:{' '}
          <strong>
            {timeout === 0 ? 'Never' : `${timeout} minute${timeout !== 1 ? 's' : ''}`}
          </strong>
        </Typography>
        <Typography variant="body2">
          • Lock on tab switch: <strong>{lockOnHidden ? 'Enabled' : 'Disabled'}</strong>
        </Typography>
      </Box>
    </Paper>
  );
}

/**
 * Biometric Setup Dialog
 * Allows users to register and manage WebAuthn biometric credentials
 */

import { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Typography,
  Box,
  List,
  ListItem,
  ListItemText,
  ListItemSecondaryAction,
  IconButton,
  Alert,
  CircularProgress,
  Chip,
  Stack,
} from '@mui/material';
import {
  Fingerprint,
  Delete,
  Add,
  Security,
  CheckCircle,
  Phone,
  Computer,
  Key,
} from '@mui/icons-material';
import { useAuthStore } from '../store/authStore';
import { userRepository } from '@/data/repositories/UserRepositoryImpl';
import { getDeviceName, isBiometricAvailable, getAuthenticatorInfo } from '@/core/auth/webauthn';
import type { WebAuthnCredential } from '@/domain/entities/User';

interface BiometricSetupDialogProps {
  open: boolean;
  onClose: () => void;
}

export default function BiometricSetupDialog({ open, onClose }: BiometricSetupDialogProps) {
  const { user, vaultKey } = useAuthStore();
  const [credentials, setCredentials] = useState<WebAuthnCredential[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [authenticatorInfo, setAuthenticatorInfo] = useState<{
    biometricAvailable: boolean;
    conditionalMediationAvailable: boolean;
  } | null>(null);

  useEffect(() => {
    if (open && user) {
      loadCredentials();
      checkBiometricAvailability();
    }
  }, [open, user]);

  const loadCredentials = async () => {
    if (!user) return;

    try {
      const fullUser = await userRepository.findById(user.id);
      if (fullUser) {
        setCredentials(fullUser.webAuthnCredentials);
      }
    } catch (err) {
      console.error('Failed to load credentials:', err);
    }
  };

  const checkBiometricAvailability = async () => {
    try {
      const available = await isBiometricAvailable();
      setBiometricAvailable(available);

      const info = await getAuthenticatorInfo();
      setAuthenticatorInfo(info);
    } catch (err) {
      console.error('Failed to check biometric availability:', err);
      setBiometricAvailable(false);
    }
  };

  const handleRegisterBiometric = async () => {
    if (!user || !vaultKey) {
      setError('You must be logged in with your master password to register biometric');
      return;
    }

    setError(null);
    setSuccess(null);
    setIsLoading(true);

    try {
      const deviceName = getDeviceName();
      await userRepository.registerBiometric(user.id, vaultKey, deviceName);

      setSuccess(`${deviceName} registered successfully!`);
      await loadCredentials();
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to register biometric';
      setError(errorMessage);
      console.error('Biometric registration failed:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleRemoveCredential = async (credentialId: string) => {
    if (!user) return;

    setError(null);
    setSuccess(null);
    setIsLoading(true);

    try {
      await userRepository.removeBiometric(user.id, credentialId);
      setSuccess('Biometric credential removed');
      await loadCredentials();
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to remove credential');
      console.error('Failed to remove credential:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const getDeviceIcon = (deviceName?: string) => {
    if (!deviceName) return <Fingerprint />;

    if (deviceName.includes('iPhone') || deviceName.includes('iPad') || deviceName.includes('Android')) {
      return <Phone />;
    }
    if (deviceName.includes('Mac') || deviceName.includes('Windows')) {
      return <Computer />;
    }
    if (deviceName.includes('YubiKey') || deviceName.includes('Key')) {
      return <Key />;
    }

    return <Fingerprint />;
  };

  const formatDate = (date: Date) => {
    return new Date(date).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  return (
    <Dialog 
      open={open} 
      onClose={onClose} 
      maxWidth="sm" 
      fullWidth
      disablePortal={false}
      keepMounted={false}
      aria-labelledby="biometric-dialog-title"
    >
      <DialogTitle id="biometric-dialog-title">
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <Security color="primary" />
          <Typography variant="h6">Biometric Authentication</Typography>
        </Box>
      </DialogTitle>

      <DialogContent>
        {error && (
          <Alert severity="error" sx={{ mb: 2 }} onClose={() => { setError(null); }}>
            {error}
          </Alert>
        )}

        {success && (
          <Alert severity="success" sx={{ mb: 2 }} onClose={() => { setSuccess(null); }}>
            {success}
          </Alert>
        )}

        {!biometricAvailable && (
          <Alert severity="warning" sx={{ mb: 2 }}>
            Biometric authentication is not available on this device or browser.
          </Alert>
        )}

        {biometricAvailable && !vaultKey && (
          <Alert severity="info" sx={{ mb: 2 }}>
            Please unlock your vault with your master password before registering biometric authentication.
          </Alert>
        )}

        {authenticatorInfo && (
          <Box sx={{ mb: 3 }}>
            <Typography variant="body2" color="text.secondary" gutterBottom>
              Device Capabilities:
            </Typography>
            <Stack direction="row" spacing={1} sx={{ mt: 1 }}>
              {authenticatorInfo.biometricAvailable && (
                <Chip
                  icon={<CheckCircle />}
                  label="Platform Authenticator"
                  size="small"
                  color="success"
                />
              )}
              {authenticatorInfo.conditionalMediationAvailable && (
                <Chip
                  icon={<CheckCircle />}
                  label="Autofill UI"
                  size="small"
                  color="success"
                />
              )}
            </Stack>
          </Box>
        )}

        {window.location.protocol !== 'https:' && window.location.hostname !== 'localhost' && (
          <Alert severity="warning" sx={{ mb: 2 }}>
            <Typography variant="body2" fontWeight={600}>
              HTTPS Required
            </Typography>
            <Typography variant="caption">
              Biometric authentication requires a secure connection. Please use <code>npm run dev:https</code> or access via <code>https://localhost:3000</code>
            </Typography>
          </Alert>
        )}

        <Typography variant="body2" color="text.secondary" paragraph>
          Register your fingerprint, face, or security key to unlock TrustVault faster.
          You can register multiple devices.
        </Typography>

        {credentials.length > 0 && (
          <Box sx={{ mb: 2 }}>
            <Typography variant="subtitle2" gutterBottom>
              Registered Devices ({credentials.length})
            </Typography>
            <List>
              {credentials.map((credential) => (
                <ListItem
                  key={credential.id}
                  sx={{
                    border: 1,
                    borderColor: 'divider',
                    borderRadius: 1,
                    mb: 1,
                  }}
                >
                  <Box sx={{ mr: 2 }}>{getDeviceIcon(credential.deviceName)}</Box>
                  <ListItemText
                    primary={credential.deviceName || 'Biometric Device'}
                    secondary={
                      <>
                        <Typography variant="caption" display="block">
                          Registered: {formatDate(credential.createdAt)}
                        </Typography>
                        {credential.lastUsedAt && (
                          <Typography variant="caption" display="block">
                            Last used: {formatDate(credential.lastUsedAt)}
                          </Typography>
                        )}
                        <Typography variant="caption" color="text.secondary">
                          ID: {credential.id.substring(0, 16)}...
                        </Typography>
                      </>
                    }
                  />
                  <ListItemSecondaryAction>
                    <IconButton
                      edge="end"
                      onClick={() => handleRemoveCredential(credential.id)}
                      disabled={isLoading}
                      color="error"
                    >
                      <Delete />
                    </IconButton>
                  </ListItemSecondaryAction>
                </ListItem>
              ))}
            </List>
          </Box>
        )}

        {credentials.length === 0 && (
          <Box
            sx={{
              textAlign: 'center',
              py: 4,
              border: 1,
              borderColor: 'divider',
              borderRadius: 1,
              borderStyle: 'dashed',
            }}
          >
            <Fingerprint sx={{ fontSize: 64, color: 'text.secondary', mb: 2 }} />
            <Typography variant="body2" color="text.secondary">
              No biometric credentials registered yet
            </Typography>
          </Box>
        )}

        <Button
          fullWidth
          variant={credentials.length === 0 ? 'contained' : 'outlined'}
          startIcon={isLoading ? <CircularProgress size={20} /> : <Add />}
          onClick={handleRegisterBiometric}
          disabled={!biometricAvailable || !vaultKey || isLoading}
          sx={{ mt: 2 }}
        >
          {isLoading ? 'Registering...' : 'Register New Device'}
        </Button>

        <Alert severity="info" sx={{ mt: 2 }}>
          <Typography variant="caption">
            🔒 <strong>Security Note:</strong> Biometric authentication provides quick access
            while maintaining security. Your master password is still required for initial setup
            and critical operations.
          </Typography>
        </Alert>
      </DialogContent>

      <DialogActions>
        <Button onClick={onClose}>Close</Button>
      </DialogActions>
    </Dialog>
  );
}

/**
 * Breach Alert Banner Component
 * Displays prominent alert when breached credentials are detected
 */

import { useState, useEffect } from 'react';
import {
  Alert,
  AlertTitle,
  Button,
  IconButton,
  Box,
  Collapse,
  Typography,
} from '@mui/material';
import {
  Warning,
  Close,
  Visibility,
  Security,
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { getAllBreachedCredentials } from '@/data/repositories/breachResultsRepository';

const DISMISS_DURATION = 7 * 24 * 60 * 60 * 1000; // 7 days
const STORAGE_KEY = 'breach-alert-dismissed';

interface BreachAlertBannerProps {
  /** Force refresh of breach data */
  refreshTrigger?: number;
}

export default function BreachAlertBanner({ refreshTrigger }: BreachAlertBannerProps) {
  const navigate = useNavigate();
  const [open, setOpen] = useState(false);
  const [breachCount, setBreachCount] = useState(0);
  const [criticalCount, setCriticalCount] = useState(0);

  useEffect(() => {
    checkForBreaches();
  }, [refreshTrigger]);

  const checkForBreaches = async () => {
    try {
      const breached = await getAllBreachedCredentials();
      const count = breached.length;

      if (count === 0) {
        setOpen(false);
        return;
      }

      // Count critical/high severity breaches
      const critical = breached.filter(
        b => b.severity === 'critical' || b.severity === 'high'
      ).length;

      setBreachCount(count);
      setCriticalCount(critical);

      // Check if dismissed recently
      const dismissedStr = localStorage.getItem(STORAGE_KEY);
      if (dismissedStr) {
        const dismissed = parseInt(dismissedStr, 10);
        if (Date.now() - dismissed < DISMISS_DURATION) {
          setOpen(false);
          return;
        }
      }

      setOpen(true);
    } catch (error) {
      console.error('Failed to check breaches:', error);
    }
  };

  const handleDismiss = () => {
    localStorage.setItem(STORAGE_KEY, Date.now().toString());
    setOpen(false);
  };

  const handleReview = () => {
    navigate('/security');
  };

  if (!open || breachCount === 0) {
    return null;
  }

  const severity = criticalCount > 0 ? 'error' : 'warning';

  return (
    <Collapse in={open}>
      <Alert
        severity={severity}
        icon={<Warning />}
        sx={{
          mb: 2,
          borderRadius: 2,
          '& .MuiAlert-message': {
            width: '100%',
          },
        }}
        action={
          <IconButton
            aria-label="close"
            color="inherit"
            size="small"
            onClick={handleDismiss}
          >
            <Close fontSize="inherit" />
          </IconButton>
        }
      >
        <AlertTitle sx={{ fontWeight: 600, mb: 1 }}>
          {criticalCount > 0
            ? `${criticalCount} Critical Security ${criticalCount === 1 ? 'Alert' : 'Alerts'}`
            : `Security Alert`}
        </AlertTitle>

        <Typography variant="body2" sx={{ mb: 2 }}>
          {breachCount === 1 ? (
            <>
              One of your passwords has been found in a data breach.
              Change it immediately to protect your account.
            </>
          ) : (
            <>
              {breachCount} of your passwords have been found in data breaches.
              Review and update them to secure your accounts.
            </>
          )}
        </Typography>

        <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap' }}>
          <Button
            size="small"
            variant="contained"
            color={severity}
            startIcon={<Visibility />}
            onClick={handleReview}
            sx={{
              backgroundColor: severity === 'error' ? 'error.main' : 'warning.main',
              '&:hover': {
                backgroundColor: severity === 'error' ? 'error.dark' : 'warning.dark',
              },
            }}
          >
            Review Breaches
          </Button>

          <Button
            size="small"
            variant="outlined"
            color={severity}
            startIcon={<Security />}
            onClick={() => navigate('/security')}
          >
            Security Audit
          </Button>
        </Box>
      </Alert>
    </Collapse>
  );
}

