/**
 * CameraScanDialog
 *
 * Full-screen modal for capturing credential information via device camera.
 * Displays live camera feed with guidance overlay, quality feedback, and capture controls.
 *
 * Security:
 * - All image processing is local-only (Tesseract.js)
 * - Image buffers are cleared immediately after OCR
 * - No images are persisted to disk or network
 */

import { useEffect, useRef, useState, useCallback } from 'react';
import {
  Dialog,
  DialogContent,
  DialogTitle,
  Box,
  Button,
  IconButton,
  Typography,
  CircularProgress,
  Alert,
  LinearProgress,
} from '@mui/material';
import CloseIcon from '@mui/icons-material/Close';
import CameraAltIcon from '@mui/icons-material/CameraAlt';

import {
  requestCameraAccess,
  captureFrame,
  clearImageData,
  assessImageQuality,
  recognizeText,
  parseCredentialText,
  terminateWorker,
  isCameraSupported,
  type CameraStream,
  type ParsedCredential,
  type OCRProgress,
} from '@/core/ocr';

export interface CameraScanDialogProps {
  open: boolean;
  onClose: () => void;
  onResult: (result: ParsedCredential) => void;
}

type ScanState =
  | 'idle'
  | 'requesting'
  | 'streaming'
  | 'capturing'
  | 'processing'
  | 'error';

export function CameraScanDialog({
  open,
  onClose,
  onResult,
}: CameraScanDialogProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const cameraStreamRef = useRef<CameraStream | null>(null);

  const [scanState, setScanState] = useState<ScanState>('idle');
  const [errorMessage, setErrorMessage] = useState<string>('');
  const [qualityIssues, setQualityIssues] = useState<string[]>([]);
  const [ocrProgress, setOcrProgress] = useState<OCRProgress | null>(null);

  // Start camera when dialog opens
  useEffect(() => {
    if (!open) return;

    let mounted = true;

    async function initCamera() {
      if (!isCameraSupported()) {
        setScanState('error');
        setErrorMessage('Camera not supported in this browser');
        return;
      }

      setScanState('requesting');
      setErrorMessage('');

      try {
        const stream = await requestCameraAccess();

        if (!mounted) {
          stream.stop();
          return;
        }

        cameraStreamRef.current = stream;

        if (videoRef.current) {
          videoRef.current.srcObject = stream.stream;
          await videoRef.current.play();
        }

        setScanState('streaming');
      } catch (err) {
        if (!mounted) return;

        setScanState('error');
        if (err instanceof Error) {
          if (err.name === 'NotAllowedError') {
            setErrorMessage(
              'Camera access denied. Please allow camera access in your browser settings.'
            );
          } else if (err.name === 'NotFoundError') {
            setErrorMessage('No camera found on this device.');
          } else {
            setErrorMessage(err.message);
          }
        } else {
          setErrorMessage('Failed to access camera');
        }
      }
    }

    initCamera();

    return () => {
      mounted = false;
      if (cameraStreamRef.current) {
        cameraStreamRef.current.stop();
        cameraStreamRef.current = null;
      }
    };
  }, [open]);

  // Clean up on close
  useEffect(() => {
    if (!open) {
      setScanState('idle');
      setErrorMessage('');
      setQualityIssues([]);
      setOcrProgress(null);

      if (cameraStreamRef.current) {
        cameraStreamRef.current.stop();
        cameraStreamRef.current = null;
      }
    }
  }, [open]);

  // Update quality assessment periodically
  useEffect(() => {
    if (scanState !== 'streaming' || !videoRef.current) return;

    const interval = setInterval(() => {
      if (videoRef.current) {
        const { issues } = assessImageQuality(videoRef.current);
        setQualityIssues(issues);
      }
    }, 1000);

    return () => { clearInterval(interval); };
  }, [scanState]);

  const handleCapture = useCallback(async () => {
    if (!videoRef.current || scanState !== 'streaming') return;

    setScanState('capturing');

    try {
      const { blob } = await captureFrame(videoRef.current);

      setScanState('processing');
      setOcrProgress({ status: 'initializing', progress: 0 });

      const { text, confidence } = await recognizeText(blob, setOcrProgress);

      // Clear image data immediately after OCR
      await clearImageData(blob);

      if (text.trim().length === 0) {
        setScanState('error');
        setErrorMessage(
          'No text detected. Please position the credential information clearly in the frame.'
        );
        return;
      }

      const parsed = parseCredentialText(text);
      parsed.confidence.overall = (parsed.confidence.overall + confidence / 100) / 2;

      onResult(parsed);
      onClose();
    } catch (err) {
      setScanState('error');
      setErrorMessage(
        err instanceof Error ? err.message : 'Failed to process image'
      );
    }
  }, [scanState, onResult, onClose]);

  const handleClose = useCallback(() => {
    // Ensure cleanup before closing
    terminateWorker().catch(() => {});
    onClose();
  }, [onClose]);

  const handleRetry = useCallback(() => {
    setScanState('idle');
    setErrorMessage('');
    // Re-trigger camera init via useEffect
    if (cameraStreamRef.current) {
      cameraStreamRef.current.stop();
      cameraStreamRef.current = null;
    }
    // Small delay then reset to trigger effect
    setTimeout(() => { setScanState('requesting'); }, 100);
  }, []);

  return (
    <Dialog
      open={open}
      onClose={handleClose}
      fullScreen
      PaperProps={{
        sx: { bgcolor: 'black' },
      }}
    >
      <DialogTitle
        sx={{
          bgcolor: 'rgba(0,0,0,0.8)',
          color: 'white',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          py: 1,
        }}
      >
        <Typography variant="h6">Scan Credential</Typography>
        <IconButton onClick={handleClose} sx={{ color: 'white' }}>
          <CloseIcon />
        </IconButton>
      </DialogTitle>

      <DialogContent
        sx={{
          p: 0,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          bgcolor: 'black',
          position: 'relative',
        }}
      >
        {/* Video feed */}
        <Box
          sx={{
            position: 'relative',
            width: '100%',
            maxWidth: 600,
            aspectRatio: '4/3',
            bgcolor: '#111',
            borderRadius: 2,
            overflow: 'hidden',
            mx: 'auto',
            my: 2,
          }}
        >
          <video
            ref={videoRef}
            autoPlay
            playsInline
            muted
            style={{
              width: '100%',
              height: '100%',
              objectFit: 'cover',
              display: scanState === 'streaming' ? 'block' : 'none',
            }}
          />

          {/* Viewfinder overlay */}
          {scanState === 'streaming' && (
            <Box
              sx={{
                position: 'absolute',
                inset: 0,
                border: '2px dashed rgba(255,255,255,0.5)',
                borderRadius: 2,
                m: 2,
                pointerEvents: 'none',
              }}
            >
              <Typography
                variant="caption"
                sx={{
                  position: 'absolute',
                  top: 8,
                  left: '50%',
                  transform: 'translateX(-50%)',
                  color: 'rgba(255,255,255,0.8)',
                  bgcolor: 'rgba(0,0,0,0.5)',
                  px: 1,
                  borderRadius: 1,
                }}
              >
                Position credential info in frame
              </Typography>
            </Box>
          )}

          {/* Loading states */}
          {scanState === 'requesting' && (
            <Box
              sx={{
                position: 'absolute',
                inset: 0,
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                color: 'white',
              }}
            >
              <CircularProgress color="inherit" />
              <Typography sx={{ mt: 2 }}>Requesting camera access...</Typography>
            </Box>
          )}

          {scanState === 'capturing' && (
            <Box
              sx={{
                position: 'absolute',
                inset: 0,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                bgcolor: 'rgba(255,255,255,0.3)',
              }}
            >
              <CircularProgress />
            </Box>
          )}

          {scanState === 'processing' && (
            <Box
              sx={{
                position: 'absolute',
                inset: 0,
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                bgcolor: 'rgba(0,0,0,0.8)',
                color: 'white',
              }}
            >
              <CircularProgress color="inherit" />
              <Typography sx={{ mt: 2 }}>
                {ocrProgress?.status || 'Processing...'}
              </Typography>
              {ocrProgress && (
                <LinearProgress
                  variant="determinate"
                  value={ocrProgress.progress * 100}
                  sx={{ width: '60%', mt: 1 }}
                />
              )}
              <Typography variant="caption" sx={{ mt: 1, opacity: 0.7 }}>
                Processing locally on your device
              </Typography>
            </Box>
          )}
        </Box>

        {/* Quality feedback */}
        {scanState === 'streaming' && qualityIssues.length > 0 && (
          <Alert severity="warning" sx={{ mx: 2, mb: 2, maxWidth: 560 }}>
            {qualityIssues.join('. ')}
          </Alert>
        )}

        {/* Error state */}
        {scanState === 'error' && (
          <Alert
            severity="error"
            sx={{ mx: 2, mb: 2, maxWidth: 560 }}
            action={
              <Button color="inherit" size="small" onClick={handleRetry}>
                Retry
              </Button>
            }
          >
            {errorMessage}
          </Alert>
        )}

        {/* Capture controls */}
        {scanState === 'streaming' && (
          <Box sx={{ display: 'flex', gap: 2, mb: 4 }}>
            <Button
              variant="contained"
              size="large"
              startIcon={<CameraAltIcon />}
              onClick={handleCapture}
              sx={{
                borderRadius: '50px',
                px: 4,
                py: 1.5,
              }}
            >
              Capture
            </Button>
          </Box>
        )}

        {/* Privacy notice */}
        <Typography
          variant="caption"
          sx={{
            position: 'absolute',
            bottom: 16,
            left: '50%',
            transform: 'translateX(-50%)',
            color: 'rgba(255,255,255,0.5)',
            textAlign: 'center',
          }}
        >
          🔒 Images are processed locally and never uploaded
        </Typography>
      </DialogContent>
    </Dialog>
  );
}

/**
 * Category Icon Component
 * Displays category-specific icons with color coding
 */

import { Avatar, SvgIconProps } from '@mui/material';
import {
  Lock,
  CreditCard,
  AccountBalance,
  Person,
  Code,
  Key,
  Note,
} from '@mui/icons-material';
import type { CredentialCategory } from '@/domain/entities/Credential';

interface CategoryIconProps {
  category: CredentialCategory;
  size?: 'small' | 'medium' | 'large';
}

/**
 * Get the icon component for a category
 */
export function getCategoryIcon(category: CredentialCategory): React.ReactElement<SvgIconProps> {
  switch (category) {
    case 'login':
      return <Lock />;
    case 'credit_card':
      return <CreditCard />;
    case 'bank_account':
      return <AccountBalance />;
    case 'identity':
      return <Person />;
    case 'api_key':
      return <Code />;
    case 'ssh_key':
      return <Key />;
    case 'secure_note':
      return <Note />;
    default:
      return <Lock />;
  }
}

/**
 * Get the color for a category
 */
export function getCategoryColor(category: CredentialCategory): string {
  switch (category) {
    case 'login':
      return '#2196F3'; // Blue
    case 'credit_card':
      return '#4CAF50'; // Green
    case 'bank_account':
      return '#009688'; // Teal
    case 'identity':
      return '#9C27B0'; // Purple
    case 'api_key':
      return '#FF9800'; // Orange
    case 'ssh_key':
      return '#FF5722'; // Deep Orange
    case 'secure_note':
      return '#607D8B'; // Blue Grey
    default:
      return '#2196F3';
  }
}

/**
 * Get category display name
 */
export function getCategoryName(category: CredentialCategory): string {
  switch (category) {
    case 'login':
      return 'Login';
    case 'credit_card':
      return 'Credit Card';
    case 'bank_account':
      return 'Bank Account';
    case 'identity':
      return 'Identity';
    case 'api_key':
      return 'API Key';
    case 'ssh_key':
      return 'SSH Key';
    case 'secure_note':
      return 'Secure Note';
    default:
      return 'Login';
  }
}

export default function CategoryIcon({ category, size = 'medium' }: CategoryIconProps) {
  const iconSize = size === 'small' ? 32 : size === 'large' ? 56 : 40;

  return (
    <Avatar
      sx={{
        width: iconSize,
        height: iconSize,
        backgroundColor: getCategoryColor(category),
      }}
    >
      {getCategoryIcon(category)}
    </Avatar>
  );
}

/**
 * Change Master Password Dialog
 * Allows users to change their master password with re-encryption
 */

import { useState } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Button,
  Alert,
  Box,
  IconButton,
  InputAdornment,
} from '@mui/material';
import { Visibility, VisibilityOff, Warning } from '@mui/icons-material';
import PasswordStrengthIndicator from './PasswordStrengthIndicator';
import ReEncryptionProgress from './ReEncryptionProgress';
import { verifyPassword } from '@/core/crypto/password';
import { userRepository } from '@/data/repositories/UserRepositoryImpl';
import { credentialRepository } from '@/data/repositories/CredentialRepositoryImpl';
import { useAuthStore } from '../store/authStore';

interface ChangeMasterPasswordDialogProps {
  open: boolean;
  onClose: () => void;
  onSuccess: () => void;
}

export default function ChangeMasterPasswordDialog({
  open,
  onClose,
  onSuccess,
}: ChangeMasterPasswordDialogProps) {
  const { user, logout } = useAuthStore();

  // Form state
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  // Visibility state
  const [showCurrentPassword, setShowCurrentPassword] = useState(false);
  const [showNewPassword, setShowNewPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  // UI state
  const [error, setError] = useState<string | null>(null);
  const [processing, setProcessing] = useState(false);
  const [reEncrypting, setReEncrypting] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });

  // Validation
  const isValid =
    currentPassword.length > 0 &&
    newPassword.length >= 12 &&
    newPassword === confirmPassword;

  const handleSubmit = async () => {
    if (!user || !isValid) return;

    setError(null);
    setProcessing(true);

    try {
      // Step 1: Verify current password
      const isCurrentPasswordValid = await verifyPassword(
        currentPassword,
        user.hashedMasterPassword
      );

      if (!isCurrentPasswordValid) {
        setError('Current password is incorrect');
        setProcessing(false);
        return;
      }

      // Step 2: Get current vault key from store
      const vaultKey = useAuthStore.getState().vaultKey;
      if (!vaultKey) {
        setError('Session expired. Please sign in again.');
        setProcessing(false);
        return;
      }

      const oldVaultKey = vaultKey;

      // Step 3: Start re-encryption process
      setReEncrypting(true);

      // Step 4: Get all credentials
      const allCredentials = await credentialRepository.findAll(oldVaultKey);
      setProgress({ current: 0, total: allCredentials.length });

      // Step 5: Change master password (this derives new vault key)
      await userRepository.changeMasterPassword(
        user.id,
        currentPassword,
        newPassword
      );

      // Step 6: Re-authenticate to get new vault key
      const authResult = await userRepository.authenticateWithPassword(
        user.email,
        newPassword
      );

      if (!authResult.vaultKey) {
        throw new Error('Failed to get new vault key');
      }

      const newVaultKey = authResult.vaultKey;

      // Step 7: Re-encrypt all credentials
      for (let i = 0; i < allCredentials.length; i++) {
        const credential = allCredentials[i]!;

        // Delete old encrypted version
        await credentialRepository.delete(credential.id);

        // Save with new key (will encrypt with new vault key)
        await credentialRepository.create(credential, newVaultKey);

        // Update progress
        setProgress({ current: i + 1, total: allCredentials.length });
      }

      // Step 8: Success - sign out to force re-login with new password
      setReEncrypting(false);
      setProcessing(false);

      // Show success and close
      onSuccess();

      // Sign out after a brief delay
      setTimeout(() => {
        logout();
      }, 2000);
    } catch (err) {
      console.error('Failed to change master password:', err);
      setError(
        err instanceof Error
          ? err.message
          : 'Failed to change master password. Please try again.'
      );
      setProcessing(false);
      setReEncrypting(false);
    }
  };

  const handleClose = () => {
    if (processing) return; // Don't allow closing during processing
    setCurrentPassword('');
    setNewPassword('');
    setConfirmPassword('');
    setError(null);
    setReEncrypting(false);
    onClose();
  };

  return (
    <Dialog open={open} onClose={handleClose} maxWidth="sm" fullWidth>
      <DialogTitle>Change Master Password</DialogTitle>

      <DialogContent>
        {/* Warning Alert */}
        <Alert severity="error" icon={<Warning />} sx={{ mb: 3 }}>
          <strong>Important:</strong> This will re-encrypt all your credentials. You will be
          signed out after the process completes. Make sure you remember your new password.
        </Alert>

        {/* Error Alert */}
        {error && (
          <Alert severity="error" sx={{ mb: 2 }} onClose={() => { setError(null); }}>
            {error}
          </Alert>
        )}

        {/* Re-encryption Progress */}
        {reEncrypting ? (
          <ReEncryptionProgress current={progress.current} total={progress.total} />
        ) : (
          <>
            {/* Current Password */}
            <TextField
              label="Current Master Password"
              type={showCurrentPassword ? 'text' : 'password'}
              fullWidth
              value={currentPassword}
              onChange={(e) => { setCurrentPassword(e.target.value); }}
              disabled={processing}
              autoFocus
              margin="normal"
              InputProps={{
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      onClick={() => { setShowCurrentPassword(!showCurrentPassword); }}
                      edge="end"
                    >
                      {showCurrentPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
            />

            {/* New Password */}
            <TextField
              label="New Master Password"
              type={showNewPassword ? 'text' : 'password'}
              fullWidth
              value={newPassword}
              onChange={(e) => { setNewPassword(e.target.value); }}
              disabled={processing}
              margin="normal"
              helperText="Minimum 12 characters"
              InputProps={{
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      onClick={() => { setShowNewPassword(!showNewPassword); }}
                      edge="end"
                    >
                      {showNewPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
            />

            {/* Password Strength Indicator */}
            {newPassword && (
              <Box sx={{ mt: 1, mb: 2 }}>
                <PasswordStrengthIndicator password={newPassword} />
              </Box>
            )}

            {/* Confirm Password */}
            <TextField
              label="Confirm New Master Password"
              type={showConfirmPassword ? 'text' : 'password'}
              fullWidth
              value={confirmPassword}
              onChange={(e) => { setConfirmPassword(e.target.value); }}
              disabled={processing}
              margin="normal"
              error={confirmPassword.length > 0 && newPassword !== confirmPassword}
              helperText={
                confirmPassword.length > 0 && newPassword !== confirmPassword
                  ? 'Passwords do not match'
                  : ''
              }
              InputProps={{
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      onClick={() => { setShowConfirmPassword(!showConfirmPassword); }}
                      edge="end"
                    >
                      {showConfirmPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
            />
          </>
        )}
      </DialogContent>

      <DialogActions>
        <Button onClick={handleClose} disabled={processing}>
          Cancel
        </Button>
        <Button
          onClick={handleSubmit}
          variant="contained"
          color="primary"
          disabled={!isValid || processing}
        >
          {processing ? 'Processing...' : 'Change Password'}
        </Button>
      </DialogActions>
    </Dialog>
  );
}

/**
 * Clipboard Settings Component
 * Configure clipboard auto-clear behavior
 */

import { useState } from 'react';
import {
  Box,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Typography,
  Paper,
  Alert,
} from '@mui/material';
import { ContentCopy, Timer, Warning } from '@mui/icons-material';

interface ClipboardSettingsProps {
  clipboardClearSeconds: number;
  onSave: (seconds: number) => void;
}

const TIMEOUT_OPTIONS = [
  { value: 15, label: '15 seconds' },
  { value: 30, label: '30 seconds (recommended)' },
  { value: 60, label: '1 minute' },
  { value: 120, label: '2 minutes' },
  { value: 0, label: 'Never (not recommended)' },
];

export default function ClipboardSettings({
  clipboardClearSeconds,
  onSave,
}: ClipboardSettingsProps) {
  const [timeout, setTimeout] = useState(clipboardClearSeconds);

  const handleChange = (value: number) => {
    setTimeout(value);
    onSave(value);
  };

  return (
    <Paper sx={{ p: 3, mb: 3 }}>
      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2 }}>
        <ContentCopy color="primary" />
        <Typography variant="h6">Clipboard Auto-Clear</Typography>
      </Box>

      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        Automatically clear sensitive data from clipboard after a specified duration to protect your credentials.
      </Typography>

      {/* Timeout Selector */}
      <FormControl fullWidth sx={{ mb: 2 }}>
        <InputLabel id="clipboard-timeout-label">Auto-clear timeout</InputLabel>
        <Select
          labelId="clipboard-timeout-label"
          value={timeout}
          label="Auto-clear timeout"
          onChange={(e) => { handleChange(Number(e.target.value)); }}
        >
          {TIMEOUT_OPTIONS.map((option) => (
            <MenuItem key={option.value} value={option.value}>
              {option.label}
            </MenuItem>
          ))}
        </Select>
      </FormControl>

      {/* Warning for "Never" setting */}
      {timeout === 0 && (
        <Alert severity="warning" icon={<Warning />} sx={{ mb: 2 }}>
          <Typography variant="body2" fontWeight={600} gutterBottom>
            Security Warning
          </Typography>
          <Typography variant="caption">
            Disabling auto-clear is not recommended. Sensitive data will remain in your clipboard
            indefinitely, which could expose your credentials if someone gains access to your device.
          </Typography>
        </Alert>
      )}

      {/* Info box */}
      <Alert severity="info" icon={<Timer />}>
        <Typography variant="caption">
          When you copy passwords or other sensitive data, a countdown notification will appear
          showing the remaining time before the clipboard is automatically cleared.
        </Typography>
      </Alert>

      {/* Current Status */}
      <Box sx={{ mt: 3, p: 2, backgroundColor: 'action.hover', borderRadius: 1 }}>
        <Typography variant="caption" color="text.secondary" display="block" gutterBottom>
          Current Setting:
        </Typography>
        <Typography variant="body2">
          • Auto-clear after:{' '}
          <strong>
            {timeout === 0 ? 'Never' : `${timeout} second${timeout !== 1 ? 's' : ''}`}
          </strong>
        </Typography>
      </Box>
    </Paper>
  );
}

/**
 * Credential Card Component
 * Displays a single credential with actions
 */

import { useState, memo, useEffect } from 'react';
import {
  Card,
  CardContent,
  CardActions,
  Typography,
  Box,
  IconButton,
  Button,
  Chip,
  Menu,
  MenuItem,
  ListItemIcon,
  ListItemText,
  Tooltip,
} from '@mui/material';
import {
  MoreVert,
  ContentCopy,
  Edit,
  Delete,
  Star,
  StarBorder,
  GppBad,
} from '@mui/icons-material';
import type { Credential } from '@/domain/entities/Credential';
import { clipboardManager } from '@/presentation/utils/clipboard';
import { formatRelativeTime } from '@/presentation/utils/timeFormat';
import { credentialRepository } from '@/data/repositories/CredentialRepositoryImpl';
import { getBreachResult } from '@/data/repositories/breachResultsRepository';
import TotpDisplay from './TotpDisplay';
import CategoryIcon, { getCategoryColor, getCategoryName } from './CategoryIcon';
import type { BreachSeverity } from '@/core/breach/breachTypes';

interface CredentialCardProps {
  credential: Credential;
  onEdit: (id: string) => void;
  onDelete: (id: string) => void;
  onToggleFavorite: (id: string) => void;
  onCopySuccess: (message: string) => void;
  showBreachStatus?: boolean;
}

// Memoize component to prevent unnecessary re-renders
const CredentialCard = memo(function CredentialCard({
  credential,
  onEdit,
  onDelete,
  onToggleFavorite,
  onCopySuccess,
  showBreachStatus = true,
}: CredentialCardProps) {
  const [menuAnchor, setMenuAnchor] = useState<null | HTMLElement>(null);
  const [breachStatus, setBreachStatus] = useState<{
    breached: boolean;
    severity: BreachSeverity;
    breachCount?: number;
  } | null>(null);

  useEffect(() => {
    if (showBreachStatus) {
      loadBreachStatus();
    }
  }, [credential.id, showBreachStatus]);

  const loadBreachStatus = async () => {
    try {
      const result = await getBreachResult(credential.id, 'password');
      if (result && result.breached) {
        const status: { breached: boolean; severity: BreachSeverity; breachCount?: number } = {
          breached: true,
          severity: result.severity,
        };
        if (result.breachCount !== undefined) {
          status.breachCount = result.breachCount;
        }
        setBreachStatus(status);
      } else {
        setBreachStatus(null);
      }
    } catch (error) {
      console.error('Failed to load breach status:', error);
    }
  };

  const handleCopyUsername = async () => {
    // Update access time
    await credentialRepository.updateAccessTime(credential.id);

    const success = await clipboardManager.copy(credential.username, false, 0);
    if (success) {
      onCopySuccess(`Username copied: ${credential.username}`);
    } else {
      onCopySuccess('Failed to copy username');
    }
  };

  const handleCopyPassword = async () => {
    // Update access time
    await credentialRepository.updateAccessTime(credential.id);

    const success = await clipboardManager.copy(credential.password, true, 30);
    if (success) {
      onCopySuccess('Password copied! Auto-clearing in 30 seconds');
    } else {
      onCopySuccess('Failed to copy password');
    }
  };

  const getPasswordStrengthColor = (score?: number) => {
    if (!score) return 'default';
    if (score >= 80) return 'success';
    if (score >= 60) return 'info';
    if (score >= 40) return 'warning';
    return 'error';
  };

  return (
    <Card
      sx={{
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        position: 'relative',
        '&:hover': {
          boxShadow: 3,
        },
      }}
    >
      <CardContent sx={{ flexGrow: 1, pb: 1 }}>
        {/* Header */}
        <Box sx={{ display: 'flex', alignItems: 'flex-start', mb: 2 }}>
          <Box sx={{ mr: 2 }}>
            <CategoryIcon category={credential.category} size="small" />
          </Box>
          <Box sx={{ flexGrow: 1, minWidth: 0 }}>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <Typography variant="h6" noWrap sx={{ flexGrow: 1 }}>
                {credential.title}
              </Typography>
              <Tooltip title={credential.isFavorite ? 'Remove from favorites' : 'Add to favorites'}>
                <IconButton
                  size="small"
                  onClick={() => { onToggleFavorite(credential.id); }}
                  sx={{ color: credential.isFavorite ? 'warning.main' : 'action.disabled' }}
                >
                  {credential.isFavorite ? <Star fontSize="small" /> : <StarBorder fontSize="small" />}
                </IconButton>
              </Tooltip>
            </Box>
            <Typography variant="body2" color="text.secondary" noWrap>
              {credential.username}
            </Typography>
          </Box>
          <IconButton
            size="small"
            onClick={(e) => { setMenuAnchor(e.currentTarget); }}
            sx={{ ml: 1 }}
          >
            <MoreVert />
          </IconButton>
        </Box>

        {/* URL */}
        {credential.url && (
          <Typography
            variant="caption"
            color="text.secondary"
            sx={{ display: 'block', mb: 1 }}
            noWrap
          >
            {credential.url}
          </Typography>
        )}

        {/* TOTP Display */}
        {credential.totpSecret && (
          <Box sx={{ mb: 2 }}>
            <TotpDisplay totpSecret={credential.totpSecret} />
          </Box>
        )}

        {/* Category and Tags */}
        <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5, mb: 1 }}>
          <Chip
            size="small"
            label={getCategoryName(credential.category)}
            sx={{
              backgroundColor: getCategoryColor(credential.category),
              color: 'white',
              fontWeight: 500,
              fontSize: '0.75rem',
            }}
          />
          {credential.tags && credential.tags.length > 0 && (
            <>
              {credential.tags.slice(0, 3).map((tag) => (
                <Chip
                  key={tag}
                  size="small"
                  label={tag}
                  variant="outlined"
                  sx={{ fontSize: '0.7rem' }}
                />
              ))}
              {credential.tags.length > 3 && (
                <Chip
                  size="small"
                  label={`+${credential.tags.length - 3}`}
                  variant="outlined"
                  sx={{ fontSize: '0.7rem' }}
                />
              )}
            </>
          )}
        </Box>

        {/* Metadata */}
        <Box sx={{ display: 'flex', gap: 0.5, flexWrap: 'wrap', mb: 1 }}>
          {breachStatus && breachStatus.breached && (
            <Tooltip
              title={`Password found in ${breachStatus.breachCount?.toLocaleString() || 'multiple'} data breach${breachStatus.breachCount === 1 ? '' : 'es'}! Change immediately.`}
            >
              <Chip
                icon={<GppBad />}
                label={`Breached ${breachStatus.breachCount ? `(${breachStatus.breachCount.toLocaleString()}x)` : ''}`}
                size="small"
                color={breachStatus.severity === 'critical' || breachStatus.severity === 'high' ? 'error' : 'warning'}
                sx={{ fontWeight: 600 }}
              />
            </Tooltip>
          )}
          {credential.securityScore !== undefined && (
            <Chip
              label={`Security: ${credential.securityScore}%`}
              size="small"
              color={getPasswordStrengthColor(credential.securityScore)}
              variant="outlined"
            />
          )}
        </Box>

        {/* Tags */}
        {credential.tags.length > 0 && (
          <Box sx={{ display: 'flex', gap: 0.5, flexWrap: 'wrap', mb: 1 }}>
            {credential.tags.slice(0, 3).map((tag) => (
              <Chip key={tag} label={tag} size="small" variant="filled" />
            ))}
            {credential.tags.length > 3 && (
              <Chip label={`+${credential.tags.length - 3}`} size="small" variant="filled" />
            )}
          </Box>
        )}

        {/* Last Updated */}
        <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mt: 1 }}>
          Updated {formatRelativeTime(credential.updatedAt)}
        </Typography>
      </CardContent>

      {/* Actions */}
      <CardActions sx={{ pt: 0 }}>
        <Button size="small" startIcon={<ContentCopy />} onClick={handleCopyUsername}>
          Username
        </Button>
        <Button size="small" startIcon={<ContentCopy />} onClick={handleCopyPassword}>
          Password
        </Button>
        <Button size="small" startIcon={<Edit />} onClick={() => { onEdit(credential.id); }}>
          Edit
        </Button>
      </CardActions>

      {/* Menu */}
      <Menu
        anchorEl={menuAnchor}
        open={Boolean(menuAnchor)}
        onClose={() => { setMenuAnchor(null); }}
      >
        <MenuItem onClick={() => { onEdit(credential.id); setMenuAnchor(null); }}>
          <ListItemIcon>
            <Edit fontSize="small" />
          </ListItemIcon>
          <ListItemText>Edit</ListItemText>
        </MenuItem>
        <MenuItem onClick={() => { onToggleFavorite(credential.id); setMenuAnchor(null); }}>
          <ListItemIcon>
            {credential.isFavorite ? <StarBorder fontSize="small" /> : <Star fontSize="small" />}
          </ListItemIcon>
          <ListItemText>
            {credential.isFavorite ? 'Remove from favorites' : 'Add to favorites'}
          </ListItemText>
        </MenuItem>
        <MenuItem
          onClick={() => { onDelete(credential.id); setMenuAnchor(null); }}
          sx={{ color: 'error.main' }}
        >
          <ListItemIcon>
            <Delete fontSize="small" color="error" />
          </ListItemIcon>
          <ListItemText>Delete</ListItemText>
        </MenuItem>
      </Menu>
    </Card>
  );
});

export default CredentialCard;

/**
 * Credential Details Dialog Component
 * Full-screen dialog for viewing credential details on mobile
 */

import React, { useState, useEffect } from 'react';
import {
  Dialog,
  AppBar,
  Toolbar,
  IconButton,
  Typography,
  Box,
  Button,
  Divider,
  Chip,
  Avatar,
  List,
  ListItem,
  ListItemText,
  Slide,
  Alert,
  AlertTitle,
  CircularProgress,
} from '@mui/material';
import { TransitionProps } from '@mui/material/transitions';
import {
  Close,
  ContentCopy,
  Edit,
  Delete,
  Star,
  StarBorder,
  Lock,
  CreditCard,
  Key,
  Note,
  AccountBalance,
  Person,
  Code,
  Shield,
  GppBad,
  CheckCircle,
  Security,
} from '@mui/icons-material';
import type { Credential } from '@/domain/entities/Credential';
import { formatRelativeTime } from '@/presentation/utils/timeFormat';
import { checkPasswordBreach, isHibpEnabled } from '@/core/breach/hibpService';
import { getBreachResult, saveBreachResult } from '@/data/repositories/breachResultsRepository';
import type { BreachCheckResult } from '@/core/breach/breachTypes';
import TotpDisplay from './TotpDisplay';
import BreachDetailsModal from './BreachDetailsModal';

interface CredentialDetailsDialogProps {
  open: boolean;
  credential: Credential | null;
  onClose: () => void;
  onCopyUsername: () => void;
  onCopyPassword: () => void;
  onEdit: () => void;
  onDelete: () => void;
  onToggleFavorite: () => void;
}

const Transition = React.forwardRef(function Transition(
  props: TransitionProps & {
    children: React.ReactElement;
  },
  ref: React.Ref<unknown>,
) {
  const { appear, enter, exit, ...otherProps } = props;
  return (
    <Slide 
      direction="up" 
      ref={ref} 
      appear={appear === undefined ? true : appear}
      enter={enter === undefined ? true : enter}
      exit={exit === undefined ? true : exit}
      {...otherProps}
    />
  );
});

export default function CredentialDetailsDialog({
  open,
  credential,
  onClose,
  onCopyUsername,
  onCopyPassword,
  onEdit,
  onDelete,
  onToggleFavorite,
}: CredentialDetailsDialogProps) {
  const [breachChecking, setBreachChecking] = useState(false);
  const [breachResult, setBreachResult] = useState<BreachCheckResult | null>(null);
  const [breachDetailsOpen, setBreachDetailsOpen] = useState(false);

  useEffect(() => {
    if (open && credential) {
      loadExistingBreachData();
    }
  }, [open, credential]);

  const loadExistingBreachData = async () => {
    if (!credential) return;

    try {
      const result = await getBreachResult(credential.id, 'password');
      setBreachResult(result);
    } catch (error) {
      console.error('Failed to load breach data:', error);
    }
  };

  const handleCheckBreach = async () => {
    if (!credential || !isHibpEnabled()) {
      alert('Breach detection is not enabled. Set VITE_HIBP_API_ENABLED=true in your environment configuration.');
      return;
    }

    setBreachChecking(true);

    try {
      const result = await checkPasswordBreach(credential.password);
      await saveBreachResult(credential.id, 'password', result);
      setBreachResult(result);
    } catch (error) {
      console.error('Breach check failed:', error);
      alert('Failed to check for breaches. Please try again later.');
    } finally {
      setBreachChecking(false);
    }
  };

  if (!credential) return null;

  const getSeverityColor = (severity: string) => {
    switch (severity) {
      case 'critical':
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'info';
      default:
        return 'success';
    }
  };

  const isBreached = breachResult?.breached ?? false;
  const lastChecked = breachResult?.checkedAt
    ? formatRelativeTime(new Date(breachResult.checkedAt))
    : null;

  const getCategoryIcon = () => {
    switch (credential.category) {
      case 'login':
        return <Lock />;
      case 'credit_card':
        return <CreditCard />;
      case 'bank_account':
        return <AccountBalance />;
      case 'identity':
        return <Person />;
      case 'api_key':
        return <Code />;
      case 'ssh_key':
        return <Key />;
      case 'secure_note':
        return <Note />;
      default:
        return <Lock />;
    }
  };

  const getCategoryColor = () => {
    switch (credential.category) {
      case 'login':
        return 'primary';
      case 'credit_card':
        return 'success';
      case 'bank_account':
        return 'info';
      case 'identity':
        return 'secondary';
      case 'api_key':
      case 'ssh_key':
        return 'warning';
      case 'secure_note':
        return 'default';
      default:
        return 'default';
    }
  };

  const getCategoryLabel = () => {
    switch (credential.category) {
      case 'login':
        return 'Login';
      case 'credit_card':
        return 'Card';
      case 'bank_account':
        return 'Bank';
      case 'identity':
        return 'Identity';
      case 'api_key':
        return 'API Key';
      case 'ssh_key':
        return 'SSH Key';
      case 'secure_note':
        return 'Note';
      default:
        return 'Other';
    }
  };

  return (
    <>
    <Dialog fullScreen open={open} onClose={onClose} TransitionComponent={Transition}>
      {/* App Bar */}
      <AppBar sx={{ position: 'relative' }}>
        <Toolbar>
          <IconButton edge="start" color="inherit" onClick={onClose} aria-label="close">
            <Close />
          </IconButton>
          <Typography sx={{ ml: 2, flex: 1 }} variant="h6" component="div">
            Credential Details
          </Typography>
          <IconButton
            color="inherit"
            onClick={onToggleFavorite}
            aria-label={credential.isFavorite ? 'remove from favorites' : 'add to favorites'}
          >
            {credential.isFavorite ? <Star /> : <StarBorder />}
          </IconButton>
        </Toolbar>
      </AppBar>

      {/* Content */}
      <Box sx={{ p: 2, pb: 10 }}>
        {/* Header with Icon */}
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
          <Avatar
            sx={{
              mr: 2,
              bgcolor: `${getCategoryColor()}.main`,
              width: 56,
              height: 56,
            }}
          >
            {getCategoryIcon()}
          </Avatar>
          <Box>
            <Typography variant="h5" gutterBottom>
              {credential.title}
            </Typography>
            <Chip label={getCategoryLabel()} size="small" color={getCategoryColor()} />
          </Box>
        </Box>

        <Divider sx={{ mb: 3 }} />

        {/* Credential Information */}
        <List>
          {/* Card-specific fields */}
          {credential.category === 'credit_card' ? (
            <>
              {/* Card Number (masked) */}
              {credential.cardNumber && (
                <ListItem>
                  <ListItemText
                    primary="Card Number"
                    secondary={`•••• •••• •••• ${credential.cardNumber.slice(-4)}`}
                  />
                </ListItem>
              )}

              {/* Cardholder Name */}
              {credential.cardholderName && (
                <ListItem>
                  <ListItemText primary="Cardholder Name" secondary={credential.cardholderName} />
                </ListItem>
              )}

              {/* Card Type */}
              {credential.cardType && (
                <ListItem>
                  <ListItemText
                    primary="Card Type"
                    secondary={credential.cardType.charAt(0).toUpperCase() + credential.cardType.slice(1)}
                  />
                </ListItem>
              )}

              {/* Expiry Date */}
              {credential.expiryMonth && credential.expiryYear && (
                <ListItem>
                  <ListItemText
                    primary="Expiry Date"
                    secondary={`${credential.expiryMonth}/${credential.expiryYear}`}
                  />
                </ListItem>
              )}

              {/* CVV (masked) */}
              {credential.cvv && (
                <ListItem>
                  <ListItemText primary="CVV" secondary="•••" />
                </ListItem>
              )}

              {/* Billing Address */}
              {credential.billingAddress && (
                <ListItem>
                  <ListItemText primary="Billing Address" secondary={credential.billingAddress} />
                </ListItem>
              )}
            </>
          ) : (
            <>
              {/* Username */}
              <ListItem>
                <ListItemText primary="Username" secondary={credential.username} />
              </ListItem>

              {/* Password (masked) */}
              <ListItem>
                <ListItemText primary="Password" secondary="••••••••••••" />
              </ListItem>
            </>
          )}

          {/* URL */}
          {credential.url && (
            <ListItem>
              <ListItemText
                primary="Website"
                secondary={
                  <a
                    href={credential.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    style={{ color: 'inherit' }}
                  >
                    {credential.url}
                  </a>
                }
              />
            </ListItem>
          )}

          {/* TOTP */}
          {credential.totpSecret && (
            <ListItem>
              <Box sx={{ width: '100%' }}>
                <Typography variant="caption" color="text.secondary">
                  Two-Factor Authentication
                </Typography>
                <Box sx={{ mt: 1 }}>
                  <TotpDisplay totpSecret={credential.totpSecret} />
                </Box>
              </Box>
            </ListItem>
          )}

          {/* Tags */}
          {credential.tags.length > 0 && (
            <ListItem>
              <Box sx={{ width: '100%' }}>
                <Typography variant="caption" color="text.secondary" sx={{ mb: 1, display: 'block' }}>
                  Tags
                </Typography>
                <Box sx={{ display: 'flex', gap: 0.5, flexWrap: 'wrap' }}>
                  {credential.tags.map((tag) => (
                    <Chip key={tag} label={tag} size="small" variant="filled" />
                  ))}
                </Box>
              </Box>
            </ListItem>
          )}

          {/* Notes */}
          {credential.notes && (
            <ListItem>
              <ListItemText primary="Notes" secondary={credential.notes} />
            </ListItem>
          )}
        </List>

        <Divider sx={{ my: 2 }} />

        {/* Breach Detection Section */}
        {credential.category !== 'credit_card' && credential.category !== 'secure_note' && (
          <Box sx={{ px: 2, mb: 3 }}>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2 }}>
              <Security fontSize="small" color="primary" />
              <Typography variant="subtitle2" fontWeight="600">
                Breach Detection
              </Typography>
            </Box>

            {!isHibpEnabled() ? (
              <Alert severity="info" sx={{ mb: 2 }}>
                Breach detection is not enabled.
              </Alert>
            ) : isBreached ? (
              <Alert
                severity={getSeverityColor(breachResult?.severity || 'medium')}
                sx={{ mb: 2 }}
                action={
                  <Button
                    size="small"
                    color="inherit"
                    onClick={() => { setBreachDetailsOpen(true); }}
                  >
                    Details
                  </Button>
                }
              >
                <AlertTitle sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                  <GppBad />
                  Password Compromised
                </AlertTitle>
                This password has been seen{' '}
                <strong>{breachResult?.breachCount?.toLocaleString()}</strong> time
                {breachResult?.breachCount === 1 ? '' : 's'} in data breaches.
                {lastChecked && (
                  <Typography variant="caption" display="block" sx={{ mt: 1 }}>
                    Last checked {lastChecked}
                  </Typography>
                )}
              </Alert>
            ) : breachResult ? (
              <Alert severity="success" sx={{ mb: 2 }} icon={<CheckCircle />}>
                <AlertTitle>Password Secure</AlertTitle>
                Not found in known data breaches.
                {lastChecked && (
                  <Typography variant="caption" display="block" sx={{ mt: 1 }}>
                    Last checked {lastChecked}
                  </Typography>
                )}
              </Alert>
            ) : null}

            <Button
              variant="outlined"
              size="small"
              fullWidth
              startIcon={breachChecking ? <CircularProgress size={16} /> : <Shield />}
              onClick={handleCheckBreach}
              disabled={breachChecking}
            >
              {breachChecking ? 'Checking...' : lastChecked ? 'Re-check for Breaches' : 'Check for Breaches'}
            </Button>
          </Box>
        )}

        <Divider sx={{ my: 2 }} />

        {/* Metadata */}
        <List>
          <ListItem>
            <ListItemText
              primary="Last Updated"
              secondary={formatRelativeTime(credential.updatedAt)}
            />
          </ListItem>
        </List>
      </Box>

      {/* Bottom Action Bar */}
      <Box
        sx={{
          position: 'fixed',
          bottom: 0,
          left: 0,
          right: 0,
          bgcolor: 'background.paper',
          borderTop: 1,
          borderColor: 'divider',
          p: 2,
          display: 'flex',
          gap: 1,
        }}
      >
        {credential.category === 'credit_card' ? (
          <>
            <Button
              variant="outlined"
              startIcon={<ContentCopy />}
              onClick={() => {
                if (credential.cardNumber) {
                  navigator.clipboard.writeText(credential.cardNumber);
                }
              }}
              fullWidth
            >
              Card #
            </Button>
            <Button
              variant="outlined"
              startIcon={<ContentCopy />}
              onClick={() => {
                if (credential.cvv) {
                  navigator.clipboard.writeText(credential.cvv);
                }
              }}
              fullWidth
            >
              CVV
            </Button>
          </>
        ) : (
          <>
            <Button
              variant="outlined"
              startIcon={<ContentCopy />}
              onClick={onCopyUsername}
              fullWidth
            >
              Username
            </Button>
            <Button
              variant="outlined"
              startIcon={<ContentCopy />}
              onClick={onCopyPassword}
              fullWidth
            >
              Password
            </Button>
          </>
        )}
        <Button variant="outlined" startIcon={<Edit />} onClick={onEdit} fullWidth>
          Edit
        </Button>
        <Button
          variant="outlined"
          color="error"
          startIcon={<Delete />}
          onClick={onDelete}
          fullWidth
        >
          Delete
        </Button>
      </Box>
    </Dialog>

    {/* Breach Details Modal */}
    {breachResult && isBreached && (
      <BreachDetailsModal
        open={breachDetailsOpen}
        onClose={() => { setBreachDetailsOpen(false); }}
        breaches={breachResult.breaches}
        credentialTitle={credential.title}
        severity={breachResult.severity}
        {...(breachResult.breachCount !== undefined && { breachCount: breachResult.breachCount })}
        onChangePassword={() => {
          setBreachDetailsOpen(false);
          onEdit();
          onClose();
        }}
      />
    )}
    </>
  );
}

/**
 * Export Dialog Component
 * Allows users to export their vault with encryption
 */

import { useState } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Button,
  Alert,
  Box,
  IconButton,
  InputAdornment,
  Checkbox,
  FormControlLabel,
  Typography,
  CircularProgress,
} from '@mui/material';
import { Visibility, VisibilityOff, Warning, Download } from '@mui/icons-material';
import PasswordStrengthIndicator from './PasswordStrengthIndicator';
import { encryptExport, generateExportFilename, downloadExportFile } from '@/core/crypto/exportEncryption';
import { credentialRepository } from '@/data/repositories/CredentialRepositoryImpl';
import { useAuthStore } from '../store/authStore';

interface ExportDialogProps {
  open: boolean;
  onClose: () => void;
  onSuccess: () => void;
}

export default function ExportDialog({ open, onClose, onSuccess }: ExportDialogProps) {
  const { session } = useAuthStore();

  // Form state
  const [exportPassword, setExportPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [confirmationChecked, setConfirmationChecked] = useState(false);

  // UI state
  const [error, setError] = useState<string | null>(null);
  const [exporting, setExporting] = useState(false);

  // Validation
  const isValid =
    exportPassword.length >= 12 &&
    exportPassword === confirmPassword &&
    confirmationChecked;

  const handleExport = async () => {
    if (!session?.vaultKey || !isValid) return;

    setError(null);
    setExporting(true);

    try {
      // Get all credentials
      const credentials = await credentialRepository.findAll(session.vaultKey);

      if (credentials.length === 0) {
        setError('No credentials to export');
        setExporting(false);
        return;
      }

      // Encrypt export
      const exportJson = await encryptExport(credentials, exportPassword);

      // Download file
      const filename = generateExportFilename();
      downloadExportFile(exportJson, filename);

      // Success
      setExporting(false);
      onSuccess();
      handleClose();
    } catch (err) {
      console.error('Export failed:', err);
      setError(err instanceof Error ? err.message : 'Failed to export vault');
      setExporting(false);
    }
  };

  const handleClose = () => {
    if (exporting) return; // Don't allow closing during export
    setExportPassword('');
    setConfirmPassword('');
    setConfirmationChecked(false);
    setError(null);
    onClose();
  };

  return (
    <Dialog open={open} onClose={handleClose} maxWidth="sm" fullWidth>
      <DialogTitle>Export Vault</DialogTitle>

      <DialogContent>
        {/* Info Alert */}
        <Alert severity="info" sx={{ mb: 3 }}>
          <Typography variant="body2" fontWeight={600} gutterBottom>
            Secure Vault Backup
          </Typography>
          <Typography variant="caption">
            Your vault will be encrypted with a password separate from your master password.
            Store this export password securely - you'll need it to import the vault later.
          </Typography>
        </Alert>

        {/* Error Alert */}
        {error && (
          <Alert severity="error" sx={{ mb: 2 }} onClose={() => { setError(null); }}>
            {error}
          </Alert>
        )}

        {/* Export Password */}
        <TextField
          label="Export Password"
          type={showPassword ? 'text' : 'password'}
          fullWidth
          value={exportPassword}
          onChange={(e) => { setExportPassword(e.target.value); }}
          disabled={exporting}
          autoFocus
          margin="normal"
          helperText="Minimum 12 characters. Different from your master password."
          InputProps={{
            endAdornment: (
              <InputAdornment position="end">
                <IconButton onClick={() => { setShowPassword(!showPassword); }} edge="end">
                  {showPassword ? <VisibilityOff /> : <Visibility />}
                </IconButton>
              </InputAdornment>
            ),
          }}
        />

        {/* Password Strength Indicator */}
        {exportPassword && (
          <Box sx={{ mt: 1, mb: 2 }}>
            <PasswordStrengthIndicator password={exportPassword} />
          </Box>
        )}

        {/* Confirm Password */}
        <TextField
          label="Confirm Export Password"
          type={showConfirm ? 'text' : 'password'}
          fullWidth
          value={confirmPassword}
          onChange={(e) => { setConfirmPassword(e.target.value); }}
          disabled={exporting}
          margin="normal"
          error={confirmPassword.length > 0 && exportPassword !== confirmPassword}
          helperText={
            confirmPassword.length > 0 && exportPassword !== confirmPassword
              ? 'Passwords do not match'
              : ''
          }
          InputProps={{
            endAdornment: (
              <InputAdornment position="end">
                <IconButton onClick={() => { setShowConfirm(!showConfirm); }} edge="end">
                  {showConfirm ? <VisibilityOff /> : <Visibility />}
                </IconButton>
              </InputAdornment>
            ),
          }}
        />

        {/* Warning Alert */}
        <Alert severity="warning" icon={<Warning />} sx={{ mt: 3, mb: 2 }}>
          <Typography variant="body2" fontWeight={600} gutterBottom>
            Important: Save Your Export Password
          </Typography>
          <Typography variant="caption">
            Without the export password, you will not be able to import this backup. Write it
            down or store it in a secure location separate from this device.
          </Typography>
        </Alert>

        {/* Confirmation Checkbox */}
        <FormControlLabel
          control={
            <Checkbox
              checked={confirmationChecked}
              onChange={(e) => { setConfirmationChecked(e.target.checked); }}
              disabled={exporting}
            />
          }
          label={
            <Typography variant="body2">
              I have stored the export password securely and understand I cannot recover the backup
              without it
            </Typography>
          }
        />
      </DialogContent>

      <DialogActions>
        <Button onClick={handleClose} disabled={exporting}>
          Cancel
        </Button>
        <Button
          onClick={handleExport}
          variant="contained"
          color="primary"
          disabled={!isValid || exporting}
          startIcon={exporting ? <CircularProgress size={20} /> : <Download />}
        >
          {exporting ? 'Exporting...' : 'Export Vault'}
        </Button>
      </DialogActions>
    </Dialog>
  );
}

/**
 * Filter Chips Component
 * Category and favorite filters with chips UI
 */

import { Box, Chip, Autocomplete, TextField } from '@mui/material';
import {
  Star as StarIcon,
  Lock,
  CreditCard,
  AccountBalance,
  Person,
  Code,
  Key,
  Note,
  LocalOffer as TagIcon,
} from '@mui/icons-material';
import type { CredentialCategory } from '@/domain/entities/Credential';

interface FilterChipsProps {
  selectedCategory: CredentialCategory | 'all';
  onCategoryChange: (category: CredentialCategory | 'all') => void;
  favoritesOnly: boolean;
  onFavoritesToggle: () => void;
  selectedTags?: string[];
  onTagsChange?: (tags: string[]) => void;
  availableTags?: string[];
}

const CATEGORY_OPTIONS: Array<{
  value: CredentialCategory | 'all';
  label: string;
  icon?: React.ReactElement | undefined;
}> = [
  { value: 'all', label: 'All' },
  { value: 'login', label: 'Login', icon: <Lock fontSize="small" /> },
  { value: 'credit_card', label: 'Cards', icon: <CreditCard fontSize="small" /> },
  { value: 'bank_account', label: 'Bank', icon: <AccountBalance fontSize="small" /> },
  { value: 'identity', label: 'Identity', icon: <Person fontSize="small" /> },
  { value: 'api_key', label: 'API Keys', icon: <Code fontSize="small" /> },
  { value: 'ssh_key', label: 'SSH Keys', icon: <Key fontSize="small" /> },
  { value: 'secure_note', label: 'Notes', icon: <Note fontSize="small" /> },
];

export default function FilterChips({
  selectedCategory,
  onCategoryChange,
  favoritesOnly,
  onFavoritesToggle,
  selectedTags = [],
  onTagsChange,
  availableTags = [],
}: FilterChipsProps) {
  return (
    <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap', alignItems: 'center' }}>
      {/* Category and Favorites Filters */}
      <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap', alignItems: 'center' }}>
        {CATEGORY_OPTIONS.map((option) => (
          <Chip
            key={option.value}
            label={option.label}
            {...(option.icon && { icon: option.icon })}
            onClick={() => { onCategoryChange(option.value); }}
            color={selectedCategory === option.value ? 'primary' : 'default'}
            variant={selectedCategory === option.value ? 'filled' : 'outlined'}
            sx={{
              cursor: 'pointer',
              '&:hover': {
                backgroundColor:
                  selectedCategory === option.value
                    ? 'primary.dark'
                    : 'action.hover',
              },
            }}
          />
        ))}

        {/* Favorites Filter */}
        <Chip
          label="Favorites"
          icon={<StarIcon fontSize="small" />}
          onClick={onFavoritesToggle}
          color={favoritesOnly ? 'warning' : 'default'}
          variant={favoritesOnly ? 'filled' : 'outlined'}
          sx={{
            cursor: 'pointer',
            '&:hover': {
              backgroundColor: favoritesOnly ? 'warning.dark' : 'action.hover',
            },
          }}
        />
      </Box>

      {/* Tag Filter */}
      {onTagsChange && availableTags.length > 0 && (
        <Autocomplete
          multiple
          size="small"
          options={availableTags}
          value={selectedTags}
          onChange={(_, newValue) => { onTagsChange(newValue); }}
          renderInput={(params) => (
            <TextField 
              {...params} 
              placeholder="Filter by tags..." 
              size="small"
              // eslint-disable-next-line @typescript-eslint/no-explicit-any
              InputLabelProps={{ ...(params.InputLabelProps as any) }}
            />
          )}
          renderTags={(value, getTagProps) =>
            value.map((option, index) => (
              <Chip
                {...getTagProps({ index })}
                key={option}
                label={option}
                size="small"
                icon={<TagIcon fontSize="small" />}
                color="secondary"
              />
            ))
          }
          sx={{ minWidth: 250 }}
        />
      )}
    </Box>
  );
}

/**
 * Import Dialog Component
 * Allows users to import encrypted vault backups
 */

import { useState } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Button,
  Alert,
  Box,
  IconButton,
  InputAdornment,
  Typography,
  CircularProgress,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  LinearProgress,
} from '@mui/material';
import { Visibility, VisibilityOff, Upload, Warning } from '@mui/icons-material';
import { decryptImport, readImportFile } from '@/core/crypto/exportEncryption';
import { credentialRepository } from '@/data/repositories/CredentialRepositoryImpl';
import { useAuthStore } from '../store/authStore';
import { Credential, CredentialInput } from '@/domain/entities/Credential';

interface ImportDialogProps {
  open: boolean;
  onClose: () => void;
  onSuccess: (count: number) => void;
}

type ImportMode = 'replace' | 'merge';

export default function ImportDialog({ open, onClose, onSuccess }: ImportDialogProps) {
  const { session } = useAuthStore();

  // File state
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [fileContent, setFileContent] = useState<string | null>(null);
  const [credentials, setCredentials] = useState<Credential[]>([]);

  // Form state
  const [exportPassword, setExportPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [importMode, setImportMode] = useState<ImportMode>('merge');

  // UI state
  const [error, setError] = useState<string | null>(null);
  const [decrypting, setDecrypting] = useState(false);
  const [importing, setImporting] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [decrypted, setDecrypted] = useState(false);

  const handleFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    // Validate file extension
    if (!file.name.endsWith('.tvault')) {
      setError('Invalid file type. Please select a .tvault file.');
      return;
    }

    setSelectedFile(file);
    setError(null);

    try {
      const content = await readImportFile(file);
      setFileContent(content);
    } catch (err) {
      setError('Failed to read file');
      setSelectedFile(null);
    }
  };

  const handleDecrypt = async () => {
    if (!fileContent || !exportPassword) return;

    setError(null);
    setDecrypting(true);

    try {
      // Decrypt and parse import
      const importedCredentials = await decryptImport(fileContent, exportPassword);

      setCredentials(importedCredentials);
      setDecrypted(true);
      setDecrypting(false);
    } catch (err) {
      console.error('Decryption failed:', err);
      setError(err instanceof Error ? err.message : 'Failed to decrypt import file');
      setDecrypting(false);
    }
  };

  const handleImport = async () => {
    if (!session?.vaultKey || credentials.length === 0) return;

    setError(null);
    setImporting(true);
    setProgress({ current: 0, total: credentials.length });

    try {
      // Replace mode: delete all existing credentials first
      if (importMode === 'replace') {
        const existing = await credentialRepository.findAll(session.vaultKey);
        for (const cred of existing) {
          await credentialRepository.delete(cred.id);
        }
      }

      // Import credentials
      for (let i = 0; i < credentials.length; i++) {
        const credential = credentials[i];

        // In merge mode, check for duplicates (same title + username)
        if (importMode === 'merge') {
          const existing = await credentialRepository.findAll(session.vaultKey);
          const duplicate = existing.find(
            (c) =>
              c.title.toLowerCase() === credential!.title.toLowerCase() &&
              c.username.toLowerCase() === credential!.username.toLowerCase()
          );

          if (duplicate) {
            // Skip duplicate
            setProgress({ current: i + 1, total: credentials.length });
            continue;
          }
        }

        // Generate new ID for imported credential and ensure required fields
        const newCredential: CredentialInput = {
          title: credential!.title ?? 'Untitled',
          username: credential!.username ?? '',
          password: credential!.password ?? '',
          url: credential!.url,
          notes: credential!.notes,
          category: credential!.category ?? 'login',
          tags: credential!.tags,
          isFavorite: credential!.isFavorite,
          totpSecret: credential!.totpSecret,
        };

        // Save credential
        await credentialRepository.create(newCredential, session.vaultKey);

        // Update progress
        setProgress({ current: i + 1, total: credentials.length });
      }

      // Success
      setImporting(false);
      onSuccess(credentials.length);
      handleClose();
    } catch (err) {
      console.error('Import failed:', err);
      setError(err instanceof Error ? err.message : 'Failed to import credentials');
      setImporting(false);
    }
  };

  const handleClose = () => {
    if (decrypting || importing) return; // Don't allow closing during processing
    setSelectedFile(null);
    setFileContent(null);
    setCredentials([]);
    setExportPassword('');
    setImportMode('merge');
    setDecrypted(false);
    setError(null);
    setProgress({ current: 0, total: 0 });
    onClose();
  };

  const percentage =
    progress.total > 0 ? Math.round((progress.current / progress.total) * 100) : 0;

  return (
    <Dialog open={open} onClose={handleClose} maxWidth="sm" fullWidth>
      <DialogTitle>Import Vault</DialogTitle>

      <DialogContent>
        {/* Error Alert */}
        {error && (
          <Alert severity="error" sx={{ mb: 2 }} onClose={() => { setError(null); }}>
            {error}
          </Alert>
        )}

        {/* Import Progress */}
        {importing ? (
          <Box
            sx={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              py: 4,
            }}
          >
            <CircularProgress size={60} sx={{ mb: 2 }} />
            <Typography variant="h6" gutterBottom>
              Importing Credentials
            </Typography>
            <Typography variant="body2" color="text.secondary" gutterBottom>
              {progress.current} of {progress.total} credentials imported
            </Typography>
            <Box sx={{ width: '100%', mt: 2 }}>
              <LinearProgress variant="determinate" value={percentage} sx={{ height: 8 }} />
            </Box>
            <Typography variant="h4" sx={{ mt: 2, color: 'primary.main' }}>
              {percentage}%
            </Typography>
          </Box>
        ) : (
          <>
            {/* File Selection */}
            {!decrypted && (
              <>
                <Alert severity="info" sx={{ mb: 3 }}>
                  <Typography variant="body2">
                    Select a .tvault backup file and enter the export password used when creating
                    the backup.
                  </Typography>
                </Alert>

                <Button
                  variant="outlined"
                  component="label"
                  startIcon={<Upload />}
                  fullWidth
                  sx={{ mb: 2 }}
                >
                  {selectedFile ? selectedFile.name : 'Select Backup File (.tvault)'}
                  <input
                    type="file"
                    hidden
                    accept=".tvault"
                    onChange={handleFileSelect}
                  />
                </Button>

                {/* Export Password */}
                {selectedFile && (
                  <TextField
                    label="Export Password"
                    type={showPassword ? 'text' : 'password'}
                    fullWidth
                    value={exportPassword}
                    onChange={(e) => { setExportPassword(e.target.value); }}
                    disabled={decrypting}
                    margin="normal"
                    helperText="Enter the password used to encrypt this backup"
                    InputProps={{
                      endAdornment: (
                        <InputAdornment position="end">
                          <IconButton onClick={() => { setShowPassword(!showPassword); }} edge="end">
                            {showPassword ? <VisibilityOff /> : <Visibility />}
                          </IconButton>
                        </InputAdornment>
                      ),
                    }}
                  />
                )}
              </>
            )}

            {/* Decryption Success - Show Import Options */}
            {decrypted && (
              <>
                <Alert severity="success" sx={{ mb: 3 }}>
                  <Typography variant="body2" fontWeight={600}>
                    {credentials.length} credentials found
                  </Typography>
                  <Typography variant="caption">
                    Choose how to import these credentials into your vault.
                  </Typography>
                </Alert>

                {/* Import Mode */}
                <FormControl fullWidth sx={{ mb: 2 }}>
                  <InputLabel>Import Mode</InputLabel>
                  <Select
                    value={importMode}
                    label="Import Mode"
                    onChange={(e) => { setImportMode(e.target.value as ImportMode); }}
                  >
                    <MenuItem value="merge">
                      <Box>
                        <Typography variant="body2">Merge (Recommended)</Typography>
                        <Typography variant="caption" color="text.secondary">
                          Keep existing credentials and add new ones. Duplicates are skipped.
                        </Typography>
                      </Box>
                    </MenuItem>
                    <MenuItem value="replace">
                      <Box>
                        <Typography variant="body2">Replace All</Typography>
                        <Typography variant="caption" color="text.secondary">
                          Delete all existing credentials and replace with imported ones.
                        </Typography>
                      </Box>
                    </MenuItem>
                  </Select>
                </FormControl>

                {/* Warning for Replace Mode */}
                {importMode === 'replace' && (
                  <Alert severity="warning" icon={<Warning />} sx={{ mb: 2 }}>
                    <Typography variant="body2" fontWeight={600}>
                      Warning: Replace Mode
                    </Typography>
                    <Typography variant="caption">
                      This will permanently delete all your existing credentials before importing.
                      This action cannot be undone.
                    </Typography>
                  </Alert>
                )}
              </>
            )}
          </>
        )}
      </DialogContent>

      <DialogActions>
        <Button onClick={handleClose} disabled={decrypting || importing}>
          Cancel
        </Button>

        {!decrypted ? (
          <Button
            onClick={handleDecrypt}
            variant="contained"
            color="primary"
            disabled={!selectedFile || !exportPassword || decrypting}
            startIcon={decrypting ? <CircularProgress size={20} /> : undefined}
          >
            {decrypting ? 'Decrypting...' : 'Next'}
          </Button>
        ) : (
          <Button
            onClick={handleImport}
            variant="contained"
            color="primary"
            disabled={importing}
            startIcon={importing ? <CircularProgress size={20} /> : <Upload />}
          >
            Import {credentials.length} Credentials
          </Button>
        )}
      </DialogActions>
    </Dialog>
  );
}

import { useEffect, useState } from 'react';
import { Button, Snackbar } from '@mui/material';

export default function InstallPrompt() {
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [open, setOpen] = useState(false);

  useEffect(() => {
    function onBeforeInstall(e: Event) {
      // @ts-ignore - non-standard event
      e.preventDefault();
      // @ts-ignore
      setDeferredPrompt(e);
      setOpen(true);
    }

    window.addEventListener('beforeinstallprompt', onBeforeInstall as EventListener);

    return () => {
      window.removeEventListener('beforeinstallprompt', onBeforeInstall as EventListener);
    };
  }, []);

  const handleInstall = async () => {
    if (!deferredPrompt) return;
    try {
      // @ts-ignore
      deferredPrompt.prompt();
      // @ts-ignore
      const choice = await deferredPrompt.userChoice;
      setOpen(false);
      setDeferredPrompt(null);
      // choice.outcome is 'accepted' or 'dismissed'
      // We intentionally don't force a reload
    } catch (e) {
      setOpen(false);
    }
  };

  return (
    <Snackbar
      open={open}
      message="Install TrustVault for quick access"
      action={
        <Button
          color="inherit"
          size="small"
          onClick={handleInstall}
          data-tour="install-button"
        >
          Install
        </Button>
      }
      onClose={() => { setOpen(false); }}
    />
  );
}

/**
 * Mobile Navigation Component
 * Bottom navigation bar for mobile devices (<768px)
 */

import { useLocation, useNavigate } from 'react-router-dom';
import { BottomNavigation, BottomNavigationAction, Paper } from '@mui/material';
import {
  Dashboard as DashboardIcon,
  VpnKey as VpnKeyIcon,
  Settings as SettingsIcon,
} from '@mui/icons-material';

export default function MobileNavigation() {
  const location = useLocation();
  const navigate = useNavigate();

  // Determine active tab based on current route
  const getActiveTab = () => {
    const path = location.pathname;
    if (path === '/dashboard') return 0;
    if (path === '/generator') return 1;
    if (path === '/settings') return 2;
    return 0;
  };

  const handleChange = (_event: React.SyntheticEvent, newValue: number) => {
    switch (newValue) {
      case 0:
        navigate('/dashboard');
        break;
      case 1:
        // Navigate to standalone generator page (create if needed) or open dialog
        navigate('/dashboard'); // For now, stay on dashboard
        break;
      case 2:
        navigate('/settings');
        break;
    }
  };

  return (
    <Paper
      sx={{
        position: 'fixed',
        bottom: 0,
        left: 0,
        right: 0,
        zIndex: 1100,
        display: { xs: 'block', md: 'none' }, // Only show on mobile
      }}
      elevation={3}
    >
      <BottomNavigation value={getActiveTab()} onChange={handleChange} showLabels>
        <BottomNavigationAction label="Credentials" icon={<DashboardIcon />} />
        <BottomNavigationAction label="Generator" icon={<VpnKeyIcon />} />
        <BottomNavigationAction label="Settings" icon={<SettingsIcon />} />
      </BottomNavigation>
    </Paper>
  );
}

/**
 * OcrResultDialog
 *
 * Confirmation dialog for reviewing and editing OCR-detected credential fields
 * before applying them to the credential form.
 */

import { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Button,
  Box,
  Typography,
  Chip,
  Alert,
  IconButton,
  InputAdornment,
} from '@mui/material';
import VisibilityIcon from '@mui/icons-material/Visibility';
import VisibilityOffIcon from '@mui/icons-material/VisibilityOff';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import WarningIcon from '@mui/icons-material/Warning';
import InfoIcon from '@mui/icons-material/Info';

import { sanitizeValue, type ParsedCredential } from '@/core/ocr';

export interface OcrResultDialogProps {
  open: boolean;
  result: ParsedCredential | null;
  onClose: () => void;
  onApply: (fields: {
    username?: string;
    password?: string;
    url?: string;
    notes?: string;
  }) => void;
  onRescan: () => void;
}

function ConfidenceBadge({ confidence }: { confidence: number }) {
  if (confidence >= 0.8) {
    return (
      <Chip
        icon={<CheckCircleIcon />}
        label="High confidence"
        size="small"
        color="success"
        variant="outlined"
      />
    );
  }
  if (confidence >= 0.5) {
    return (
      <Chip
        icon={<WarningIcon />}
        label="Verify"
        size="small"
        color="warning"
        variant="outlined"
      />
    );
  }
  if (confidence > 0) {
    return (
      <Chip
        icon={<InfoIcon />}
        label="Low confidence"
        size="small"
        color="default"
        variant="outlined"
      />
    );
  }
  return null;
}

export function OcrResultDialog({
  open,
  result,
  onClose,
  onApply,
  onRescan,
}: OcrResultDialogProps) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [url, setUrl] = useState('');
  const [notes, setNotes] = useState('');
  const [showPassword, setShowPassword] = useState(false);

  // Update form when result changes
  useEffect(() => {
    if (result) {
      setUsername(sanitizeValue(result.username ?? ''));
      setPassword(sanitizeValue(result.password ?? ''));
      setUrl(sanitizeValue(result.url ?? ''));
      setNotes(sanitizeValue(result.notes ?? ''));
    }
  }, [result]);

  const handleApply = () => {
    const fields: {
      username?: string;
      password?: string;
      url?: string;
      notes?: string;
    } = {};

    if (username.trim()) fields.username = username.trim();
    if (password.trim()) fields.password = password.trim();
    if (url.trim()) fields.url = url.trim();
    if (notes.trim()) fields.notes = notes.trim();

    onApply(fields);
    onClose();
  };

  const hasAnyField =
    username.trim() || password.trim() || url.trim() || notes.trim();

  return (
    <Dialog open={open} onClose={onClose} maxWidth="sm" fullWidth>
      <DialogTitle>Review Detected Fields</DialogTitle>

      <DialogContent>
        {result && (
          <Box sx={{ mb: 2 }}>
            <Alert severity="info" sx={{ mb: 2 }}>
              Review and edit the detected fields before applying them to the
              form. Always verify passwords are correct.
            </Alert>

            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2.5 }}>
              {/* Username/Email */}
              <Box>
                <Box
                  sx={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    mb: 0.5,
                  }}
                >
                  <Typography variant="caption" color="text.secondary">
                    Username / Email
                  </Typography>
                  {result.confidence.username > 0 && (
                    <ConfidenceBadge confidence={result.confidence.username} />
                  )}
                </Box>
                <TextField
                  fullWidth
                  size="small"
                  value={username}
                  onChange={(e) => { setUsername(e.target.value); }}
                  placeholder="Not detected"
                />
              </Box>

              {/* Password */}
              <Box>
                <Box
                  sx={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    mb: 0.5,
                  }}
                >
                  <Typography variant="caption" color="text.secondary">
                    Password
                  </Typography>
                  {result.confidence.password > 0 && (
                    <ConfidenceBadge confidence={result.confidence.password} />
                  )}
                </Box>
                <TextField
                  fullWidth
                  size="small"
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={(e) => { setPassword(e.target.value); }}
                  placeholder="Not detected"
                  InputProps={{
                    endAdornment: (
                      <InputAdornment position="end">
                        <IconButton
                          onClick={() => { setShowPassword(!showPassword); }}
                          edge="end"
                          size="small"
                        >
                          {showPassword ? (
                            <VisibilityOffIcon />
                          ) : (
                            <VisibilityIcon />
                          )}
                        </IconButton>
                      </InputAdornment>
                    ),
                  }}
                />
                {result.confidence.password > 0 &&
                  result.confidence.password < 0.8 && (
                    <Typography
                      variant="caption"
                      color="warning.main"
                      sx={{ mt: 0.5, display: 'block' }}
                    >
                      ⚠️ Please verify the password is correct before saving
                    </Typography>
                  )}
              </Box>

              {/* URL */}
              <Box>
                <Box
                  sx={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    mb: 0.5,
                  }}
                >
                  <Typography variant="caption" color="text.secondary">
                    Website URL
                  </Typography>
                  {result.confidence.url > 0 && (
                    <ConfidenceBadge confidence={result.confidence.url} />
                  )}
                </Box>
                <TextField
                  fullWidth
                  size="small"
                  value={url}
                  onChange={(e) => { setUrl(e.target.value); }}
                  placeholder="Not detected"
                />
              </Box>

              {/* Notes */}
              <Box>
                <Box
                  sx={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    mb: 0.5,
                  }}
                >
                  <Typography variant="caption" color="text.secondary">
                    Notes
                  </Typography>
                  {result.confidence.notes > 0 && (
                    <ConfidenceBadge confidence={result.confidence.notes} />
                  )}
                </Box>
                <TextField
                  fullWidth
                  size="small"
                  multiline
                  rows={2}
                  value={notes}
                  onChange={(e) => { setNotes(e.target.value); }}
                  placeholder="Not detected"
                />
              </Box>
            </Box>

            {!hasAnyField && (
              <Alert severity="warning" sx={{ mt: 2 }}>
                No fields were detected. Try rescanning with better lighting or
                positioning.
              </Alert>
            )}
          </Box>
        )}
      </DialogContent>

      <DialogActions sx={{ px: 3, pb: 2 }}>
        <Button onClick={onRescan} color="inherit">
          Rescan
        </Button>
        <Button onClick={onClose} color="inherit">
          Cancel
        </Button>
        <Button
          onClick={handleApply}
          variant="contained"
          disabled={!hasAnyField}
        >
          Apply to Form
        </Button>
      </DialogActions>
    </Dialog>
  );
}

/**
 * Password Generator Dialog Component
 * Modal for generating secure passwords with customizable options
 */

import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Box,
  Typography,
  Slider,
  FormControlLabel,
  Checkbox,
  TextField,
  IconButton,
  Tooltip,
  Stack,
} from '@mui/material';
import {
  Close as CloseIcon,
  Refresh as RefreshIcon,
  ContentCopy as CopyIcon,
} from '@mui/icons-material';
import { usePasswordGenerator } from '@/presentation/hooks/usePasswordGenerator';
import PasswordStrengthIndicator from './PasswordStrengthIndicator';
import { copyPassword } from '@/presentation/utils/clipboard';
import { useState } from 'react';

interface PasswordGeneratorDialogProps {
  open: boolean;
  onClose: () => void;
  onUse: (password: string) => void;
}

export default function PasswordGeneratorDialog({
  open,
  onClose,
  onUse,
}: PasswordGeneratorDialogProps) {
  const {
    password,
    strength,
    options,
    generatePassword,
    setLength,
    toggleLowercase,
    toggleUppercase,
    toggleNumbers,
    toggleSymbols,
    toggleExcludeAmbiguous,
  } = usePasswordGenerator();

  const [copySuccess, setCopySuccess] = useState(false);

  const handleCopy = async () => {
    const success = await copyPassword(password, 30);
    if (success) {
      setCopySuccess(true);
      setTimeout(() => { setCopySuccess(false); }, 2000);
    }
  };

  const handleUse = () => {
    onUse(password);
    onClose();
  };

  const handleLengthChange = (_: Event, value: number | number[]) => {
    const length = Array.isArray(value) ? value[0] : value;
    if (length !== undefined) {
      setLength(length);
    }
  };

  // Check if at least one character type is selected
  const hasValidSelection =
    options.lowercase || options.uppercase || options.numbers || options.symbols;

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="sm"
      fullWidth
      PaperProps={{
        sx: {
          borderRadius: 2,
        },
      }}
    >
      {/* Header */}
      <DialogTitle>
        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <Typography variant="h6" component="div">
            Password Generator
          </Typography>
          <IconButton
            size="small"
            onClick={onClose}
            aria-label="close"
            sx={{ color: 'text.secondary' }}
          >
            <CloseIcon />
          </IconButton>
        </Box>
      </DialogTitle>

      <DialogContent dividers>
        <Stack spacing={3}>
          {/* Generated Password Display */}
          <Box>
            <TextField
              fullWidth
              value={password}
              InputProps={{
                readOnly: true,
                sx: {
                  fontFamily: 'monospace',
                  fontSize: '1.1rem',
                  letterSpacing: '0.5px',
                },
                endAdornment: (
                  <Box sx={{ display: 'flex', gap: 0.5 }}>
                    <Tooltip title={copySuccess ? 'Copied!' : 'Copy password'}>
                      <IconButton
                        size="small"
                        onClick={handleCopy}
                        color={copySuccess ? 'success' : 'default'}
                      >
                        <CopyIcon />
                      </IconButton>
                    </Tooltip>
                    <Tooltip title="Generate new password">
                      <IconButton size="small" onClick={generatePassword} color="primary">
                        <RefreshIcon />
                      </IconButton>
                    </Tooltip>
                  </Box>
                ),
              }}
              multiline
              maxRows={3}
            />
          </Box>

          {/* Password Strength Indicator */}
          {strength && (
            <Box>
              <PasswordStrengthIndicator password={password} showFeedback={false} />
            </Box>
          )}

          {/* Length Slider */}
          <Box>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
              <Typography variant="body2" color="text.secondary">
                Length
              </Typography>
              <Typography variant="body2" fontWeight="600">
                {options.length} characters
              </Typography>
            </Box>
            <Slider
              value={options.length}
              onChange={handleLengthChange}
              min={8}
              max={64}
              step={1}
              marks={[
                { value: 8, label: '8' },
                { value: 16, label: '16' },
                { value: 32, label: '32' },
                { value: 64, label: '64' },
              ]}
              sx={{
                '& .MuiSlider-markLabel': {
                  fontSize: '0.75rem',
                },
              }}
            />
          </Box>

          {/* Character Type Options */}
          <Box>
            <Typography variant="body2" color="text.secondary" gutterBottom>
              Character Types
            </Typography>
            <Stack spacing={0.5}>
              <FormControlLabel
                control={
                  <Checkbox
                    checked={options.lowercase}
                    onChange={toggleLowercase}
                    disabled={!hasValidSelection && options.lowercase}
                  />
                }
                label={
                  <Box>
                    <Typography variant="body2">Lowercase (a-z)</Typography>
                    <Typography variant="caption" color="text.secondary">
                      abcdefghijklmnopqrstuvwxyz
                    </Typography>
                  </Box>
                }
              />
              <FormControlLabel
                control={
                  <Checkbox
                    checked={options.uppercase}
                    onChange={toggleUppercase}
                    disabled={!hasValidSelection && options.uppercase}
                  />
                }
                label={
                  <Box>
                    <Typography variant="body2">Uppercase (A-Z)</Typography>
                    <Typography variant="caption" color="text.secondary">
                      ABCDEFGHIJKLMNOPQRSTUVWXYZ
                    </Typography>
                  </Box>
                }
              />
              <FormControlLabel
                control={
                  <Checkbox
                    checked={options.numbers}
                    onChange={toggleNumbers}
                    disabled={!hasValidSelection && options.numbers}
                  />
                }
                label={
                  <Box>
                    <Typography variant="body2">Numbers (0-9)</Typography>
                    <Typography variant="caption" color="text.secondary">
                      0123456789
                    </Typography>
                  </Box>
                }
              />
              <FormControlLabel
                control={
                  <Checkbox
                    checked={options.symbols}
                    onChange={toggleSymbols}
                    disabled={!hasValidSelection && options.symbols}
                  />
                }
                label={
                  <Box>
                    <Typography variant="body2">Symbols</Typography>
                    <Typography variant="caption" color="text.secondary">
                      !@#$%^&*()_+-=[]&#123;&#125;|;:,.&lt;&gt;?
                    </Typography>
                  </Box>
                }
              />
            </Stack>
          </Box>

          {/* Additional Options */}
          <Box>
            <Typography variant="body2" color="text.secondary" gutterBottom>
              Additional Options
            </Typography>
            <FormControlLabel
              control={
                <Checkbox
                  checked={options.excludeAmbiguous}
                  onChange={toggleExcludeAmbiguous}
                />
              }
              label={
                <Box>
                  <Typography variant="body2">Exclude ambiguous characters</Typography>
                  <Typography variant="caption" color="text.secondary">
                    Excludes: 0, O, o, I, i, l, 1, |
                  </Typography>
                </Box>
              }
            />
          </Box>

          {/* Warning if no character types selected */}
          {!hasValidSelection && (
            <Box
              sx={{
                p: 2,
                bgcolor: 'warning.main',
                color: 'warning.contrastText',
                borderRadius: 1,
              }}
            >
              <Typography variant="body2">
                Please select at least one character type
              </Typography>
            </Box>
          )}
        </Stack>
      </DialogContent>

      {/* Actions */}
      <DialogActions sx={{ px: 3, py: 2 }}>
        <Button onClick={onClose} variant="outlined">
          Cancel
        </Button>
        <Button onClick={handleUse} variant="contained" disabled={!hasValidSelection}>
          Use This Password
        </Button>
      </DialogActions>
    </Dialog>
  );
}

/**
 * Swipeable Credential Card Component
 * Mobile-optimized card with swipe-to-reveal actions
 */

import { useState, useRef, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Typography,
  IconButton,
  Chip,
} from '@mui/material';
import {
  Edit,
  Delete,
  Star,
  StarBorder,
} from '@mui/icons-material';
import type { Credential } from '@/domain/entities/Credential';
import { formatRelativeTime } from '@/presentation/utils/timeFormat';
import CategoryIcon, { getCategoryColor, getCategoryName } from './CategoryIcon';

interface SwipeableCredentialCardProps {
  credential: Credential;
  onEdit: (id: string) => void;
  onDelete: (id: string) => void;
  onToggleFavorite: (id: string) => void;
  onTap: (id: string) => void;
}

export default function SwipeableCredentialCard({
  credential,
  onEdit,
  onDelete,
  onToggleFavorite,
  onTap,
}: SwipeableCredentialCardProps) {
  const [swipeOffset, setSwipeOffset] = useState(0);
  const [isRevealed, setIsRevealed] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);
  const startX = useRef<number | null>(null);
  const currentX = useRef<number | null>(null);

  const handleTouchStart = (e: React.TouchEvent) => {
    startX.current = e.touches[0]?.clientX ?? null;
    currentX.current = startX.current;
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (!startX.current) return;

    currentX.current = e.touches[0]?.clientX ?? null;
    if (currentX.current === null) return;

    const diff = startX.current - currentX.current;

    // Only allow left swipe (reveal actions on right)
    if (diff > 0 && diff <= 160) {
      setSwipeOffset(diff);
    } else if (diff < 0) {
      setSwipeOffset(0); // Close if swiping right
    }
  };

  const handleTouchEnd = () => {
    if (swipeOffset > 80) {
      // Reveal actions
      setSwipeOffset(160);
      setIsRevealed(true);
    } else {
      // Snap back
      setSwipeOffset(0);
      setIsRevealed(false);
    }

    startX.current = null;
    currentX.current = null;
  };

  const handleTap = () => {
    if (isRevealed) {
      // Close actions if revealed
      setSwipeOffset(0);
      setIsRevealed(false);
    } else {
      // Open details
      onTap(credential.id);
    }
  };

  const handleEdit = () => {
    setSwipeOffset(0);
    setIsRevealed(false);
    onEdit(credential.id);
  };

  const handleDelete = () => {
    setSwipeOffset(0);
    setIsRevealed(false);
    onDelete(credential.id);
  };

  // Close swipe on outside click
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (cardRef.current && !cardRef.current.contains(event.target as Node)) {
        setSwipeOffset(0);
        setIsRevealed(false);
      }
    };

    if (isRevealed) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => { document.removeEventListener('mousedown', handleClickOutside); };
    }

    return undefined;
  }, [isRevealed]);

  return (
    <Box 
      ref={cardRef}
      sx={{ 
        position: 'relative', 
        overflow: 'hidden',
        touchAction: 'pan-y', // Allow vertical scrolling
      }}
    >
      {/* Action buttons behind card */}
      <Box
        sx={{
          position: 'absolute',
          right: 0,
          top: 0,
          bottom: 0,
          width: 160,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'flex-end',
          gap: 1,
          pr: 1,
        }}
      >
        <IconButton
          onClick={handleEdit}
          sx={{
            bgcolor: 'primary.main',
            color: 'white',
            width: 56,
            height: 56,
            '&:hover': {
              bgcolor: 'primary.dark',
            },
          }}
        >
          <Edit />
        </IconButton>
        <IconButton
          onClick={handleDelete}
          sx={{
            bgcolor: 'error.main',
            color: 'white',
            width: 56,
            height: 56,
            '&:hover': {
              bgcolor: 'error.dark',
            },
          }}
        >
          <Delete />
        </IconButton>
      </Box>

      {/* Swipeable card */}
      <Card
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
        onClick={handleTap}
        sx={{
          position: 'relative',
          transform: `translateX(-${swipeOffset}px)`,
          transition: startX.current === null ? 'transform 0.3s ease-out' : 'none',
          cursor: 'pointer',
          userSelect: 'none',
          minHeight: 140,
        }}
        elevation={2}
      >
        <CardContent sx={{ pb: 1 }}>
          {/* Header */}
          <Box sx={{ display: 'flex', alignItems: 'flex-start', mb: 1.5 }}>
            <CategoryIcon category={credential.category} size="small" />
            <Box sx={{ flex: 1, ml: 1.5, minWidth: 0 }}>
              <Typography 
                variant="h6" 
                component="div"
                sx={{ 
                  fontWeight: 600,
                  fontSize: '1rem',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                }}
              >
                {credential.title}
              </Typography>
              <Typography 
                variant="body2" 
                color="text.secondary"
                sx={{ 
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                }}
              >
                {credential.username}
              </Typography>
            </Box>
            <IconButton
              size="small"
              onClick={(e) => {
                e.stopPropagation();
                onToggleFavorite(credential.id);
              }}
              sx={{ ml: 1 }}
            >
              {credential.isFavorite ? (
                <Star sx={{ color: 'warning.main' }} />
              ) : (
                <StarBorder />
              )}
            </IconButton>
          </Box>

          {/* Category and updated time */}
          <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap', alignItems: 'center' }}>
            <Chip
              label={getCategoryName(credential.category)}
              size="small"
              sx={{
                backgroundColor: getCategoryColor(credential.category),
                color: 'white',
                fontWeight: 500,
                fontSize: '0.7rem',
                height: 20,
              }}
            />
            <Typography variant="caption" color="text.secondary">
              {formatRelativeTime(credential.updatedAt)}
            </Typography>
          </Box>

          {/* Tags */}
          {credential.tags.length > 0 && (
            <Box sx={{ display: 'flex', gap: 0.5, flexWrap: 'wrap', mt: 1 }}>
              {credential.tags.slice(0, 2).map((tag) => (
                <Chip
                  key={tag}
                  label={tag}
                  size="small"
                  variant="outlined"
                  sx={{ 
                    height: 20,
                    fontSize: '0.65rem',
                    '& .MuiChip-label': {
                      px: 0.75,
                    },
                  }}
                />
              ))}
              {credential.tags.length > 2 && (
                <Chip
                  label={`+${credential.tags.length - 2}`}
                  size="small"
                  variant="outlined"
                  sx={{ 
                    height: 20,
                    fontSize: '0.65rem',
                    '& .MuiChip-label': {
                      px: 0.75,
                    },
                  }}
                />
              )}
            </Box>
          )}
        </CardContent>
      </Card>
    </Box>
  );
}

/**
 * Tag Input Component
 * Input field with autocomplete for credential tags
 */

import { useState } from 'react';
import {
  Box,
  TextField,
  Chip,
  Autocomplete,
} from '@mui/material';

interface TagInputProps {
  tags: string[];
  onChange: (tags: string[]) => void;
  suggestions?: string[];
  disabled?: boolean;
}

export default function TagInput({
  tags,
  onChange,
  suggestions = [],
  disabled = false,
}: TagInputProps) {
  const [inputValue, setInputValue] = useState('');

  const handleAddTag = (newTag: string) => {
    const trimmedTag = newTag.trim().toLowerCase();

    // Validate tag
    if (!trimmedTag) return;
    if (tags.includes(trimmedTag)) return;
    if (trimmedTag.length > 50) return;

    // Add tag
    onChange([...tags, trimmedTag]);
    setInputValue('');
  };

  const handleDeleteTag = (tagToDelete: string) => {
    onChange(tags.filter((tag) => tag !== tagToDelete));
  };

  const handleKeyDown = (event: React.KeyboardEvent) => {
    if (event.key === 'Enter' && inputValue) {
      event.preventDefault();
      handleAddTag(inputValue);
    }
  };

  return (
    <Box>
      <Autocomplete
        freeSolo
        options={suggestions.filter((s) => !tags.includes(s))}
        inputValue={inputValue}
        onInputChange={(_, value) => { setInputValue(value); }}
        onChange={(_, value) => {
          if (typeof value === 'string') {
            handleAddTag(value);
          }
        }}
        disabled={disabled}
        renderInput={(params) => {
          // TypeScript workaround for exactOptionalPropertyTypes with MUI Autocomplete params
          // The params.size property can be undefined which conflicts with strict typing
          const textFieldParams = params as any;
          return (
            <TextField
              {...textFieldParams}
              label="Tags"
              placeholder={tags.length === 0 ? 'Add tags (press Enter)' : 'Add more tags'}
              helperText="Press Enter or select from suggestions"
              onKeyDown={handleKeyDown}
            />
          );
        }}
      />

      {/* Tag Chips */}
      {tags.length > 0 && (
        <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1, mt: 2 }}>
          {tags.map((tag) => (
            <Chip
              key={tag}
              label={tag}
              {...(!disabled && { onDelete: () => { handleDeleteTag(tag); } })}
              color="primary"
              variant="outlined"
            />
          ))}
        </Box>
      )}
    </Box>
  );
}

/**
 * TOTP Display Component
 * Shows live TOTP code with countdown timer
 */

import { useState, useEffect } from 'react';
import {
  Box,
  Typography,
  IconButton,
  CircularProgress,
  Tooltip,
  Paper,
} from '@mui/material';
import { ContentCopy, Check } from '@mui/icons-material';
import {
  generateTOTP,
  formatTOTPCode,
  getTOTPRemaining,
  isValidTOTPSecret,
} from '@/core/auth/totp';

interface TotpDisplayProps {
  totpSecret: string;
  timeStep?: number;
}

export default function TotpDisplay({ totpSecret, timeStep = 30 }: TotpDisplayProps) {
  const [code, setCode] = useState<string>('');
  const [remaining, setRemaining] = useState<number>(0);
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Validate TOTP secret on mount
  useEffect(() => {
    if (!isValidTOTPSecret(totpSecret)) {
      setError('Invalid TOTP secret format');
      return;
    }

    setError(null);
  }, [totpSecret]);

  // Update TOTP code and countdown every second
  useEffect(() => {
    if (error) return;

    const updateTOTP = () => {
      try {
        const now = Date.now();
        const newCode = generateTOTP(totpSecret, timeStep, 6, now);
        const newRemaining = getTOTPRemaining(timeStep, now);

        setCode(newCode);
        setRemaining(newRemaining);
      } catch (err) {
        console.error('Failed to generate TOTP:', err);
        setError('Failed to generate code');
      }
    };

    // Initial generation
    updateTOTP();

    // Update every second
    const interval = setInterval(updateTOTP, 1000);

    return () => { clearInterval(interval); };
  }, [totpSecret, timeStep, error]);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(code);
      setCopied(true);

      // Reset copied state after 2 seconds
      setTimeout(() => {
        setCopied(false);
      }, 2000);
    } catch (err) {
      console.error('Failed to copy TOTP code:', err);
    }
  };

  // Calculate progress percentage (0-100)
  const progress = (remaining / timeStep) * 100;

  // Color based on remaining time
  const getColor = () => {
    if (remaining <= 5) return 'error'; // Red when < 5 seconds
    if (remaining <= 10) return 'warning'; // Orange when < 10 seconds
    return 'primary'; // Blue otherwise
  };

  if (error) {
    return (
      <Paper
        sx={{
          p: 2,
          backgroundColor: 'error.dark',
          color: 'error.contrastText',
        }}
      >
        <Typography variant="body2">{error}</Typography>
      </Paper>
    );
  }

  return (
    <Paper
      elevation={0}
      sx={{
        p: 2,
        backgroundColor: 'background.default',
        border: '1px solid',
        borderColor: 'divider',
        display: 'flex',
        alignItems: 'center',
        gap: 2,
      }}
    >
      {/* TOTP Code */}
      <Box sx={{ flexGrow: 1 }}>
        <Typography variant="caption" color="text.secondary" sx={{ mb: 0.5, display: 'block' }}>
          2FA Code
        </Typography>
        <Typography
          variant="h4"
          component="div"
          sx={{
            fontFamily: 'monospace',
            fontWeight: 600,
            letterSpacing: 2,
            color: getColor() + '.main',
          }}
        >
          {formatTOTPCode(code)}
        </Typography>
      </Box>

      {/* Countdown Timer */}
      <Box sx={{ position: 'relative', display: 'inline-flex' }}>
        <CircularProgress
          variant="determinate"
          value={progress}
          size={48}
          thickness={4}
          color={getColor()}
        />
        <Box
          sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            bottom: 0,
            right: 0,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          <Typography
            variant="caption"
            component="div"
            color="text.secondary"
            sx={{ fontWeight: 600 }}
          >
            {remaining}s
          </Typography>
        </Box>
      </Box>

      {/* Copy Button */}
      <Tooltip title={copied ? 'Copied!' : 'Copy code'}>
        <IconButton
          onClick={handleCopy}
          color={copied ? 'success' : 'default'}
          sx={{ ml: 1 }}
        >
          {copied ? <Check /> : <ContentCopy />}
        </IconButton>
      </Tooltip>
    </Paper>
  );
}

/**
 * UnlockDialog Component
 * Prompts user to re-enter master password to unlock vault
 * Used when vault is locked but user is still authenticated
 */

import { useState } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Button,
  Box,
  Typography,
  Alert,
  CircularProgress,
  InputAdornment,
  IconButton,
} from '@mui/material';
import { Lock, Visibility, VisibilityOff } from '@mui/icons-material';
import { useAuthStore } from '../store/authStore';
import { userRepository } from '@/data/repositories/UserRepositoryImpl';

interface UnlockDialogProps {
  open: boolean;
  onClose?: () => void;
}

export default function UnlockDialog({ open, onClose }: UnlockDialogProps) {
  const { user, unlockVault } = useAuthStore();
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [unlocking, setUnlocking] = useState(false);

  const handleUnlock = async () => {
    if (!user) {
      setError('User session not found. Please sign in again.');
      return;
    }

    if (!password) {
      setError('Please enter your master password');
      return;
    }

    setUnlocking(true);
    setError(null);

    try {
      // Authenticate with password to get vault key
      const session = await userRepository.authenticateWithPassword(user.email, password);

      // Unlock vault with the vault key
      unlockVault(session.vaultKey);

      // Clear password from memory
      setPassword('');

      // Close dialog
      if (onClose) {
        onClose();
      }
    } catch (err) {
      console.error('Unlock failed:', err);
      setError('Incorrect password. Please try again.');
    } finally {
      setUnlocking(false);
    }
  };

  const handleKeyPress = (event: React.KeyboardEvent) => {
    if (event.key === 'Enter' && !unlocking) {
      handleUnlock();
    }
  };

  const handleClose = () => {
    if (unlocking) return; // Prevent closing during unlock
    setPassword('');
    setError(null);
    if (onClose) {
      onClose();
    }
  };

  return (
    <Dialog
      open={open}
      onClose={handleClose}
      maxWidth="xs"
      fullWidth
      disableEscapeKeyDown={unlocking}
    >
      <DialogTitle>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <Lock color="primary" />
          <Typography variant="h6">Vault Locked</Typography>
        </Box>
      </DialogTitle>

      <DialogContent>
        <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
          Your vault is locked for security. Enter your master password to unlock and access your
          credentials.
        </Typography>

        {user && (
          <Alert severity="info" sx={{ mb: 2 }}>
            <Typography variant="body2">
              <strong>Account:</strong> {user.email}
            </Typography>
          </Alert>
        )}

        {error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}

        <TextField
          fullWidth
          label="Master Password"
          type={showPassword ? 'text' : 'password'}
          value={password}
          onChange={(e) => { setPassword(e.target.value); }}
          onKeyPress={handleKeyPress}
          disabled={unlocking}
          autoFocus
          placeholder="Enter your master password"
          InputProps={{
            endAdornment: (
              <InputAdornment position="end">
                <IconButton
                  onClick={() => { setShowPassword(!showPassword); }}
                  edge="end"
                  disabled={unlocking}
                >
                  {showPassword ? <VisibilityOff /> : <Visibility />}
                </IconButton>
              </InputAdornment>
            ),
          }}
        />

        <Typography variant="caption" color="text.secondary" sx={{ mt: 1, display: 'block' }}>
          Your master password is never stored and is used only to decrypt your vault.
        </Typography>
      </DialogContent>

      <DialogActions sx={{ px: 3, pb: 2 }}>
        <Button onClick={handleClose} disabled={unlocking}>
          Cancel
        </Button>
        <Button
          variant="contained"
          onClick={handleUnlock}
          disabled={!password || unlocking}
          startIcon={unlocking ? <CircularProgress size={16} /> : <Lock />}
        >
          {unlocking ? 'Unlocking...' : 'Unlock Vault'}
        </Button>
      </DialogActions>
    </Dialog>
  );
}

import { useEffect, useState } from 'react';
import { Button, Snackbar } from '@mui/material';

export default function UpdateAvailableSnackbar() {
  const [open, setOpen] = useState(false);
  const [registration, setRegistration] = useState<ServiceWorkerRegistration | null>(null);

  useEffect(() => {
    if (!('serviceWorker' in navigator)) return;

    navigator.serviceWorker.getRegistration().then((reg) => {
      if (!reg) return;
      setRegistration(reg);

      // If there's a waiting SW, an update is available
      if (reg.waiting) {
        setOpen(true);
      }

      reg.addEventListener('updatefound', () => {
        const newWorker = reg.installing;
        if (!newWorker) return;
        newWorker.addEventListener('statechange', () => {
          if (newWorker.state === 'installed' && reg.waiting) {
            setOpen(true);
          }
        });
      });
    });

    // Reload when the new service worker has taken control
    const onControllerChange = () => {
      window.location.reload();
    };
    navigator.serviceWorker.addEventListener('controllerchange', onControllerChange);

    return () => {
      try {
        navigator.serviceWorker.removeEventListener('controllerchange', onControllerChange);
      } catch (e) {
        // ignore
      }
    };
  }, []);

  const handleRefresh = () => {
    if (!registration) return;
    // Tell SW to skip waiting
    if (registration.waiting) {
      registration.waiting.postMessage({ type: 'SKIP_WAITING' });
    }
  };

  return (
    <Snackbar
      open={open}
      message="A new version is available"
      action={<Button color="inherit" size="small" onClick={handleRefresh}>Update</Button>}
      onClose={() => { setOpen(false); }}
    />
  );
}

/**
 * Update Notification Component
 * Non-intrusive banner for PWA updates
 *
 * Features:
 * - Bottom-anchored slide-up notification
 * - Version display (current → available)
 * - Update Now / Dismiss actions
 * - Installing state feedback
 * - Auto-show on update detection
 * - Cross-platform styling
 */

import { useState, useEffect, type ReactElement } from 'react';
import {
  Snackbar,
  Alert,
  AlertTitle,
  Button,
  Box,
  Typography,
  CircularProgress,
  Slide,
} from '@mui/material';
import type { TransitionProps } from '@mui/material/transitions';
import {
  SystemUpdate,
  Close,
  CheckCircle,
} from '@mui/icons-material';
import { useServiceWorkerUpdate } from '../hooks/useServiceWorkerUpdate';

function SlideTransition(props: TransitionProps & { children: ReactElement }) {
  return <Slide {...props} direction="up" appear={props.appear ?? true} />;
}

export default function UpdateNotification() {
  const {
    updateAvailable,
    updateInstalling,
    currentVersion,
    availableVersion,
    installUpdate,
    dismissUpdate,
  } = useServiceWorkerUpdate();

  const [showSuccessMessage, setShowSuccessMessage] = useState(false);

  // Check for update completion on mount
  useEffect(() => {
    const wasUpdated = sessionStorage.getItem('sw-update-completed');
    if (wasUpdated === 'true') {
      sessionStorage.removeItem('sw-update-completed');
      setShowSuccessMessage(true);
      // Auto-hide after 5 seconds
      setTimeout(() => { setShowSuccessMessage(false); }, 5000);
    }
  }, []);

  const handleUpdateNow = async (): Promise<void> => {
    await installUpdate();
  };

  const handleDismiss = (): void => {
    dismissUpdate();
  };

  // Show success message after update
  if (showSuccessMessage) {
    return (
      <Snackbar
        open={true}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
        TransitionComponent={SlideTransition}
        onClose={() => { setShowSuccessMessage(false); }}
        sx={{ bottom: { xs: 70, md: 24 } }} // Account for mobile navigation
      >
        <Alert
          severity="success"
          icon={<CheckCircle />}
          onClose={() => { setShowSuccessMessage(false); }}
          sx={{
            width: '100%',
            maxWidth: 600,
            boxShadow: 3,
          }}
        >
          <AlertTitle>Updated Successfully</AlertTitle>
          TrustVault has been updated to the latest version
          {availableVersion && ` (${availableVersion})`}
        </Alert>
      </Snackbar>
    );
  }

  // Show update notification
  if (!updateAvailable) {
    return null;
  }

  return (
    <Snackbar
      open={updateAvailable}
      anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
      TransitionComponent={SlideTransition}
      sx={{ bottom: { xs: 70, md: 24 } }} // Account for mobile navigation
    >
      <Alert
        severity="info"
        icon={<SystemUpdate />}
        sx={{
          width: '100%',
          maxWidth: 600,
          boxShadow: 3,
          '& .MuiAlert-action': {
            alignItems: 'flex-start',
            paddingTop: 0,
          },
        }}
        action={
          <Button
            color="inherit"
            size="small"
            onClick={handleDismiss}
            disabled={updateInstalling}
            startIcon={<Close />}
            sx={{ mt: -0.5 }}
          >
            Later
          </Button>
        }
      >
        <AlertTitle>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <span>Update Available</span>
            {updateInstalling && (
              <CircularProgress size={16} color="inherit" />
            )}
          </Box>
        </AlertTitle>

        <Typography variant="body2" sx={{ mb: 1.5 }}>
          A new version of TrustVault is ready to install
          {currentVersion && availableVersion && (
            <Box component="span" sx={{ display: 'block', mt: 0.5, opacity: 0.8 }}>
              {currentVersion} → {availableVersion}
            </Box>
          )}
        </Typography>

        <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap' }}>
          <Button
            variant="contained"
            size="small"
            onClick={handleUpdateNow}
            disabled={updateInstalling}
            startIcon={updateInstalling ? <CircularProgress size={16} /> : <SystemUpdate />}
            sx={{
              bgcolor: 'primary.main',
              color: 'primary.contrastText',
              '&:hover': {
                bgcolor: 'primary.dark',
              },
            }}
          >
            {updateInstalling ? 'Installing...' : 'Update Now'}
          </Button>
        </Box>

        {updateInstalling && (
          <Typography variant="caption" sx={{ display: 'block', mt: 1, opacity: 0.7 }}>
            The page will reload automatically when the update is complete
          </Typography>
        )}
      </Alert>
    </Snackbar>
  );
}

/**
 * Auto-Lock Hook Tests
 * Phase 2.3 validation
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { renderHook, act } from '@testing-library/react';
import { useEffect, useRef, useCallback } from 'react';

// Mock auto-lock hook
interface AutoLockConfig {
  enabled: boolean;
  timeoutMinutes: number;
  lockOnTabSwitch?: boolean;
}

const createUseAutoLock = (lockCallback: () => void) => {
  return (config: AutoLockConfig) => {
    const timeoutRef = useRef<NodeJS.Timeout | null>(null);
    const lastActivityRef = useRef<number>(Date.now());

    const resetTimer = useCallback(() => {
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
        timeoutRef.current = null;
      }

      if (!config.enabled) return;

      timeoutRef.current = setTimeout(() => {
        lockCallback();
      }, config.timeoutMinutes * 60 * 1000);

      lastActivityRef.current = Date.now();
    }, [config.enabled, config.timeoutMinutes]);

    const handleActivity = useCallback(() => {
      resetTimer();
    }, [resetTimer]);

    const handleVisibilityChange = useCallback(() => {
      if (config.lockOnTabSwitch && document.hidden) {
        lockCallback();
      }
    }, [config.lockOnTabSwitch]);

    // Setup and cleanup with useEffect
    useEffect(() => {
      if (typeof document === 'undefined') return;

      document.addEventListener('mousemove', handleActivity);
      document.addEventListener('keypress', handleActivity);
      document.addEventListener('click', handleActivity);
      document.addEventListener('visibilitychange', handleVisibilityChange);
      resetTimer();

      // Cleanup
      return () => {
        if (timeoutRef.current) {
          clearTimeout(timeoutRef.current);
          timeoutRef.current = null;
        }
        document.removeEventListener('mousemove', handleActivity);
        document.removeEventListener('keypress', handleActivity);
        document.removeEventListener('click', handleActivity);
        document.removeEventListener('visibilitychange', handleVisibilityChange);
      };
    }, [handleActivity, handleVisibilityChange, resetTimer]);

    return {
      resetTimer,
      lastActivityTime: lastActivityRef.current,
    };
  };
};

describe('Auto-Lock Hook', () => {
  let lockCallback: ReturnType<typeof vi.fn>;
  let useAutoLock: ReturnType<typeof createUseAutoLock>;

  beforeEach(() => {
    vi.useFakeTimers();
    lockCallback = vi.fn();
    useAutoLock = createUseAutoLock(lockCallback);
  });

  afterEach(() => {
    vi.useRealTimers();
    vi.clearAllMocks();
  });

  describe('Basic Functionality', () => {
    it('should setup hook with config', () => {
      const config: AutoLockConfig = { enabled: true, timeoutMinutes: 15 };

      const { result } = renderHook(() => useAutoLock(config));

      expect(result.current).toBeDefined();
    });

    it('should trigger lock after timeout', async () => {
      const config: AutoLockConfig = { enabled: true, timeoutMinutes: 1 };

      renderHook(() => useAutoLock(config));

      await act(async () => {
        await vi.advanceTimersByTimeAsync(60 * 1000); // 1 minute
      });

      expect(lockCallback).toHaveBeenCalledTimes(1);
    });

    it('should not trigger lock when disabled', async () => {
      const config: AutoLockConfig = { enabled: false, timeoutMinutes: 1 };

      renderHook(() => useAutoLock(config));

      await act(async () => {
        await vi.advanceTimersByTimeAsync(60 * 1000);
      });

      expect(lockCallback).not.toHaveBeenCalled();
    });

    it('should respect different timeout values', async () => {
      const config: AutoLockConfig = { enabled: true, timeoutMinutes: 5 };

      renderHook(() => useAutoLock(config));

      // Before timeout
      await act(async () => {
        await vi.advanceTimersByTimeAsync(4 * 60 * 1000);
      });
      expect(lockCallback).not.toHaveBeenCalled();

      // After timeout
      await act(async () => {
        await vi.advanceTimersByTimeAsync(60 * 1000);
      });
      expect(lockCallback).toHaveBeenCalledTimes(1);
    });
  });

  describe('Activity Detection', () => {
    it('should reset timer on mouse move', async () => {
      const config: AutoLockConfig = { enabled: true, timeoutMinutes: 1 };

      renderHook(() => useAutoLock(config));

      // Wait 30 seconds
      await act(async () => {
        await vi.advanceTimersByTimeAsync(30 * 1000);
      });

      // Trigger mouse move
      await act(async () => {
        document.dispatchEvent(new MouseEvent('mousemove'));
      });

      // Wait another 45 seconds (total 75s, but reset at 30s)
      await act(async () => {
        await vi.advanceTimersByTimeAsync(45 * 1000);
      });

      expect(lockCallback).not.toHaveBeenCalled();

      // Wait remaining 15 seconds (60s from last activity)
      await act(async () => {
        await vi.advanceTimersByTimeAsync(15 * 1000);
      });

      expect(lockCallback).toHaveBeenCalledTimes(1);
    });

    it('should reset timer on keypress', async () => {
      const config: AutoLockConfig = { enabled: true, timeoutMinutes: 1 };

      renderHook(() => useAutoLock(config));

      await act(async () => {
        await vi.advanceTimersByTimeAsync(30 * 1000);
      });

      await act(async () => {
        document.dispatchEvent(new KeyboardEvent('keypress'));
      });

      await act(async () => {
        await vi.advanceTimersByTimeAsync(45 * 1000);
      });

      expect(lockCallback).not.toHaveBeenCalled();
    });

    it('should reset timer on click', async () => {
      const config: AutoLockConfig = { enabled: true, timeoutMinutes: 1 };

      renderHook(() => useAutoLock(config));

      await act(async () => {
        await vi.advanceTimersByTimeAsync(30 * 1000);
      });

      await act(async () => {
        document.dispatchEvent(new MouseEvent('click'));
      });

      await act(async () => {
        await vi.advanceTimersByTimeAsync(45 * 1000);
      });

      expect(lockCallback).not.toHaveBeenCalled();
    });

    it('should handle multiple rapid activities', async () => {
      const config: AutoLockConfig = { enabled: true, timeoutMinutes: 1 };

      renderHook(() => useAutoLock(config));

      // Simulate rapid user activity
      for (let i = 0; i < 10; i++) {
        await act(async () => {
          await vi.advanceTimersByTimeAsync(5 * 1000);
          document.dispatchEvent(new MouseEvent('mousemove'));
        });
      }

      expect(lockCallback).not.toHaveBeenCalled();
    });
  });

  describe('Tab Visibility', () => {
    it('should lock when tab becomes hidden if configured', async () => {
      const config: AutoLockConfig = {
        enabled: true,
        timeoutMinutes: 15,
        lockOnTabSwitch: true
      };

      renderHook(() => useAutoLock(config));

      await act(async () => {
        Object.defineProperty(document, 'hidden', {
          value: true,
          writable: true,
          configurable: true
        });
        document.dispatchEvent(new Event('visibilitychange'));
      });

      expect(lockCallback).toHaveBeenCalledTimes(1);
    });

    it('should not lock on tab switch if not configured', async () => {
      const config: AutoLockConfig = {
        enabled: true,
        timeoutMinutes: 15,
        lockOnTabSwitch: false
      };

      renderHook(() => useAutoLock(config));

      await act(async () => {
        Object.defineProperty(document, 'hidden', {
          value: true,
          writable: true,
          configurable: true
        });
        document.dispatchEvent(new Event('visibilitychange'));
      });

      expect(lockCallback).not.toHaveBeenCalled();
    });

    it('should not lock when tab becomes visible', async () => {
      const config: AutoLockConfig = {
        enabled: true,
        timeoutMinutes: 15,
        lockOnTabSwitch: true
      };

      renderHook(() => useAutoLock(config));

      await act(async () => {
        Object.defineProperty(document, 'hidden', {
          value: false,
          writable: true,
          configurable: true
        });
        document.dispatchEvent(new Event('visibilitychange'));
      });

      expect(lockCallback).not.toHaveBeenCalled();
    });
  });

  describe('Cleanup', () => {
    it('should cleanup timers on unmount', async () => {
      const config: AutoLockConfig = { enabled: true, timeoutMinutes: 1 };

      const { unmount } = renderHook(() => useAutoLock(config));

      unmount();

      await act(async () => {
        await vi.advanceTimersByTimeAsync(60 * 1000);
      });

      expect(lockCallback).not.toHaveBeenCalled();
    });

    it('should cleanup event listeners on unmount', () => {
      const config: AutoLockConfig = { enabled: true, timeoutMinutes: 15 };

      const addEventListenerSpy = vi.spyOn(document, 'addEventListener');
      const removeEventListenerSpy = vi.spyOn(document, 'removeEventListener');

      const { unmount } = renderHook(() => useAutoLock(config));

      const addCallCount = addEventListenerSpy.mock.calls.length;

      unmount();

      expect(removeEventListenerSpy).toHaveBeenCalledTimes(addCallCount);

      addEventListenerSpy.mockRestore();
      removeEventListenerSpy.mockRestore();
    });
  });

  describe('Security Considerations', () => {
    it('should lock after configured time regardless of tab state', async () => {
      const config: AutoLockConfig = {
        enabled: true,
        timeoutMinutes: 1,
        lockOnTabSwitch: false
      };

      renderHook(() => useAutoLock(config));

      // Even with tab visible, should lock after timeout
      await act(async () => {
        Object.defineProperty(document, 'hidden', {
          value: false,
          writable: true,
          configurable: true
        });
        await vi.advanceTimersByTimeAsync(60 * 1000);
      });

      expect(lockCallback).toHaveBeenCalledTimes(1);
    });

    it('should support very short timeouts for high security', async () => {
      const config: AutoLockConfig = {
        enabled: true,
        timeoutMinutes: 0.25 // 15 seconds
      };

      renderHook(() => useAutoLock(config));

      await act(async () => {
        await vi.advanceTimersByTimeAsync(15 * 1000);
      });

      expect(lockCallback).toHaveBeenCalledTimes(1);
    });

    it('should support disabling auto-lock for convenience', async () => {
      const config: AutoLockConfig = {
        enabled: false,
        timeoutMinutes: 1
      };

      renderHook(() => useAutoLock(config));

      await act(async () => {
        await vi.advanceTimersByTimeAsync(60 * 1000);
      });

      expect(lockCallback).not.toHaveBeenCalled();
    });
  });
});

/**
