      });
    });
  });

  describe('Password Generation', () => {
    it('should generate password with correct length', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      act(() => {
        result.current.setLength(16);
      });

      await waitFor(() => {
        expect(result.current.password.length).toBe(16);
      });
    });

    it('should generate different passwords on each call', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      await waitFor(() => {
        expect(result.current.password).toBeTruthy();
      });

      const firstPassword = result.current.password;

      act(() => {
        result.current.generatePassword();
      });

      await waitFor(() => {
        expect(result.current.password).not.toBe(firstPassword);
      });
    });

    it('should include uppercase when enabled', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      act(() => {
        result.current.updateOptions({
          uppercase: true,
          lowercase: false,
          numbers: false,
          symbols: false,
          length: 30,
        });
      });

      await waitFor(() => {
        expect(/[A-Z]/.test(result.current.password)).toBe(true);
        expect(/[a-z]/.test(result.current.password)).toBe(false);
      });
    });

    it('should include lowercase when enabled', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      act(() => {
        result.current.updateOptions({
          uppercase: false,
          lowercase: true,
          numbers: false,
          symbols: false,
          length: 30,
        });
      });

      await waitFor(() => {
        expect(/[a-z]/.test(result.current.password)).toBe(true);
        expect(/[A-Z]/.test(result.current.password)).toBe(false);
      });
    });

    it('should include numbers when enabled', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      act(() => {
        result.current.updateOptions({
          uppercase: false,
          lowercase: false,
          numbers: true,
          symbols: false,
          length: 30,
        });
      });

      await waitFor(() => {
        expect(/[0-9]/.test(result.current.password)).toBe(true);
      });
    });

    it('should include symbols when enabled', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      act(() => {
        result.current.updateOptions({
          uppercase: false,
          lowercase: false,
          numbers: false,
          symbols: true,
          length: 30,
        });
      });

      await waitFor(() => {
        expect(/[!@#$%^&*()_+\-=[\]{};:,.<>?]/.test(result.current.password)).toBe(true);
      });
    });

    it('should exclude ambiguous characters when requested', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      act(() => {
        result.current.updateOptions({
          excludeAmbiguous: true,
          length: 100,
        });
      });

      await waitFor(() => {
        // Should not contain: i, l, o, 0, 1, I, O, |
        expect(/[il0O|]/.test(result.current.password)).toBe(false);
      });
    });
  });

  describe('Option Updates', () => {
    it('should update length', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      act(() => {
        result.current.setLength(24);
      });

      expect(result.current.options.length).toBe(24);
      await waitFor(() => {
        expect(result.current.password.length).toBe(24);
      });
    });

    it('should toggle uppercase', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      const initialValue = result.current.options.uppercase;

      act(() => {
        result.current.toggleUppercase();
      });

      expect(result.current.options.uppercase).toBe(!initialValue);
    });

    it('should toggle lowercase', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      const initialValue = result.current.options.lowercase;

      act(() => {
        result.current.toggleLowercase();
      });

      expect(result.current.options.lowercase).toBe(!initialValue);
    });

    it('should toggle numbers', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      const initialValue = result.current.options.numbers;

      act(() => {
        result.current.toggleNumbers();
      });

      expect(result.current.options.numbers).toBe(!initialValue);
    });

    it('should toggle symbols', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      const initialValue = result.current.options.symbols;

      act(() => {
        result.current.toggleSymbols();
      });

      expect(result.current.options.symbols).toBe(!initialValue);
    });

    it('should toggle exclude ambiguous', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      const initialValue = result.current.options.excludeAmbiguous;

      act(() => {
        result.current.toggleExcludeAmbiguous();
      });

      expect(result.current.options.excludeAmbiguous).toBe(!initialValue);
    });
  });

  describe('Strength Calculation', () => {
    it('should calculate strength for generated password', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      await waitFor(() => {
        expect(result.current.strength).toBeTruthy();
        expect(result.current.strength?.score).toBeGreaterThan(0);
        expect(result.current.strength?.strength).toBeDefined();
      });
    });

    it('should update strength when password changes', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      await waitFor(() => {
        expect(result.current.strength).toBeTruthy();
      });

      act(() => {
        result.current.generatePassword();
      });

      await waitFor(() => {
        // Strength might be same or different, but should be recalculated
        expect(result.current.strength?.score).toBeDefined();
      });
    });
  });

  describe('Preferences Persistence', () => {
    it('should save options to localStorage', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      act(() => {
        result.current.updateOptions({
          length: 32,
          excludeAmbiguous: true,
        });
      });

      const saved = localStorage.getItem('trustvault_password_generator_prefs');
      expect(saved).toBeTruthy();

      const parsed = JSON.parse(saved!);
      expect(parsed.length).toBe(32);
      expect(parsed.excludeAmbiguous).toBe(true);
    });

    it('should restore options from localStorage', () => {
      const savedOptions = {
        length: 24,
        uppercase: true,
        lowercase: true,
        numbers: false,
        symbols: true,
        excludeAmbiguous: true,
      };

      localStorage.setItem('trustvault_password_generator_prefs', JSON.stringify(savedOptions));

      const { result } = renderHook(() => usePasswordGenerator());

      expect(result.current.options.length).toBe(24);
      expect(result.current.options.numbers).toBe(false);
      expect(result.current.options.excludeAmbiguous).toBe(true);
    });
  });

  describe('Edge Cases', () => {
    it('should handle minimum length', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      act(() => {
        result.current.setLength(8);
      });

      await waitFor(() => {
        expect(result.current.password.length).toBeGreaterThanOrEqual(8);
      });
    });

    it('should handle maximum length', async () => {
      const { result } = renderHook(() => usePasswordGenerator());

      act(() => {
        result.current.setLength(128);
      });

      await waitFor(() => {
        expect(result.current.password.length).toBeLessThanOrEqual(128);
      });
    });

    it('should generate unique passwords', async () => {
      const { result } = renderHook(() => usePasswordGenerator());
      const passwords = new Set<string>();

      await waitFor(() => {
        expect(result.current.password).toBeTruthy();
      });

      for (let i = 0; i < 10; i++) {
        act(() => {
          result.current.generatePassword();
        });

        await waitFor(() => {
          passwords.add(result.current.password);
        });
      }

      // Most should be unique (allow for very rare collisions)
      expect(passwords.size).toBeGreaterThan(8);
    });
  });
});

/**
 * Auto-Lock Hook
 * Implements automatic session locking based on inactivity and tab visibility
 */

import { useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuthStore } from '@/presentation/store/authStore';
import { useCredentialStore } from '@/presentation/store/credentialStore';

export interface AutoLockConfig {
  timeoutMinutes: number; // 0 = disabled/never
  lockOnTabHidden: boolean;
  onLock?: () => void;
}

/**
 * Hook to automatically lock the vault after inactivity
 * @param config Auto-lock configuration
 */
export function useAutoLock(config: AutoLockConfig) {
  const navigate = useNavigate();
  const { isAuthenticated, lock } = useAuthStore();
  const { clearCredentials } = useCredentialStore();

  const timeoutRef = useRef<NodeJS.Timeout | null>(null);
  const lastActivityRef = useRef<number>(Date.now());
  const isLockedRef = useRef<boolean>(false);

  /**
   * Lock the vault and clear sensitive data
   */
  const performLock = useCallback(() => {
    if (isLockedRef.current) return; // Prevent double-locking

    console.log('[AutoLock] Locking vault due to inactivity');
    isLockedRef.current = true;

    // Clear vault key and credentials from memory
    lock();
    clearCredentials();

    // Call optional callback
    config.onLock?.();

    // Navigate to signin with locked state indicator
    navigate('/signin', {
      state: { locked: true, message: 'Session locked due to inactivity' }
    });
  }, [lock, clearCredentials, navigate, config]);

  /**
   * Reset the inactivity timer
   */
  const resetTimer = useCallback(() => {
    if (config.timeoutMinutes === 0) return; // Never lock
    if (!isAuthenticated) return; // Not authenticated, no need to track

    lastActivityRef.current = Date.now();

    // Clear existing timeout
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
    }

    // Set new timeout
    const timeoutMs = config.timeoutMinutes * 60 * 1000;
    timeoutRef.current = setTimeout(() => {
      const elapsed = Date.now() - lastActivityRef.current;

      // Double-check elapsed time (in case system clock changed)
      if (elapsed >= timeoutMs) {
        performLock();
      }
    }, timeoutMs);
  }, [config.timeoutMinutes, isAuthenticated, performLock]);

  /**
   * Handle user activity events
   */
  const handleActivity = useCallback(() => {
    if (!isAuthenticated) return;
    resetTimer();
  }, [isAuthenticated, resetTimer]);

  /**
   * Handle tab visibility changes
   */
  const handleVisibilityChange = useCallback(() => {
    if (!isAuthenticated) return;

    if (document.visibilityState === 'hidden') {
      if (config.lockOnTabHidden) {
        console.log('[AutoLock] Tab hidden, locking immediately');
        performLock();
      }
    } else if (document.visibilityState === 'visible') {
      // Tab became visible again, reset timer
      console.log('[AutoLock] Tab visible, resetting timer');
      isLockedRef.current = false; // Allow locking again
      resetTimer();
    }
  }, [isAuthenticated, config.lockOnTabHidden, performLock, resetTimer]);

  /**
   * Setup event listeners for activity detection
   */
  useEffect(() => {
    if (!isAuthenticated || config.timeoutMinutes === 0) {
      // Clean up if not authenticated or auto-lock disabled
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
        timeoutRef.current = null;
      }
      return;
    }

    // Reset locked state when authenticated
    isLockedRef.current = false;

    // Activity events to track
    const activityEvents = [
      'mousedown',
      'mousemove',
      'keydown',
      'scroll',
      'touchstart',
      'click',
    ];

    // Add event listeners
    activityEvents.forEach((event) => {
      document.addEventListener(event, handleActivity, { passive: true });
    });

    // Add visibility change listener
    document.addEventListener('visibilitychange', handleVisibilityChange);

    // Start initial timer
    resetTimer();

    // Cleanup
    return () => {
      activityEvents.forEach((event) => {
        document.removeEventListener(event, handleActivity);
      });
      document.removeEventListener('visibilitychange', handleVisibilityChange);

      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
        timeoutRef.current = null;
      }
    };
  }, [isAuthenticated, config.timeoutMinutes, config.lockOnTabHidden, handleActivity, handleVisibilityChange, resetTimer]);

  /**
   * Reset timer when config changes
   */
  useEffect(() => {
    if (isAuthenticated && config.timeoutMinutes > 0) {
      resetTimer();
    }
  }, [config.timeoutMinutes, isAuthenticated, resetTimer]);

  return {
    resetTimer,
    performLock,
  };
}

/**
 * Get default auto-lock configuration from user settings
 */
export function getDefaultAutoLockConfig(
  sessionTimeoutMinutes?: number
): AutoLockConfig {
  return {
    timeoutMinutes: sessionTimeoutMinutes ?? 15, // Default 15 minutes
    lockOnTabHidden: false, // Don't lock immediately on tab switch by default
  };
}

/**
 * Service Worker Update Hook
 * Handles PWA update detection and installation across all platforms
 *
 * Features:
 * - Automatic update detection when new SW enters "waiting" state
 * - Manual update check via button/menu
 * - Cross-platform support (Android WebAPK, iOS standalone, Desktop PWA)
 * - skipWaiting() pattern with postMessage communication
 * - Session storage to preserve state across reload
 */

import { useState, useEffect, useCallback, useRef } from 'react';

export interface ServiceWorkerUpdateState {
  // Update availability
  updateAvailable: boolean;
  updateChecking: boolean;
  updateInstalling: boolean;

  // Version information
  currentVersion: string | null;
  availableVersion: string | null;

  // Actions
  checkForUpdate: () => Promise<void>;
  installUpdate: () => Promise<void>;
  dismissUpdate: () => void;

  // Error handling
  error: string | null;
}

const SW_UPDATE_DISMISSED_KEY = 'sw-update-dismissed';
const SW_UPDATE_AVAILABLE_KEY = 'sw-update-available';

/**
 * Custom hook for managing service worker updates
 */
export function useServiceWorkerUpdate(): ServiceWorkerUpdateState {
  const [updateAvailable, setUpdateAvailable] = useState(false);
  const [updateChecking, setUpdateChecking] = useState(false);
  const [updateInstalling, setUpdateInstalling] = useState(false);
  const [currentVersion, setCurrentVersion] = useState<string | null>(null);
  const [availableVersion, setAvailableVersion] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const waitingWorkerRef = useRef<ServiceWorker | null>(null);
  const registrationRef = useRef<ServiceWorkerRegistration | null>(null);

  /**
   * Get current service worker version from active worker
   */
  const fetchCurrentVersion = useCallback(async () => {
    if (!navigator.serviceWorker.controller) {
      return null;
    }

    try {
      // Query the active service worker for its version
      const messageChannel = new MessageChannel();

      return new Promise<string | null>((resolve) => {
        messageChannel.port1.onmessage = (event) => {
          if (event.data && event.data.type === 'VERSION') {
            resolve(event.data.version);
          } else {
            resolve(null);
          }
        };

        navigator.serviceWorker.controller?.postMessage(
          { type: 'GET_VERSION' },
          [messageChannel.port2]
        );

        // Timeout after 2 seconds
        setTimeout(() => { resolve(null); }, 2000);
      });
    } catch (err) {
      console.error('Failed to fetch current version:', err);
      return null;
    }
  }, []);

  /**
   * Get version from waiting service worker
   */
  const fetchWaitingVersion = useCallback(async (worker: ServiceWorker) => {
    try {
      const messageChannel = new MessageChannel();

      return new Promise<string | null>((resolve) => {
        messageChannel.port1.onmessage = (event) => {
          if (event.data && event.data.type === 'VERSION') {
            resolve(event.data.version);
          } else {
            resolve(null);
          }
        };

        worker.postMessage(
          { type: 'GET_VERSION' },
          [messageChannel.port2]
        );

        // Timeout after 2 seconds
        setTimeout(() => { resolve(null); }, 2000);
      });
    } catch (err) {
      console.error('Failed to fetch waiting version:', err);
      return null;
    }
  }, []);

  /**
   * Handle update found (new service worker waiting)
   */
  const handleUpdateFound = useCallback(async (registration: ServiceWorkerRegistration) => {
    const waitingWorker = registration.waiting;
    if (!waitingWorker) return;

    console.log('Service worker update found');

    waitingWorkerRef.current = waitingWorker;
    registrationRef.current = registration;

    // Check if user previously dismissed this update
    const dismissed = sessionStorage.getItem(SW_UPDATE_DISMISSED_KEY);
    if (dismissed === waitingWorker.scriptURL) {
      console.log('User dismissed this update, not showing notification');
      return;
    }

    // Fetch versions
    const [current, available] = await Promise.all([
      fetchCurrentVersion(),
      fetchWaitingVersion(waitingWorker)
    ]);

    setCurrentVersion(current);
    setAvailableVersion(available);
    setUpdateAvailable(true);

    // Store in session for persistence
    sessionStorage.setItem(SW_UPDATE_AVAILABLE_KEY, 'true');
  }, [fetchCurrentVersion, fetchWaitingVersion]);

  /**
   * Check for service worker updates manually
   */
  const checkForUpdate = useCallback(async () => {
    if (!('serviceWorker' in navigator)) {
      setError('Service workers are not supported in this browser');
      return;
    }

    setUpdateChecking(true);
    setError(null);

    try {
      const registration = await navigator.serviceWorker.getRegistration();

      if (!registration) {
        setError('No service worker registered');
        setUpdateChecking(false);
        return;
      }

      console.log('Checking for service worker updates...');

      // Trigger update check
      await registration.update();

      // Wait a bit for the update to process
      await new Promise(resolve => setTimeout(resolve, 1000));

      // Check if there's a waiting worker
      if (registration.waiting) {
        await handleUpdateFound(registration);
      } else if (!registration.installing) {
        // No update available
        console.log('No service worker update available');
        setError(null); // Clear any previous errors
      }
    } catch (err) {
      console.error('Failed to check for updates:', err);
      setError('Failed to check for updates. Please try again.');
    } finally {
      setUpdateChecking(false);
    }
  }, [handleUpdateFound]);

  /**
   * Install the waiting service worker update
   */
  const installUpdate = useCallback(async () => {
    const waitingWorker = waitingWorkerRef.current;

    if (!waitingWorker) {
      setError('No update available to install');
      return;
    }

    setUpdateInstalling(true);
    setError(null);

    try {
      // Clear dismissed flag
      sessionStorage.removeItem(SW_UPDATE_DISMISSED_KEY);

      // Set flag to show success message after reload
      sessionStorage.setItem('sw-update-completed', 'true');

      // Send SKIP_WAITING message to the waiting worker
      waitingWorker.postMessage({ type: 'SKIP_WAITING' });

      // Listen for controllerchange event
      navigator.serviceWorker.addEventListener('controllerchange', () => {
        console.log('New service worker activated, reloading page...');
        // Reload the page to use the new service worker
        window.location.reload();
      }, { once: true });

    } catch (err) {
      console.error('Failed to install update:', err);
      setError('Failed to install update. Please try again.');
      setUpdateInstalling(false);
    }
  }, []);

  /**
   * Dismiss the update notification (user can update later)
   */
  const dismissUpdate = useCallback(() => {
    const waitingWorker = waitingWorkerRef.current;

    if (waitingWorker) {
      // Store dismissal in session storage
      sessionStorage.setItem(SW_UPDATE_DISMISSED_KEY, waitingWorker.scriptURL);
    }

    sessionStorage.removeItem(SW_UPDATE_AVAILABLE_KEY);
    setUpdateAvailable(false);
    console.log('Update notification dismissed');
  }, []);

  /**
   * Setup service worker update listeners
   */
  useEffect(() => {
    if (!('serviceWorker' in navigator)) {
      return;
    }

    let registration: ServiceWorkerRegistration | null = null;
    let intervalId: NodeJS.Timeout | null = null;

    const setupListeners = async (): Promise<void> => {
      try {
        registration = await navigator.serviceWorker.getRegistration() ?? null;

        if (!registration) {
          console.log('No service worker registration found');
          return;
        }

        registrationRef.current = registration;

        // Fetch current version
        const version = await fetchCurrentVersion();
        setCurrentVersion(version);

        // Check if there's already a waiting worker
        if (registration.waiting) {
          await handleUpdateFound(registration);
        }

        // Listen for new service worker installing
        registration.addEventListener('updatefound', () => {
          if (!registration) return;
          const installingWorker = registration.installing;

          if (!installingWorker) return;

          console.log('New service worker installing...');

          installingWorker.addEventListener('statechange', () => {
            if (installingWorker.state === 'installed' && navigator.serviceWorker.controller && registration) {
              // New service worker installed and waiting
              void handleUpdateFound(registration);
            }
          });
        });

        // Check on interval (every 60 seconds) - only in production
        if (import.meta.env.PROD) {
          intervalId = setInterval(() => {
            registration?.update().catch(console.error);
          }, 60000); // Check every minute
        }
      } catch (err) {
        console.error('Failed to setup service worker listeners:', err);
      }
    };

    void setupListeners();

    // Cleanup
    return () => {
      if (intervalId) {
        clearInterval(intervalId);
      }
    };
  }, [fetchCurrentVersion, handleUpdateFound]);

  /**
   * Check session storage on mount for persisted update state
   */
  useEffect(() => {
    const wasUpdateAvailable = sessionStorage.getItem(SW_UPDATE_AVAILABLE_KEY);
    if (wasUpdateAvailable === 'true') {
      // Re-check for update
      checkForUpdate();
    }
  }, [checkForUpdate]);

  return {
    updateAvailable,
    updateChecking,
    updateInstalling,
    currentVersion,
    availableVersion,
    checkForUpdate,
    installUpdate,
    dismissUpdate,
    error,
  };
}

/**
 * Add Credential Page
 * Form to create a new credential entry
 */

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Paper,
  MenuItem,
  IconButton,
  InputAdornment,
  FormControlLabel,
  Checkbox,
  Alert,
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  ArrowBack,
  Save,
  AutoAwesome,
  CameraAlt,
} from '@mui/icons-material';
import { credentialRepository } from '@/data/repositories/CredentialRepositoryImpl';
import { useAuthStore } from '@/presentation/store/authStore';
import PasswordStrengthIndicator from '@/presentation/components/PasswordStrengthIndicator';
import PasswordGeneratorDialog from '@/presentation/components/PasswordGeneratorDialog';
import TotpDisplay from '@/presentation/components/TotpDisplay';
import TagInput from '@/presentation/components/TagInput';
import { isValidTOTPSecret } from '@/core/auth/totp';
import type { CredentialCategory } from '@/domain/entities/Credential';
import {
  storeCredentialInBrowser,
  toBrowserCredential,
  isCredentialManagementSupported,
} from '@/core/autofill/credentialManagementService';
import { CameraScanDialog } from '@/presentation/components/CameraScanDialog';
import { OcrResultDialog } from '@/presentation/components/OcrResultDialog';
import { isCameraSupported, type ParsedCredential } from '@/core/ocr';

const CATEGORIES: { value: CredentialCategory; label: string }[] = [
  { value: 'login', label: 'Login' },
  { value: 'credit_card', label: 'Credit Card' },
  { value: 'bank_account', label: 'Bank Account' },
  { value: 'secure_note', label: 'Secure Note' },
  { value: 'identity', label: 'Identity' },
  { value: 'api_key', label: 'API Key' },
  { value: 'ssh_key', label: 'SSH Key' },
];

export default function AddCredentialPage() {
  const navigate = useNavigate();
  const { vaultKey } = useAuthStore();

  // Form state
  const [title, setTitle] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [url, setUrl] = useState('');
  const [notes, setNotes] = useState('');
  const [category, setCategory] = useState<CredentialCategory>('login');
  const [tags, setTags] = useState<string[]>([]);
  const [isFavorite, setIsFavorite] = useState(false);
  const [totpSecret, setTotpSecret] = useState('');

  // Card-specific state
  const [cardNumber, setCardNumber] = useState('');
  const [cardholderName, setCardholderName] = useState('');
  const [expiryMonth, setExpiryMonth] = useState('');
  const [expiryYear, setExpiryYear] = useState('');
  const [cvv, setCvv] = useState('');
  const [cardType, setCardType] = useState<'visa' | 'mastercard' | 'amex' | 'discover' | 'other'>('visa');
  const [billingAddress, setBillingAddress] = useState('');

  // UI state
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [generatorOpen, setGeneratorOpen] = useState(false);

  // OCR scan state
  const [scanDialogOpen, setScanDialogOpen] = useState(false);
  const [ocrResultDialogOpen, setOcrResultDialogOpen] = useState(false);
  const [ocrResult, setOcrResult] = useState<ParsedCredential | null>(null);

  // Validation
  const [errors, setErrors] = useState<Record<string, string>>({});

  const validateForm = (): boolean => {
    const newErrors: Record<string, string> = {};

    if (!title.trim()) {
      newErrors.title = 'Title is required';
    }

    // For credit cards, validate card-specific fields instead of username/password
    if (category === 'credit_card') {
      if (!cardNumber.trim()) {
        newErrors.cardNumber = 'Card number is required';
      } else if (!/^\d{13,19}$/.test(cardNumber.replace(/\s/g, ''))) {
        newErrors.cardNumber = 'Invalid card number format';
      }

      if (!cardholderName.trim()) {
        newErrors.cardholderName = 'Cardholder name is required';
      }

      if (!expiryMonth || !expiryYear) {
        newErrors.expiry = 'Expiration date is required';
      }

      if (!cvv.trim()) {
        newErrors.cvv = 'CVV is required';
      } else if (!/^\d{3,4}$/.test(cvv)) {
        newErrors.cvv = 'Invalid CVV format';
      }
    } else {
      // Standard validation for non-card credentials
      if (!username.trim()) {
        newErrors.username = 'Username is required';
      }

      if (!password) {
        newErrors.password = 'Password is required';
      } else if (password.length < 4) {
        newErrors.password = 'Password must be at least 4 characters';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleGeneratePassword = () => {
    setGeneratorOpen(true);
  };

  const handleUseGeneratedPassword = (generatedPassword: string) => {
    setPassword(generatedPassword);
  };

  // OCR scan handlers
  const handleOpenScan = () => {
    setScanDialogOpen(true);
  };

  const handleScanResult = (result: ParsedCredential) => {
    setOcrResult(result);
    setScanDialogOpen(false);
    setOcrResultDialogOpen(true);
  };

  const handleApplyOcrResult = (fields: {
    username?: string;
    password?: string;
    url?: string;
    notes?: string;
  }) => {
    if (fields.username) setUsername(fields.username);
    if (fields.password) setPassword(fields.password);
    if (fields.url) setUrl(fields.url);
    if (fields.notes) setNotes(fields.notes);
    setOcrResultDialogOpen(false);
  };

  const handleRescan = () => {
    setOcrResultDialogOpen(false);
    setScanDialogOpen(true);
  };

  const handleSave = async () => {
    if (!validateForm()) {
      return;
    }

    if (!vaultKey) {
      setError('Session expired. Please sign in again.');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const inputData: any = {
        title: title.trim(),
        category,
        tags,
        url: url.trim() || undefined,
        notes: notes.trim() || undefined,
      };

      // Add card-specific fields for credit cards
      if (category === 'credit_card') {
        inputData.username = cardholderName.trim(); // Store cardholder name as username
        inputData.password = 'N/A'; // Placeholder for required field
        inputData.cardNumber = cardNumber.replace(/\s/g, '');
        inputData.cardholderName = cardholderName.trim();
        inputData.expiryMonth = expiryMonth;
        inputData.expiryYear = expiryYear;
        inputData.cvv = cvv;
        inputData.cardType = cardType;
        inputData.billingAddress = billingAddress.trim() || undefined;
      } else {
        // Standard credential fields
        inputData.username = username.trim();
        inputData.password = password;
        inputData.totpSecret = totpSecret.trim() || undefined;
      }

      const credential = await credentialRepository.create(inputData, vaultKey);

      // Update favorite status after creation if needed
      if (isFavorite) {
        await credentialRepository.update(credential.id, { isFavorite: true }, vaultKey);
      }

      // Store credential in browser for autofill (if supported and applicable)
      if (
        credential.category === 'login' &&
        credential.url &&
        isCredentialManagementSupported()
      ) {
        try {
          const browserCred = toBrowserCredential(credential);
          if (browserCred) {
            await storeCredentialInBrowser(browserCred);
          }
        } catch (err) {
          // Non-critical: autofill storage failed, but credential was saved
          console.warn('Failed to store credential in browser for autofill:', err);
        }
      }

      // Navigate back to dashboard
      navigate('/dashboard');
    } catch (err) {
      console.error('Failed to save credential:', err);
      setError(err instanceof Error ? err.message : 'Failed to save credential');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="md" sx={{ py: 4 }}>
      <Paper sx={{ p: 3 }}>
        {/* Header */}
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
          <IconButton onClick={() => navigate('/dashboard')} sx={{ mr: 2 }}>
            <ArrowBack />
          </IconButton>
          <Typography variant="h5" component="h1" sx={{ fontWeight: 600, flex: 1 }}>
            Add Credential
          </Typography>
          {isCameraSupported() && (
            <Button
              variant="outlined"
              startIcon={<CameraAlt />}
              onClick={handleOpenScan}
              size="small"
            >
              Scan
            </Button>
          )}
        </Box>

        {/* Error Alert */}
        {error && (
          <Alert severity="error" sx={{ mb: 3 }} onClose={() => { setError(null); }}>
            {error}
          </Alert>
        )}

        {/* Form */}
        <Box component="form" noValidate>
          {/* Title */}
          <TextField
            fullWidth
            label="Title"
            value={title}
            onChange={(e) => { setTitle(e.target.value); }}
            error={!!errors.title}
            helperText={errors.title}
            margin="normal"
            required
            placeholder="e.g., Gmail Account, Work VPN"
          />

          {/* Category */}
          <TextField
            fullWidth
            select
            label="Category"
            value={category}
            onChange={(e) => { setCategory(e.target.value as CredentialCategory); }}
            margin="normal"
          >
            {CATEGORIES.map((cat) => (
              <MenuItem key={cat.value} value={cat.value}>
                {cat.label}
              </MenuItem>
            ))}
          </TextField>

          {/* Conditional Fields based on Category */}
          {category === 'credit_card' ? (
            <>
              {/* Card Number */}
              <TextField
                fullWidth
                label="Card Number"
                value={cardNumber}
                onChange={(e) => { setCardNumber(e.target.value); }}
                error={!!errors.cardNumber}
                helperText={errors.cardNumber}
                margin="normal"
                required
                placeholder="1234 5678 9012 3456"
                inputProps={{ maxLength: 19 }}
              />

              {/* Cardholder Name */}
              <TextField
                fullWidth
                label="Cardholder Name"
                value={cardholderName}
                onChange={(e) => { setCardholderName(e.target.value); }}
                error={!!errors.cardholderName}
                helperText={errors.cardholderName}
                margin="normal"
                required
                placeholder="JOHN DOE"
              />

              {/* Card Type */}
              <TextField
                fullWidth
                select
                label="Card Type"
                value={cardType}
                onChange={(e) => { setCardType(e.target.value as typeof cardType); }}
                margin="normal"
              >
                <MenuItem value="visa">Visa</MenuItem>
                <MenuItem value="mastercard">Mastercard</MenuItem>
                <MenuItem value="amex">American Express</MenuItem>
                <MenuItem value="discover">Discover</MenuItem>
                <MenuItem value="other">Other</MenuItem>
              </TextField>

              {/* Expiry Date */}
              <Box sx={{ display: 'flex', gap: 2, mt: 2 }}>
                <TextField
                  select
                  label="Expiry Month"
                  value={expiryMonth}
                  onChange={(e) => { setExpiryMonth(e.target.value); }}
                  error={!!errors.expiry}
                  required
                  sx={{ flex: 1 }}
                >
                  {Array.from({ length: 12 }, (_, i) => {
                    const month = String(i + 1).padStart(2, '0');
                    return (
                      <MenuItem key={month} value={month}>
                        {month}
                      </MenuItem>
                    );
                  })}
                </TextField>

                <TextField
                  select
                  label="Expiry Year"
                  value={expiryYear}
                  onChange={(e) => { setExpiryYear(e.target.value); }}
                  error={!!errors.expiry}
                  required
                  sx={{ flex: 1 }}
                >
                  {Array.from({ length: 15 }, (_, i) => {
                    const year = String(new Date().getFullYear() + i);
                    return (
                      <MenuItem key={year} value={year}>
                        {year}
                      </MenuItem>
                    );
                  })}
                </TextField>
              </Box>
              {errors.expiry && (
                <Typography color="error" variant="caption" sx={{ mt: 1, ml: 2 }}>
                  {errors.expiry}
                </Typography>
              )}

              {/* CVV */}
              <TextField
                fullWidth
                label="CVV / Security Code"
                type={showPassword ? 'text' : 'password'}
                value={cvv}
                onChange={(e) => { setCvv(e.target.value); }}
                error={!!errors.cvv}
                helperText={errors.cvv}
                margin="normal"
                required
                placeholder="123"
                inputProps={{ maxLength: 4 }}
                InputProps={{
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={() => { setShowPassword(!showPassword); }}
                        edge="end"
                        title={showPassword ? 'Hide CVV' : 'Show CVV'}
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />

              {/* Billing Address */}
              <TextField
                fullWidth
                label="Billing Address (Optional)"
                value={billingAddress}
                onChange={(e) => { setBillingAddress(e.target.value); }}
                margin="normal"
                multiline
                rows={2}
                placeholder="123 Main St, City, State ZIP"
              />
            </>
          ) : (
            <>
              {/* Username */}
              <TextField
                fullWidth
                label="Username / Email"
                value={username}
                onChange={(e) => { setUsername(e.target.value); }}
                error={!!errors.username}
                helperText={errors.username}
                margin="normal"
                required
                placeholder="user@example.com"
              />

              {/* Password */}
              <TextField
                fullWidth
                label="Password"
                type={showPassword ? 'text' : 'password'}
                value={password}
                onChange={(e) => { setPassword(e.target.value); }}
                error={!!errors.password}
                helperText={errors.password}
                margin="normal"
                required
                InputProps={{
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={handleGeneratePassword}
                        edge="end"
                        title="Generate password"
                        sx={{ mr: 1 }}
                      >
                        <AutoAwesome />
                      </IconButton>
                      <IconButton
                        onClick={() => { setShowPassword(!showPassword); }}
                        edge="end"
                        title={showPassword ? 'Hide password' : 'Show password'}
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />

              {/* Password Strength Indicator */}
              <PasswordStrengthIndicator password={password} showFeedback />

              {/* TOTP Secret (2FA) */}
              <TextField
                fullWidth
                label="TOTP Secret (Optional)"
                value={totpSecret}
                onChange={(e) => { setTotpSecret(e.target.value); }}
                margin="normal"
                placeholder="Base32-encoded secret (e.g., from Google Authenticator)"
                helperText="Enter the base32-encoded secret key for 2FA/TOTP authentication"
              />

              {/* TOTP Preview */}
              {totpSecret.trim() && isValidTOTPSecret(totpSecret.trim()) && (
                <Box sx={{ mt: 2 }}>
                  <TotpDisplay totpSecret={totpSecret.trim()} />
                </Box>
              )}

              {totpSecret.trim() && !isValidTOTPSecret(totpSecret.trim()) && (
                <Alert severity="warning" sx={{ mt: 2 }}>
                  Invalid TOTP secret format. Please enter a valid base32-encoded secret.
                </Alert>
              )}
            </>
          )}

          {/* URL */}
          <TextField
            fullWidth
            label="Website URL"
            value={url}
            onChange={(e) => { setUrl(e.target.value); }}
            margin="normal"
            placeholder="https://example.com"
            type="url"
          />

          {/* Tags */}
          <Box sx={{ mt: 2, mb: 1 }}>
            <TagInput tags={tags} onChange={setTags} />
          </Box>

          {/* Notes */}
          <TextField
            fullWidth
            label="Notes"
            value={notes}
            onChange={(e) => { setNotes(e.target.value); }}
            margin="normal"
            multiline
            rows={4}
            placeholder="Additional information..."
          />

          {/* Favorite Checkbox */}
          <FormControlLabel
            control={
              <Checkbox
                checked={isFavorite}
                onChange={(e) => { setIsFavorite(e.target.checked); }}
              />
            }
            label="Add to favorites"
            sx={{ mt: 2 }}
          />

          {/* Action Buttons */}
          <Box sx={{ display: 'flex', gap: 2, mt: 4 }}>
            <Button
              variant="outlined"
              onClick={() => navigate('/dashboard')}
              disabled={loading}
              fullWidth
            >
              Cancel
            </Button>
            <Button
              variant="contained"
              onClick={handleSave}
              disabled={loading}
              startIcon={<Save />}
              fullWidth
            >
              {loading ? 'Saving...' : 'Save Credential'}
            </Button>
          </Box>
        </Box>
      </Paper>

      {/* Password Generator Dialog */}
      <PasswordGeneratorDialog
        open={generatorOpen}
        onClose={() => { setGeneratorOpen(false); }}
        onUse={handleUseGeneratedPassword}
      />

      {/* Camera Scan Dialog */}
      <CameraScanDialog
        open={scanDialogOpen}
        onClose={() => { setScanDialogOpen(false); }}
        onResult={handleScanResult}
      />

      {/* OCR Result Dialog */}
      <OcrResultDialog
        open={ocrResultDialogOpen}
        result={ocrResult}
        onClose={() => { setOcrResultDialogOpen(false); }}
        onApply={handleApplyOcrResult}
        onRescan={handleRescan}
      />
    </Container>
  );
}

/**
 * Dashboard Page Component
 * Main credential management interface
 */

import { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Box,
  AppBar,
  Toolbar,
  Typography,
  IconButton,
  Drawer,
  List,
  ListItemIcon,
  ListItemText,
  ListItemButton,
  Card,
  CardContent,
  Button,
  Fab,
  Menu,
  MenuItem,
  Avatar,
  Snackbar,
  Alert,
  CircularProgress,
  useTheme,
  useMediaQuery,
} from '@mui/material';
import Grid from '@mui/material/Grid2';
import {
  Menu as MenuIcon,
  Add as AddIcon,
  Lock as LockIcon,
  Settings as SettingsIcon,
  Logout as LogoutIcon,
  Dashboard as DashboardIcon,
  Favorite as FavoriteIcon,
  Security as SecurityIcon,
  AccessTime,
  Star as StarIcon,
  VpnKey as VpnKeyIcon,
} from '@mui/icons-material';
import { useAuthStore } from '../store/authStore';
import { credentialRepository } from '@/data/repositories/CredentialRepositoryImpl';
import CredentialCard from '@/presentation/components/CredentialCard';
import SwipeableCredentialCard from '@/presentation/components/SwipeableCredentialCard';
import CredentialDetailsDialog from '@/presentation/components/CredentialDetailsDialog';
import CredentialSection from '@/presentation/components/CredentialSection';
import DeleteConfirmDialog from '@/presentation/components/DeleteConfirmDialog';
import SearchBar from '@/presentation/components/SearchBar';
import FilterChips from '@/presentation/components/FilterChips';
import SortDropdown, { type SortOption } from '@/presentation/components/SortDropdown';
import ThemeToggle from '@/presentation/components/ThemeToggle';
import TourHelpButton from '@/components/TourHelpButton';
import type { Credential, CredentialCategory } from '@/domain/entities/Credential';
import { clipboardManager } from '@/presentation/utils/clipboard';
import BreachAlertBanner from '@/presentation/components/BreachAlertBanner';

export default function DashboardPage() {
  const navigate = useNavigate();
  const { user, logout, vaultKey } = useAuthStore();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));

  // UI state
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [menuAnchor, setMenuAnchor] = useState<null | HTMLElement>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [snackbarOpen, setSnackbarOpen] = useState(false);
  const [snackbarMessage, setSnackbarMessage] = useState('');

  // Mobile details dialog state
  const [detailsDialogOpen, setDetailsDialogOpen] = useState(false);
  const [selectedCredential, setSelectedCredential] = useState<Credential | null>(null);

  // Filter and sort state
  const [selectedCategory, setSelectedCategory] = useState<CredentialCategory | 'all'>('all');
  const [favoritesOnly, setFavoritesOnly] = useState(false);
  const [selectedTags, setSelectedTags] = useState<string[]>([]);
  const [sortBy, setSortBy] = useState<SortOption>('updated-desc');

  // Credentials state
  const [credentials, setCredentials] = useState<Credential[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Delete dialog state
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [credentialToDelete, setCredentialToDelete] = useState<string | null>(null);
  const [deleting, setDeleting] = useState(false);

  // Load credentials function
  const loadCredentials = useCallback(async () => {
    if (!vaultKey) {
      setError('No vault key available');
      setLoading(false);
      return;
    }

    try {
      setLoading(true);
      setError(null);
      const creds = await credentialRepository.findAll(vaultKey);
      setCredentials(creds);
    } catch (err) {
      console.error('Failed to load credentials:', err);
      setError(err instanceof Error ? err.message : 'Failed to load credentials');
    } finally {
      setLoading(false);
    }
  }, [vaultKey]);

  // Load credentials on mount and when vaultKey changes
  useEffect(() => {
    loadCredentials();
  }, [loadCredentials]);

  const showSnackbar = (message: string) => {
    setSnackbarMessage(message);
    setSnackbarOpen(true);
  };

  const handleLogout = useCallback(() => {
    logout();
  }, [logout]);

  const handleLockVault = useCallback(() => {
    // Lock the vault (clears vault key, keeps user authenticated)
    useAuthStore.getState().lockVault();
    showSnackbar('Vault locked successfully');
  }, [showSnackbar]);

  const handleEdit = useCallback((id: string) => {
    navigate(`/credentials/${id}/edit`);
  }, [navigate]);

  const handleDeleteRequest = useCallback((id: string) => {
    setCredentialToDelete(id);
    setDeleteDialogOpen(true);
  }, []);

  const handleDeleteConfirm = useCallback(async () => {
    if (!credentialToDelete) return;

    setDeleting(true);
    try {
      await credentialRepository.delete(credentialToDelete);
      setCredentials((prev) => prev.filter((c) => c.id !== credentialToDelete));
      showSnackbar('Credential deleted successfully');
      setDeleteDialogOpen(false);
      setCredentialToDelete(null);
    } catch (err) {
      console.error('Failed to delete credential:', err);
      showSnackbar('Failed to delete credential');
    } finally {
      setDeleting(false);
    }
  }, [credentialToDelete, showSnackbar]);

  const handleToggleFavorite = async (id: string) => {
    if (!vaultKey) return;

    try {
      const credential = credentials.find((c) => c.id === id);
      if (!credential) return;

      const newFavoriteState = !credential.isFavorite;

      await credentialRepository.update(
        id,
        { isFavorite: newFavoriteState },
        vaultKey
      );

      // Update local state
      setCredentials((prev) =>
        prev.map((c) => (c.id === id ? { ...c, isFavorite: newFavoriteState } : c))
      );

      showSnackbar(newFavoriteState ? 'Added to favorites' : 'Removed from favorites');
    } catch (err) {
      console.error('Failed to toggle favorite:', err);
      showSnackbar('Failed to update favorite');
    }
  };

  const getCredentialToDelete = () => {
    return credentials.find((c) => c.id === credentialToDelete);
  };

  // Mobile-specific handlers
  const handleCredentialTap = (id: string) => {
    if (isMobile) {
      const credential = credentials.find((c) => c.id === id);
      if (credential) {
        setSelectedCredential(credential);
        setDetailsDialogOpen(true);
      }
    }
  };

  const handleCopyUsername = async () => {
    if (!selectedCredential) return;
    await credentialRepository.updateAccessTime(selectedCredential.id);
    const success = await clipboardManager.copy(selectedCredential.username, false, 0);
    if (success) {
      showSnackbar(`Username copied: ${selectedCredential.username}`);
    } else {
      showSnackbar('Failed to copy username');
    }
  };

  const handleCopyPassword = async () => {
    if (!selectedCredential) return;
    await credentialRepository.updateAccessTime(selectedCredential.id);
    const success = await clipboardManager.copy(selectedCredential.password, true, 30);
    if (success) {
      showSnackbar('Password copied! Auto-clearing in 30 seconds');
    } else {
      showSnackbar('Failed to copy password');
    }
  };

  const handleDetailsEdit = () => {
    if (selectedCredential) {
      setDetailsDialogOpen(false);
      handleEdit(selectedCredential.id);
    }
  };

  const handleDetailsDelete = () => {
    if (selectedCredential) {
      setDetailsDialogOpen(false);
      handleDeleteRequest(selectedCredential.id);
    }
  };

  const handleDetailsToggleFavorite = () => {
    if (selectedCredential) {
      handleToggleFavorite(selectedCredential.id);
      // Update selected credential
      setSelectedCredential({
        ...selectedCredential,
        isFavorite: !selectedCredential.isFavorite,
      });
    }
  };

  // Filter and sort credentials with useMemo for performance
  const filteredAndSortedCredentials = useMemo(() => {
    let filtered = [...credentials];

    // Apply search filter
    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      filtered = filtered.filter(
        (credential) =>
          credential.title.toLowerCase().includes(query) ||
          credential.username.toLowerCase().includes(query) ||
          credential.url?.toLowerCase().includes(query) ||
          credential.tags.some((tag) => tag.toLowerCase().includes(query))
      );
    }

    // Apply category filter
    if (selectedCategory !== 'all') {
      filtered = filtered.filter((credential) => credential.category === selectedCategory);
    }

    // Apply favorites filter
    if (favoritesOnly) {
      filtered = filtered.filter((credential) => credential.isFavorite);
    }

    // Apply tag filter
    if (selectedTags.length > 0) {
      filtered = filtered.filter((credential) =>
        selectedTags.every((tag) => credential.tags.includes(tag))
      );
    }

    // Apply sorting
    switch (sortBy) {
      case 'title-asc':
        filtered.sort((a, b) => a.title.localeCompare(b.title));
        break;
      case 'title-desc':
        filtered.sort((a, b) => b.title.localeCompare(a.title));
        break;
      case 'updated-desc':
        filtered.sort((a, b) => b.updatedAt.getTime() - a.updatedAt.getTime());
        break;
      case 'created-desc':
        filtered.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());
        break;
      case 'favorites-first':
        filtered.sort((a, b) => {
          if (a.isFavorite === b.isFavorite) {
            return b.updatedAt.getTime() - a.updatedAt.getTime();
          }
          return a.isFavorite ? -1 : 1;
        });
        break;
    }

    return filtered;
  }, [credentials, searchQuery, selectedCategory, favoritesOnly, selectedTags, sortBy]);

  // Separate credentials into sections
  const favoriteCredentials = useMemo(() => {
    return credentials
      .filter((c) => c.isFavorite)
      .sort((a, b) => b.updatedAt.getTime() - a.updatedAt.getTime())
      .slice(0, 6); // Show max 6 favorites
  }, [credentials]);

  const recentlyUsedCredentials = useMemo(() => {
    return credentials
      .filter((c) => c.lastAccessedAt)
      .sort((a, b) => {
        const timeA = a.lastAccessedAt?.getTime() || 0;
        const timeB = b.lastAccessedAt?.getTime() || 0;
        return timeB - timeA;
      })
      .slice(0, 6); // Show max 6 recently used
  }, [credentials]);

  // Get all unique tags from credentials
  const allTags = useMemo(() => {
    const tagSet = new Set<string>();
    credentials.forEach((credential) => {
      credential.tags.forEach((tag) => tagSet.add(tag));
    });
    return Array.from(tagSet).sort();
  }, [credentials]);

  // Calculate stats
  const totalCredentials = credentials.length;
  const strongPasswords = credentials.filter((c) => (c.securityScore || 0) >= 80).length;
  const weakPasswords = credentials.filter((c) => (c.securityScore || 0) < 60).length;
  const averageScore = totalCredentials > 0
    ? Math.round(credentials.reduce((sum, c) => sum + (c.securityScore || 0), 0) / totalCredentials)
    : 0;

  return (
    <Box sx={{ display: 'flex', minHeight: '100vh' }}>
      {/* App Bar */}
      <AppBar position="fixed" sx={{ zIndex: (theme) => theme.zIndex.drawer + 1 }}>
        <Toolbar>
          <IconButton
            color="inherit"
            edge="start"
            onClick={() => { setDrawerOpen(!drawerOpen); }}
            sx={{ mr: 2 }}
          >
            <MenuIcon />
          </IconButton>
          <Typography variant="h6" component="div" sx={{ flexGrow: 1 }} data-tour="dashboard">
            TrustVault
          </Typography>
          <TourHelpButton />
          <ThemeToggle />
          <IconButton color="inherit" onClick={handleLockVault}>
            <LockIcon />
          </IconButton>
          <IconButton color="inherit" onClick={(e) => { setMenuAnchor(e.currentTarget); }}>
            <Avatar sx={{ width: 32, height: 32, bgcolor: 'primary.main' }}>
              {user?.email?.[0]?.toUpperCase() || 'U'}
            </Avatar>
          </IconButton>
          <Menu
            anchorEl={menuAnchor}
            open={Boolean(menuAnchor)}
            onClose={() => { setMenuAnchor(null); }}
          >
            <MenuItem
              onClick={() => {
                setMenuAnchor(null);
                navigate('/settings');
              }}
            >
              <ListItemIcon>
                <SettingsIcon />
              </ListItemIcon>
              Settings
            </MenuItem>
            <MenuItem onClick={handleLogout}>
              <ListItemIcon>
                <LogoutIcon />
              </ListItemIcon>
              Logout
            </MenuItem>
          </Menu>
        </Toolbar>
      </AppBar>

      {/* Drawer */}
      <Drawer
        variant="temporary"
        open={drawerOpen}
        onClose={() => { setDrawerOpen(false); }}
        sx={{
          width: 240,
          flexShrink: 0,
          '& .MuiDrawer-paper': {
            width: 240,
            boxSizing: 'border-box',
          },
        }}
      >
        <Toolbar />
        <Box sx={{ overflow: 'auto' }}>
          <List>
            <ListItemButton selected>
              <ListItemIcon>
                <DashboardIcon />
              </ListItemIcon>
              <ListItemText primary="All Credentials" />
            </ListItemButton>
            <ListItemButton onClick={() => navigate('/favorites')}>
              <ListItemIcon>
                <FavoriteIcon />
              </ListItemIcon>
              <ListItemText primary="Favorites" />
            </ListItemButton>
            <ListItemButton onClick={() => navigate('/password-generator')}>
              <ListItemIcon>
                <VpnKeyIcon />
              </ListItemIcon>
              <ListItemText primary="Password Generator" />
            </ListItemButton>
            <ListItemButton onClick={() => navigate('/security-audit')} data-tour="security-audit">
              <ListItemIcon>
                <SecurityIcon />
              </ListItemIcon>
              <ListItemText primary="Security Audit" />
            </ListItemButton>
            <ListItemButton onClick={() => navigate('/settings')} data-tour="settings">
              <ListItemIcon>
                <SettingsIcon />
              </ListItemIcon>
              <ListItemText primary="Settings" />
            </ListItemButton>
          </List>
        </Box>
      </Drawer>

      {/* Main Content */}
      <Box
        component="main"
        sx={{
          flexGrow: 1,
          p: 3,
          mt: 8,
          bgcolor: 'background.default',
        }}
      >
        {/* Breach Alert Banner */}
        <BreachAlertBanner />

        {/* Search Bar */}
        <Box sx={{ mb: 3 }} data-tour="search">
          <SearchBar
            value={searchQuery}
            onChange={setSearchQuery}
            placeholder="Search credentials..."
            debounceMs={300}
          />
        </Box>

        {/* Filter Chips */}
        <Box sx={{ mb: 3 }}>
          <FilterChips
            selectedCategory={selectedCategory}
            onCategoryChange={setSelectedCategory}
            favoritesOnly={favoritesOnly}
            onFavoritesToggle={() => { setFavoritesOnly(!favoritesOnly); }}
            selectedTags={selectedTags}
            onTagsChange={setSelectedTags}
            availableTags={allTags}
          />
        </Box>

        {/* Stats */}
        <Grid container spacing={3} sx={{ mb: 4 }}>
          <Grid size={{ xs: 12, sm: 6, md: 3 }}>
            <Card>
              <CardContent>
                <Typography color="text.secondary" gutterBottom>
                  Total Credentials
                </Typography>
                <Typography variant="h4">{totalCredentials}</Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid size={{ xs: 12, sm: 6, md: 3 }}>
            <Card>
              <CardContent>
                <Typography color="text.secondary" gutterBottom>
                  Strong Passwords
                </Typography>
                <Typography variant="h4" color="success.main">
                  {strongPasswords}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid size={{ xs: 12, sm: 6, md: 3 }}>
            <Card>
              <CardContent>
                <Typography color="text.secondary" gutterBottom>
                  Weak Passwords
                </Typography>
                <Typography variant="h4" color="warning.main">
                  {weakPasswords}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid size={{ xs: 12, sm: 6, md: 3 }}>
            <Card>
              <CardContent>
                <Typography color="text.secondary" gutterBottom>
                  Security Score
                </Typography>
                <Typography variant="h4" color={averageScore >= 70 ? 'success.main' : 'warning.main'}>
                  {averageScore}/100
                </Typography>
              </CardContent>
            </Card>
          </Grid>
        </Grid>

        {/* Credentials List Header with Sort */}
        <Box sx={{ mb: 3, display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 2 }}>
          <Typography variant="h5">
            {searchQuery || selectedCategory !== 'all' || favoritesOnly
              ? `Found ${filteredAndSortedCredentials.length} credential${
                  filteredAndSortedCredentials.length !== 1 ? 's' : ''
                }`
              : 'Your Credentials'}
          </Typography>
          <SortDropdown value={sortBy} onChange={setSortBy} />
        </Box>

        {/* Loading State */}
        {loading && (
          <Box sx={{ display: 'flex', justifyContent: 'center', py: 8 }}>
            <CircularProgress />
          </Box>
        )}

        {/* Error State */}
        {error && !loading && (
          <Alert severity="error" sx={{ mb: 3 }}>
            {error}
            <Button size="small" onClick={loadCredentials} sx={{ ml: 2 }}>
              Retry
            </Button>
          </Alert>
        )}

        {/* Empty State */}
        {!loading && !error && credentials.length === 0 && (
          <Card>
            <CardContent sx={{ textAlign: 'center', py: 8 }}>
              <LockIcon sx={{ fontSize: 64, color: 'text.secondary', mb: 2 }} />
              <Typography variant="h6" gutterBottom>
                No credentials yet
              </Typography>
              <Typography color="text.secondary" sx={{ mb: 3 }}>
                Start securing your passwords by adding your first credential
              </Typography>
              <Button
                variant="contained"
                startIcon={<AddIcon />}
                onClick={() => navigate('/credentials/add')}
                data-tour="add-credential"
              >
                Add Credential
              </Button>
            </CardContent>
          </Card>
        )}

        {/* No Search Results */}
        {!loading && !error && credentials.length > 0 && filteredAndSortedCredentials.length === 0 && (
          <Card>
            <CardContent sx={{ textAlign: 'center', py: 8 }}>
              <Typography variant="h6" gutterBottom>
                No credentials found
              </Typography>
              <Typography color="text.secondary" sx={{ mb: 2 }}>
                Try adjusting your search or filters
              </Typography>
              <Button
                variant="outlined"
                onClick={() => {
                  setSearchQuery('');
                  setSelectedCategory('all');
                  setFavoritesOnly(false);
                  setSelectedTags([]);
                }}
              >
                Clear All Filters
              </Button>
            </CardContent>
          </Card>
        )}

        {/* Favorites Section - Show when no filters active */}
        {!loading && !error && credentials.length > 0 && favoriteCredentials.length > 0 && 
         !searchQuery && selectedCategory === 'all' && !favoritesOnly && selectedTags.length === 0 && (
          <Box sx={{ mb: 4 }}>
            <CredentialSection
              title="Favorites"
              subtitle="Your starred credentials"
              icon={<StarIcon />}
              credentials={favoriteCredentials}
              onEdit={handleEdit}
              onDelete={handleDeleteRequest}
              onToggleFavorite={handleToggleFavorite}
              onCopySuccess={showSnackbar}
            />
          </Box>
        )}

        {/* Recently Used Section - Show when no filters active */}
        {!loading && !error && credentials.length > 0 && recentlyUsedCredentials.length > 0 && 
         !searchQuery && selectedCategory === 'all' && !favoritesOnly && selectedTags.length === 0 && (
          <Box sx={{ mb: 4 }}>
            <CredentialSection
              title="Recently Used"
              subtitle="Your most recently accessed credentials"
              icon={<AccessTime />}
              credentials={recentlyUsedCredentials}
              onEdit={handleEdit}
              onDelete={handleDeleteRequest}
              onToggleFavorite={handleToggleFavorite}
              onCopySuccess={showSnackbar}
            />
          </Box>
        )}

        {/* Credentials Grid - Desktop & Tablet */}
        {!loading && !error && filteredAndSortedCredentials.length > 0 && !isMobile && (
          <Grid container spacing={2}>
            {filteredAndSortedCredentials.map((credential) => (
              <Grid size={{ xs: 12, sm: 6, md: 4 }} key={credential.id}>
                <CredentialCard
                  credential={credential}
                  onEdit={handleEdit}
                  onDelete={handleDeleteRequest}
                  onToggleFavorite={handleToggleFavorite}
                  onCopySuccess={showSnackbar}
                />
              </Grid>
            ))}
          </Grid>
        )}

        {/* Credentials List - Mobile with Swipe */}
        {!loading && !error && filteredAndSortedCredentials.length > 0 && isMobile && (
          <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
            {filteredAndSortedCredentials.map((credential) => (
              <SwipeableCredentialCard
                key={credential.id}
                credential={credential}
                onEdit={handleEdit}
                onDelete={handleDeleteRequest}
                onToggleFavorite={handleToggleFavorite}
                onTap={handleCredentialTap}
              />
            ))}
          </Box>
        )}
      </Box>

      {/* FAB - Position adjusted for mobile */}
      <Fab
        color="primary"
        aria-label="add"
        onClick={() => navigate('/credentials/add')}
        data-tour="add-credential"
        sx={{
          position: 'fixed',
          bottom: { xs: 80, md: 24 }, // Higher on mobile to avoid bottom nav
          right: 24,
        }}
      >
        <AddIcon />
      </Fab>

      {/* Mobile Credential Details Dialog */}
      <CredentialDetailsDialog
        open={detailsDialogOpen}
        credential={selectedCredential}
        onClose={() => {
          setDetailsDialogOpen(false);
          setSelectedCredential(null);
        }}
        onCopyUsername={handleCopyUsername}
        onCopyPassword={handleCopyPassword}
        onEdit={handleDetailsEdit}
        onDelete={handleDetailsDelete}
        onToggleFavorite={handleDetailsToggleFavorite}
      />

      {/* Delete Confirmation Dialog */}
      <DeleteConfirmDialog
        open={deleteDialogOpen}
        credentialTitle={getCredentialToDelete()?.title || 'this credential'}
        onCancel={() => {
          setDeleteDialogOpen(false);
          setCredentialToDelete(null);
        }}
        onConfirm={handleDeleteConfirm}
        loading={deleting}
      />

      {/* Snackbar for notifications */}
      <Snackbar
        open={snackbarOpen}
        autoHideDuration={4000}
        onClose={() => { setSnackbarOpen(false); }}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
      >
        <Alert
          onClose={() => { setSnackbarOpen(false); }}
          severity="success"
          variant="filled"
          sx={{ width: '100%' }}
        >
          {snackbarMessage}
        </Alert>
      </Snackbar>
    </Box>
  );
}

/**
 * Edit Credential Page
 * Form to edit an existing credential entry
 */

import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Paper,
  MenuItem,
  IconButton,
  InputAdornment,
  FormControlLabel,
  Checkbox,
  Alert,
  CircularProgress,
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  ArrowBack,
  Save,
  Delete,
  AutoAwesome,
  CameraAlt,
} from '@mui/icons-material';
import { credentialRepository } from '@/data/repositories/CredentialRepositoryImpl';
import { useAuthStore } from '@/presentation/store/authStore';
import PasswordStrengthIndicator from '@/presentation/components/PasswordStrengthIndicator';
import DeleteConfirmDialog from '@/presentation/components/DeleteConfirmDialog';
import PasswordGeneratorDialog from '@/presentation/components/PasswordGeneratorDialog';
import TotpDisplay from '@/presentation/components/TotpDisplay';
import TagInput from '@/presentation/components/TagInput';
import { isValidTOTPSecret } from '@/core/auth/totp';
import type { CredentialCategory, Credential } from '@/domain/entities/Credential';
import {
  storeCredentialInBrowser,
  toBrowserCredential,
  isCredentialManagementSupported,
} from '@/core/autofill/credentialManagementService';
import { CameraScanDialog } from '@/presentation/components/CameraScanDialog';
import { OcrResultDialog } from '@/presentation/components/OcrResultDialog';
import { isCameraSupported, type ParsedCredential } from '@/core/ocr';

const CATEGORIES: { value: CredentialCategory; label: string }[] = [
  { value: 'login', label: 'Login' },
  { value: 'credit_card', label: 'Credit Card' },
  { value: 'bank_account', label: 'Bank Account' },
  { value: 'secure_note', label: 'Secure Note' },
  { value: 'identity', label: 'Identity' },
  { value: 'api_key', label: 'API Key' },
  { value: 'ssh_key', label: 'SSH Key' },
];

export default function EditCredentialPage() {
  const navigate = useNavigate();
  const { id } = useParams<{ id: string }>();
  const { vaultKey } = useAuthStore();

  // Loading state
  const [loadingCredential, setLoadingCredential] = useState(true);
  const [credential, setCredential] = useState<Credential | null>(null);

  // Form state
  const [title, setTitle] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [url, setUrl] = useState('');
  const [notes, setNotes] = useState('');
  const [category, setCategory] = useState<CredentialCategory>('login');
  const [tags, setTags] = useState<string[]>([]);
  const [isFavorite, setIsFavorite] = useState(false);
  const [totpSecret, setTotpSecret] = useState('');

  // Card-specific state
  const [cardNumber, setCardNumber] = useState('');
  const [cardholderName, setCardholderName] = useState('');
  const [expiryMonth, setExpiryMonth] = useState('');
  const [expiryYear, setExpiryYear] = useState('');
  const [cvv, setCvv] = useState('');
  const [cardType, setCardType] = useState<'visa' | 'mastercard' | 'amex' | 'discover' | 'other'>('visa');
  const [billingAddress, setBillingAddress] = useState('');

  // UI state
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [generatorOpen, setGeneratorOpen] = useState(false);

  // OCR scan state
  const [scanDialogOpen, setScanDialogOpen] = useState(false);
  const [ocrResultDialogOpen, setOcrResultDialogOpen] = useState(false);
  const [ocrResult, setOcrResult] = useState<ParsedCredential | null>(null);

  // Validation
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Load credential on mount
  useEffect(() => {
    const loadCredential = async () => {
      if (!id || !vaultKey) {
        setError('Invalid credential or session expired');
        setLoadingCredential(false);
        return;
      }

      try {
        const cred = await credentialRepository.findById(id, vaultKey);
        if (!cred) {
          setError('Credential not found');
          setLoadingCredential(false);
          return;
        }

        // Pre-fill form
        setCredential(cred);
        setTitle(cred.title);
        setUsername(cred.username);
        setPassword(cred.password);
        setUrl(cred.url || '');
        setNotes(cred.notes || '');
        setCategory(cred.category);
        setTags(cred.tags || []);
        setIsFavorite(cred.isFavorite);
        setTotpSecret(cred.totpSecret || '');

        // Pre-fill card fields if credit card
        if (cred.category === 'credit_card') {
          setCardNumber(cred.cardNumber || '');
          setCardholderName(cred.cardholderName || '');
          setExpiryMonth(cred.expiryMonth || '');
          setExpiryYear(cred.expiryYear || '');
          setCvv(cred.cvv || '');
          setCardType(cred.cardType || 'visa');
          setBillingAddress(cred.billingAddress || '');
        }

        setLoadingCredential(false);
      } catch (err) {
        console.error('Failed to load credential:', err);
        setError(err instanceof Error ? err.message : 'Failed to load credential');
        setLoadingCredential(false);
      }
    };

    loadCredential();
  }, [id, vaultKey]);

  const validateForm = (): boolean => {
    const newErrors: Record<string, string> = {};

    if (!title.trim()) {
      newErrors.title = 'Title is required';
    }

    // For credit cards, validate card-specific fields instead of username/password
    if (category === 'credit_card') {
      if (!cardNumber.trim()) {
        newErrors.cardNumber = 'Card number is required';
      } else if (!/^\d{13,19}$/.test(cardNumber.replace(/\s/g, ''))) {
        newErrors.cardNumber = 'Invalid card number format';
      }

      if (!cardholderName.trim()) {
        newErrors.cardholderName = 'Cardholder name is required';
      }

      if (!expiryMonth || !expiryYear) {
        newErrors.expiry = 'Expiration date is required';
      }

      if (!cvv.trim()) {
        newErrors.cvv = 'CVV is required';
      } else if (!/^\d{3,4}$/.test(cvv)) {
        newErrors.cvv = 'Invalid CVV format';
      }
    } else {
      // Standard validation for non-card credentials
      if (!username.trim()) {
        newErrors.username = 'Username is required';
      }

      if (!password) {
        newErrors.password = 'Password is required';
      } else if (password.length < 4) {
        newErrors.password = 'Password must be at least 4 characters';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleGeneratePassword = () => {
    setGeneratorOpen(true);
  };

  const handleUseGeneratedPassword = (generatedPassword: string) => {
    setPassword(generatedPassword);
  };

  // OCR scan handlers
  const handleOpenScan = () => {
    setScanDialogOpen(true);
  };

  const handleScanResult = (result: ParsedCredential) => {
    setOcrResult(result);
    setScanDialogOpen(false);
    setOcrResultDialogOpen(true);
  };

  const handleApplyOcrResult = (fields: {
    username?: string;
    password?: string;
    url?: string;
    notes?: string;
  }) => {
    if (fields.username) setUsername(fields.username);
    if (fields.password) setPassword(fields.password);
    if (fields.url) setUrl(fields.url);
    if (fields.notes) setNotes(fields.notes);
    setOcrResultDialogOpen(false);
  };

  const handleRescan = () => {
    setOcrResultDialogOpen(false);
    setScanDialogOpen(true);
  };

  const handleSave = async () => {
    if (!validateForm()) {
      return;
    }

    if (!vaultKey || !id) {
      setError('Session expired. Please sign in again.');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const updateData: any = {
        title: title.trim(),
        category,
        tags,
        isFavorite,
        url: url.trim() || undefined,
        notes: notes.trim() || undefined,
      };

      // Add card-specific fields for credit cards
      if (category === 'credit_card') {
        updateData.username = cardholderName.trim();
        updateData.password = 'N/A';
        updateData.cardNumber = cardNumber.replace(/\s/g, '');
        updateData.cardholderName = cardholderName.trim();
        updateData.expiryMonth = expiryMonth;
        updateData.expiryYear = expiryYear;
        updateData.cvv = cvv;
        updateData.cardType = cardType;
        updateData.billingAddress = billingAddress.trim() || undefined;
      } else {
        // Standard credential fields
        updateData.username = username.trim();
        updateData.password = password;
        updateData.totpSecret = totpSecret.trim() || undefined;
      }

      const updatedCredential = await credentialRepository.update(id, updateData, vaultKey);

      // Store credential in browser for autofill (if supported and applicable)
      if (
        updatedCredential.category === 'login' &&
        updatedCredential.url &&
        isCredentialManagementSupported()
      ) {
        try {
          const browserCred = toBrowserCredential(updatedCredential);
          if (browserCred) {
            await storeCredentialInBrowser(browserCred);
          }
        } catch (err) {
          // Non-critical: autofill storage failed, but credential was updated
          console.warn('Failed to store credential in browser for autofill:', err);
        }
      }

      // Navigate back to dashboard
      navigate('/dashboard');
    } catch (err) {
      console.error('Failed to update credential:', err);
      setError(err instanceof Error ? err.message : 'Failed to update credential');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!id) {
      setError('Invalid credential ID');
      return;
    }

    setDeleting(true);
    setError(null);

    try {
      await credentialRepository.delete(id);
      navigate('/dashboard');
    } catch (err) {
      console.error('Failed to delete credential:', err);
      setError(err instanceof Error ? err.message : 'Failed to delete credential');
      setDeleting(false);
      setDeleteDialogOpen(false);
    }
  };

  // Loading state
  if (loadingCredential) {
    return (
      <Container maxWidth="md" sx={{ py: 4, display: 'flex', justifyContent: 'center' }}>
        <CircularProgress />
      </Container>
    );
  }

  // Error state
  if (!credential) {
    return (
      <Container maxWidth="md" sx={{ py: 4 }}>
        <Paper sx={{ p: 3 }}>
          <Alert severity="error">{error || 'Credential not found'}</Alert>
          <Button
            variant="outlined"
            onClick={() => navigate('/dashboard')}
            sx={{ mt: 2 }}
          >
            Back to Dashboard
          </Button>
        </Paper>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" sx={{ py: 4 }}>
      <Paper sx={{ p: 3 }}>
        {/* Header */}
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
          <IconButton onClick={() => navigate('/dashboard')} sx={{ mr: 2 }}>
            <ArrowBack />
          </IconButton>
          <Typography variant="h5" component="h1" sx={{ fontWeight: 600, flexGrow: 1 }}>
            Edit Credential
          </Typography>
          {isCameraSupported() && (
            <Button
              variant="outlined"
              startIcon={<CameraAlt />}
              onClick={handleOpenScan}
              size="small"
              sx={{ mr: 1 }}
            >
              Scan
            </Button>
          )}
          <Button
            variant="outlined"
            color="error"
            startIcon={<Delete />}
            onClick={() => { setDeleteDialogOpen(true); }}
            disabled={loading || deleting}
          >
            Delete
          </Button>
        </Box>

        {/* Error Alert */}
        {error && (
          <Alert severity="error" sx={{ mb: 3 }} onClose={() => { setError(null); }}>
            {error}
          </Alert>
        )}

        {/* Form */}
        <Box component="form" noValidate>
          {/* Title */}
          <TextField
            fullWidth
            label="Title"
            value={title}
            onChange={(e) => { setTitle(e.target.value); }}
            error={!!errors.title}
            helperText={errors.title}
            margin="normal"
            required
            placeholder="e.g., Gmail Account, Work VPN"
          />

          {/* Category */}
          <TextField
            fullWidth
            select
            label="Category"
            value={category}
            onChange={(e) => { setCategory(e.target.value as CredentialCategory); }}
            margin="normal"
          >
            {CATEGORIES.map((cat) => (
              <MenuItem key={cat.value} value={cat.value}>
                {cat.label}
              </MenuItem>
            ))}
          </TextField>

          {/* Conditional Fields based on Category */}
          {category === 'credit_card' ? (
            <>
              {/* Card Number */}
              <TextField
                fullWidth
                label="Card Number"
                value={cardNumber}
                onChange={(e) => { setCardNumber(e.target.value); }}
                error={!!errors.cardNumber}
                helperText={errors.cardNumber}
                margin="normal"
                required
                placeholder="1234 5678 9012 3456"
                inputProps={{ maxLength: 19 }}
              />

              {/* Cardholder Name */}
              <TextField
                fullWidth
                label="Cardholder Name"
                value={cardholderName}
                onChange={(e) => { setCardholderName(e.target.value); }}
                error={!!errors.cardholderName}
                helperText={errors.cardholderName}
                margin="normal"
                required
                placeholder="JOHN DOE"
              />

              {/* Card Type */}
              <TextField
                fullWidth
                select
                label="Card Type"
                value={cardType}
                onChange={(e) => { setCardType(e.target.value as typeof cardType); }}
                margin="normal"
              >
                <MenuItem value="visa">Visa</MenuItem>
                <MenuItem value="mastercard">Mastercard</MenuItem>
                <MenuItem value="amex">American Express</MenuItem>
                <MenuItem value="discover">Discover</MenuItem>
                <MenuItem value="other">Other</MenuItem>
              </TextField>

              {/* Expiry Date */}
              <Box sx={{ display: 'flex', gap: 2, mt: 2 }}>
                <TextField
                  select
                  label="Expiry Month"
                  value={expiryMonth}
                  onChange={(e) => { setExpiryMonth(e.target.value); }}
                  error={!!errors.expiry}
                  required
                  sx={{ flex: 1 }}
                >
                  {Array.from({ length: 12 }, (_, i) => {
                    const month = String(i + 1).padStart(2, '0');
                    return (
                      <MenuItem key={month} value={month}>
                        {month}
                      </MenuItem>
                    );
                  })}
                </TextField>

                <TextField
                  select
                  label="Expiry Year"
                  value={expiryYear}
                  onChange={(e) => { setExpiryYear(e.target.value); }}
                  error={!!errors.expiry}
                  required
                  sx={{ flex: 1 }}
                >
                  {Array.from({ length: 15 }, (_, i) => {
                    const year = String(new Date().getFullYear() + i);
                    return (
                      <MenuItem key={year} value={year}>
                        {year}
                      </MenuItem>
                    );
                  })}
                </TextField>
              </Box>
              {errors.expiry && (
                <Typography color="error" variant="caption" sx={{ mt: 1, ml: 2 }}>
                  {errors.expiry}
                </Typography>
              )}

              {/* CVV */}
              <TextField
                fullWidth
                label="CVV / Security Code"
                type={showPassword ? 'text' : 'password'}
                value={cvv}
                onChange={(e) => { setCvv(e.target.value); }}
                error={!!errors.cvv}
                helperText={errors.cvv}
                margin="normal"
                required
                placeholder="123"
                inputProps={{ maxLength: 4 }}
                InputProps={{
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={() => { setShowPassword(!showPassword); }}
                        edge="end"
                        title={showPassword ? 'Hide CVV' : 'Show CVV'}
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />

              {/* Billing Address */}
              <TextField
                fullWidth
                label="Billing Address (Optional)"
                value={billingAddress}
                onChange={(e) => { setBillingAddress(e.target.value); }}
                margin="normal"
                multiline
                rows={2}
                placeholder="123 Main St, City, State ZIP"
              />
            </>
          ) : (
            <>
              {/* Username */}
              <TextField
                fullWidth
                label="Username / Email"
                value={username}
                onChange={(e) => { setUsername(e.target.value); }}
                error={!!errors.username}
                helperText={errors.username}
                margin="normal"
                required
                placeholder="user@example.com"
              />

              {/* Password */}
              <TextField
                fullWidth
                label="Password"
                type={showPassword ? 'text' : 'password'}
                value={password}
                onChange={(e) => { setPassword(e.target.value); }}
                error={!!errors.password}
                helperText={errors.password}
                margin="normal"
                required
                InputProps={{
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={handleGeneratePassword}
                        edge="end"
                        title="Generate password"
                        sx={{ mr: 1 }}
                      >
                        <AutoAwesome />
                      </IconButton>
                      <IconButton
                        onClick={() => { setShowPassword(!showPassword); }}
                        edge="end"
                        title={showPassword ? 'Hide password' : 'Show password'}
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />

              {/* Password Strength Indicator */}
              <PasswordStrengthIndicator password={password} showFeedback />

              {/* TOTP Secret (2FA) */}
              <TextField
                fullWidth
                label="TOTP Secret (Optional)"
                value={totpSecret}
                onChange={(e) => { setTotpSecret(e.target.value); }}
                margin="normal"
                placeholder="Base32-encoded secret (e.g., from Google Authenticator)"
                helperText="Enter the base32-encoded secret key for 2FA/TOTP authentication"
              />

              {/* TOTP Preview */}
              {totpSecret.trim() && isValidTOTPSecret(totpSecret.trim()) && (
                <Box sx={{ mt: 2 }}>
                  <TotpDisplay totpSecret={totpSecret.trim()} />
                </Box>
              )}

              {totpSecret.trim() && !isValidTOTPSecret(totpSecret.trim()) && (
                <Alert severity="warning" sx={{ mt: 2 }}>
                  Invalid TOTP secret format. Please enter a valid base32-encoded secret.
                </Alert>
              )}
            </>
          )}

          {/* URL */}
          <TextField
            fullWidth
            label="Website URL"
            value={url}
            onChange={(e) => { setUrl(e.target.value); }}
            margin="normal"
            placeholder="https://example.com"
            type="url"
          />

          {/* Tags */}
          <Box sx={{ mt: 2, mb: 1 }}>
            <TagInput tags={tags} onChange={setTags} />
          </Box>

          {/* Notes */}
          <TextField
            fullWidth
            label="Notes"
            value={notes}
            onChange={(e) => { setNotes(e.target.value); }}
            margin="normal"
            multiline
            rows={4}
            placeholder="Additional information..."
          />

          {/* Favorite Checkbox */}
          <FormControlLabel
            control={
              <Checkbox
                checked={isFavorite}
                onChange={(e) => { setIsFavorite(e.target.checked); }}
              />
            }
            label="Add to favorites"
            sx={{ mt: 2 }}
          />

          {/* Action Buttons */}
          <Box sx={{ display: 'flex', gap: 2, mt: 4 }}>
            <Button
              variant="outlined"
              onClick={() => navigate('/dashboard')}
              disabled={loading || deleting}
              fullWidth
            >
              Cancel
            </Button>
            <Button
              variant="contained"
              onClick={handleSave}
              disabled={loading || deleting}
              startIcon={<Save />}
              fullWidth
            >
              {loading ? 'Saving...' : 'Save Changes'}
            </Button>
          </Box>
        </Box>
      </Paper>

      {/* Delete Confirmation Dialog */}
      <DeleteConfirmDialog
        open={deleteDialogOpen}
        credentialTitle={credential.title}
        onCancel={() => { setDeleteDialogOpen(false); }}
        onConfirm={handleDelete}
        loading={deleting}
      />

      {/* Password Generator Dialog */}
      <PasswordGeneratorDialog
        open={generatorOpen}
        onClose={() => { setGeneratorOpen(false); }}
        onUse={handleUseGeneratedPassword}
      />

      {/* Camera Scan Dialog */}
      <CameraScanDialog
        open={scanDialogOpen}
        onClose={() => { setScanDialogOpen(false); }}
        onResult={handleScanResult}
      />

      {/* OCR Result Dialog */}
      <OcrResultDialog
        open={ocrResultDialogOpen}
        result={ocrResult}
        onClose={() => { setOcrResultDialogOpen(false); }}
        onApply={handleApplyOcrResult}
        onRescan={handleRescan}
      />
    </Container>
  );
}

/**
 * Favorites Page
 * Shows only favorite/starred credentials for quick access
 */

import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Box,
  Container,
  Typography,
  AppBar,
  Toolbar,
  IconButton,
  TextField,
  InputAdornment,
  Grid,
  Card,
  CardContent,
  CardActions,
  Button,
  Chip,
  CircularProgress,
  Alert,
  AlertTitle,
  Tooltip,
} from '@mui/material';
import {
  ArrowBack,
  Search,
  Star,
  ContentCopy,
  Edit,
  Visibility,
  VisibilityOff,
  OpenInNew,
} from '@mui/icons-material';
import { Credential } from '@/domain/entities/Credential';
import { useAuthStore } from '../store/authStore';
import { credentialRepository } from '@/data/repositories/CredentialRepositoryImpl';
import { copyToClipboard } from '../utils/clipboard';

export default function FavoritesPage() {
  const navigate = useNavigate();
  const { vaultKey } = useAuthStore();

  const [credentials, setCredentials] = useState<Credential[]>([]);
  const [filteredCredentials, setFilteredCredentials] = useState<Credential[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [visiblePasswords, setVisiblePasswords] = useState<Set<string>>(new Set());
  const [snackbarMessage, setSnackbarMessage] = useState('');

  // Load favorite credentials function
  const loadFavorites = useCallback(async () => {
    if (!vaultKey) {
      setError('No vault key available');
      setLoading(false);
      return;
    }

    try {
      setLoading(true);
      setError(null);

      const allCredentials = await credentialRepository.findAll(vaultKey);

      // Filter only favorites
      const favorites = allCredentials.filter((cred) => cred.isFavorite);

      // Sort by recently updated first
      favorites.sort((a, b) => {
        const dateA = new Date(a.updatedAt).getTime();
        const dateB = new Date(b.updatedAt).getTime();
        return dateB - dateA;
      });

      setCredentials(favorites);
      setFilteredCredentials(favorites);
    } catch (err) {
      console.error('Failed to load favorites:', err);
      setError('Failed to load favorite credentials');
    } finally {
      setLoading(false);
    }
  }, [vaultKey]);

  // Load favorite credentials on mount and when vaultKey changes
  useEffect(() => {
    loadFavorites();
  }, [loadFavorites]);

  // Filter credentials based on search
  useEffect(() => {
    if (!searchQuery.trim()) {
      setFilteredCredentials(credentials);
      return;
    }

    const query = searchQuery.toLowerCase();
    const filtered = credentials.filter(
      (cred) =>
        cred.title.toLowerCase().includes(query) ||
        cred.username?.toLowerCase().includes(query) ||
        cred.url?.toLowerCase().includes(query) ||
        cred.tags?.some((tag) => tag.toLowerCase().includes(query))
    );
    setFilteredCredentials(filtered);
  }, [searchQuery, credentials]);

  const handleCopyUsername = async (credential: Credential) => {
    if (!credential.username) return;
    await copyToClipboard(credential.username, 0); // No auto-clear for usernames
    showSnackbar(`Username copied: ${credential.username}`);
  };

  const handleCopyPassword = async (credential: Credential) => {
    if (!credential.password) return;
    await copyToClipboard(credential.password, 30000); // 30 seconds in milliseconds
    showSnackbar('Password copied to clipboard (will clear in 30s)');
  };

  const togglePasswordVisibility = (credentialId: string) => {
    setVisiblePasswords((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(credentialId)) {
        newSet.delete(credentialId);
      } else {
        newSet.add(credentialId);
      }
      return newSet;
    });
  };

  const showSnackbar = (message: string) => {
    setSnackbarMessage(message);
    setTimeout(() => { setSnackbarMessage(''); }, 3000);
  };

  const handleOpenWebsite = (website: string) => {
    if (!website) return;

    // Ensure URL has protocol
    let url = website;
    if (!url.startsWith('http://') && !url.startsWith('https://')) {
      url = 'https://' + url;
    }

    window.open(url, '_blank', 'noopener,noreferrer');
  };

  const getCategoryColor = (category: string) => {
    switch (category) {
      case 'Login':
        return 'primary';
      case 'Payment':
        return 'success';
      case 'Identity':
        return 'info';
      case 'Note':
        return 'warning';
      case 'Secure Note':
        return 'error';
      default:
        return 'default';
    }
  };

  return (
    <Box sx={{ minHeight: '100vh', backgroundColor: 'background.default', pb: 4 }}>
      {/* App Bar */}
      <AppBar position="static" elevation={1}>
        <Toolbar>
          <IconButton edge="start" color="inherit" onClick={() => navigate('/dashboard')}>
            <ArrowBack />
          </IconButton>
          <Star sx={{ ml: 2, mr: 1 }} />
          <Typography variant="h6" sx={{ flexGrow: 1 }}>
            Favorites
          </Typography>
          <Chip
            label={`${filteredCredentials.length} items`}
            size="small"
            sx={{ backgroundColor: 'rgba(255,255,255,0.2)' }}
          />
        </Toolbar>
      </AppBar>

      <Container maxWidth="lg" sx={{ mt: 3 }}>
        {/* Search Bar */}
        <TextField
          fullWidth
          placeholder="Search favorites..."
          value={searchQuery}
          onChange={(e) => { setSearchQuery(e.target.value); }}
          sx={{ mb: 3 }}
          InputProps={{
            startAdornment: (
              <InputAdornment position="start">
                <Search />
              </InputAdornment>
            ),
          }}
        />

        {/* Loading State */}
        {loading && (
          <Box sx={{ display: 'flex', justifyContent: 'center', py: 8 }}>
            <CircularProgress />
          </Box>
        )}

        {/* Error State */}
        {error && (
          <Alert severity="error" sx={{ mb: 3 }}>
            <AlertTitle>Error</AlertTitle>
            {error}
          </Alert>
        )}

        {/* Empty State */}
        {!loading && !error && credentials.length === 0 && (
          <Box sx={{ textAlign: 'center', py: 8 }}>
            <Star sx={{ fontSize: 80, color: 'text.disabled', mb: 2 }} />
            <Typography variant="h5" gutterBottom color="text.secondary">
              No Favorites Yet
            </Typography>
            <Typography variant="body1" color="text.secondary" sx={{ mb: 3 }}>
              Star your most important credentials for quick access.
            </Typography>
            <Button variant="contained" onClick={() => navigate('/dashboard')}>
              Go to Dashboard
            </Button>
          </Box>
        )}

        {/* No Search Results */}
        {!loading && !error && credentials.length > 0 && filteredCredentials.length === 0 && (
          <Box sx={{ textAlign: 'center', py: 8 }}>
            <Search sx={{ fontSize: 80, color: 'text.disabled', mb: 2 }} />
            <Typography variant="h6" gutterBottom color="text.secondary">
              No favorites match "{searchQuery}"
            </Typography>
            <Button variant="outlined" onClick={() => { setSearchQuery(''); }}>
              Clear Search
            </Button>
          </Box>
        )}

        {/* Credentials Grid */}
        {!loading && !error && filteredCredentials.length > 0 && (
          <Grid container spacing={2}>
            {filteredCredentials.map((credential) => (
              <Grid item xs={12} sm={6} md={4} key={credential.id}>
                <Card
                  sx={{
                    height: '100%',
                    display: 'flex',
                    flexDirection: 'column',
                    transition: 'all 0.2s',
                    '&:hover': {
                      transform: 'translateY(-4px)',
                      boxShadow: 4,
                    },
                  }}
                >
                  <CardContent sx={{ flexGrow: 1 }}>
                    {/* Header */}
                    <Box sx={{ display: 'flex', alignItems: 'flex-start', mb: 2 }}>
                      <Box sx={{ flexGrow: 1 }}>
                        <Typography variant="h6" sx={{ mb: 0.5, wordBreak: 'break-word' }}>
                          {credential.title}
                        </Typography>
                        <Chip
                          label={credential.category}
                          size="small"
                          color={getCategoryColor(credential.category) as any}
                          sx={{ mb: 1 }}
                        />
                      </Box>
                      <Tooltip title="Favorite">
                        <Star sx={{ color: 'warning.main', ml: 1 }} />
                      </Tooltip>
                    </Box>

                    {/* Username */}
                    {credential.username && (
                      <Box sx={{ mb: 1 }}>
                        <Typography variant="caption" color="text.secondary">
                          Username
                        </Typography>
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                          <Typography variant="body2" sx={{ flexGrow: 1, wordBreak: 'break-all' }}>
                            {credential.username}
                          </Typography>
                          <Tooltip title="Copy username">
                            <IconButton
                              size="small"
                              onClick={() => handleCopyUsername(credential)}
                            >
                              <ContentCopy fontSize="small" />
                            </IconButton>
                          </Tooltip>
                        </Box>
                      </Box>
                    )}

                    {/* Password */}
                    {credential.password && (
                      <Box sx={{ mb: 1 }}>
                        <Typography variant="caption" color="text.secondary">
                          Password
                        </Typography>
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                          <Typography
                            variant="body2"
                            sx={{
                              flexGrow: 1,
                              fontFamily: 'monospace',
                              wordBreak: 'break-all',
                            }}
                          >
                            {visiblePasswords.has(credential.id)
                              ? credential.password
                              : '••••••••••••'}
                          </Typography>
                          <Tooltip title={visiblePasswords.has(credential.id) ? 'Hide' : 'Show'}>
                            <IconButton
                              size="small"
                              onClick={() => { togglePasswordVisibility(credential.id); }}
                            >
                              {visiblePasswords.has(credential.id) ? (
                                <VisibilityOff fontSize="small" />
                              ) : (
                                <Visibility fontSize="small" />
                              )}
                            </IconButton>
                          </Tooltip>
                          <Tooltip title="Copy password">
                            <IconButton
                              size="small"
                              onClick={() => handleCopyPassword(credential)}
                            >
                              <ContentCopy fontSize="small" />
                            </IconButton>
                          </Tooltip>
                        </Box>
                      </Box>
                    )}

                    {/* Website */}
                    {credential.url && (
                      <Box sx={{ mb: 1 }}>
                        <Typography variant="caption" color="text.secondary">
                          Website
                        </Typography>
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                          <Typography
                            variant="body2"
                            sx={{
                              flexGrow: 1,
                              wordBreak: 'break-all',
                              color: 'primary.main',
                              cursor: 'pointer',
                              textDecoration: 'underline',
                            }}
                            onClick={() => { handleOpenWebsite(credential.url!); }}
                          >
                            {credential.url}
                          </Typography>
                          <Tooltip title="Open website">
                            <IconButton
                              size="small"
                              onClick={() => { handleOpenWebsite(credential.url!); }}
                            >
                              <OpenInNew fontSize="small" />
                            </IconButton>
                          </Tooltip>
                        </Box>
                      </Box>
                    )}

                    {/* Tags */}
                    {credential.tags && credential.tags.length > 0 && (
                      <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5, mt: 2 }}>
                        {credential.tags.map((tag) => (
                          <Chip key={tag} label={tag} size="small" variant="outlined" />
                        ))}
                      </Box>
                    )}
                  </CardContent>

                  {/* Actions */}
                  <CardActions sx={{ justifyContent: 'flex-end', px: 2, pb: 2 }}>
                    <Button
                      size="small"
                      startIcon={<Edit />}
                      onClick={() => navigate(`/credentials/${credential.id}/edit`)}
                    >
                      Edit
                    </Button>
                  </CardActions>
                </Card>
              </Grid>
            ))}
          </Grid>
        )}

        {/* Snackbar */}
        {snackbarMessage && (
          <Alert
            severity="success"
            sx={{
              position: 'fixed',
              bottom: 24,
              left: '50%',
              transform: 'translateX(-50%)',
              zIndex: 1400,
              minWidth: 300,
            }}
            onClose={() => { setSnackbarMessage(''); }}
          >
            {snackbarMessage}
          </Alert>
        )}
      </Container>
    </Box>
  );
}

/**
 * Login Page Component
 * Handles master password and biometric authentication
 */

import { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  TextField,
  Button,
  Typography,
  IconButton,
  InputAdornment,
  Alert,
  Stack,
  Divider,
  Link,
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Fingerprint,
  Lock,
  Shield,
  PersonAdd,
} from '@mui/icons-material';
import { useAuthStore } from '../store/authStore';
import { isBiometricAvailable } from '@/core/auth/webauthn';
import { userRepository } from '@/data/repositories/UserRepositoryImpl';

type AuthMode = 'login' | 'signup';

export default function LoginPage() {
  const [mode, setMode] = useState<AuthMode>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [biometricEnabled, setBiometricEnabled] = useState(false);
  const [hasExistingAccount, setHasExistingAccount] = useState<boolean | null>(null);

  const { setUser, setSession, setVaultKey } = useAuthStore();

  // Check biometric availability and existing accounts on mount
  useEffect(() => {
    isBiometricAvailable().then(setBiometricEnabled).catch(console.error);

    // Check if any users exist
    userRepository.hasAnyUsers().then((hasUsers) => {
      setHasExistingAccount(hasUsers);
      // Default to signup if no users exist
      if (!hasUsers) {
        setMode('signup');
      }
    }).catch(console.error);
  }, []);

  const handleSignup = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSuccess(null);
    setIsLoading(true);

    try {
      // Validate passwords match
      if (password !== confirmPassword) {
        throw new Error('Passwords do not match');
      }

      // Validate password strength (minimum requirements)
      if (password.length < 12) {
        throw new Error('Password must be at least 12 characters long');
      }

      // Create new user
      const user = await userRepository.createUser(email, password);
      console.log('User created successfully');

      // Automatically authenticate after signup
      const session = await userRepository.authenticateWithPassword(email, password);

      setUser(user);
      setSession(session);
      setVaultKey(session.vaultKey);
      setSuccess('Account created successfully! Welcome to TrustVault.');

      // Update account existence state
      setHasExistingAccount(true);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to create account');
      console.error('Signup failed:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSuccess(null);
    setIsLoading(true);

    try {
      // Authenticate with user repository
      const session = await userRepository.authenticateWithPassword(email, password);

      // Get user details
      const user = await userRepository.findByEmail(email);
      if (!user) {
        throw new Error('User not found');
      }

      setUser(user);
      setSession(session);
      setVaultKey(session.vaultKey);
      console.log('Login successful');
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Invalid email or password');
      console.error('Login failed:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleBiometricLogin = async (): Promise<void> => {
    if (!email) {
      setError('Please enter your email to identify your account');
      return;
    }

    setError(null);
    setIsLoading(true);

    try {
      // Find user by email
      const targetUser = await userRepository.findByEmail(email);
      if (!targetUser) {
        throw new Error('User not found. Please sign in with your password first.');
      }

      // Check if biometric is enabled
      if (!targetUser.biometricEnabled || targetUser.webAuthnCredentials.length === 0) {
        throw new Error('Biometric authentication is not set up for this account. Please sign in with your password first.');
      }

      // Get the first biometric credential ID for authentication
      const credentialId = targetUser.webAuthnCredentials[0]?.id;
      if (!credentialId) {
        throw new Error('No biometric credential found. Please sign in with your password and re-enable biometric in Settings.');
      }

      // Perform full biometric authentication (WebAuthn + vault key decryption)
      const session = await userRepository.authenticateWithBiometric(targetUser.id, credentialId);

      // Set authentication state with vault key
      setUser(targetUser);
      setSession(session);
      setVaultKey(session.vaultKey);
      console.log('Biometric login successful');
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Biometric authentication failed');
      console.error('Biometric login failed:', err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'linear-gradient(135deg, #1a237e 0%, #0d47a1 100%)',
        padding: 3,
      }}
    >
      <Card sx={{ maxWidth: 450, width: '100%' }}>
        <CardContent sx={{ p: 4 }}>
          <Box sx={{ textAlign: 'center', mb: 4 }}>
            <Shield sx={{ fontSize: 64, color: 'primary.main', mb: 2 }} />
            <Typography variant="h4" component="h1" gutterBottom fontWeight={600}>
              TrustVault
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {mode === 'signup'
                ? 'Create your secure vault account'
                : 'Enterprise-grade security for your credentials'}
            </Typography>
          </Box>

          {error && (
            <Alert severity="error" sx={{ mb: 3 }}>
              {error}
            </Alert>
          )}

          {success && (
            <Alert severity="success" sx={{ mb: 3 }}>
              {success}
            </Alert>
          )}

          <form onSubmit={(e): void => {
            void (mode === 'signup' ? handleSignup(e) : handleLogin(e));
          }}>
            <Stack spacing={3}>
              <TextField
                fullWidth
                label="Email"
                type="email"
                value={email}
                onChange={(e): void => {
                  setEmail(e.target.value);
                }}
                required
                disabled={isLoading}
                autoComplete="email"
              />

              <TextField
                fullWidth
                label={mode === 'signup' ? 'Master Password (min 12 characters)' : 'Master Password'}
                type={showPassword ? 'text' : 'password'}
                value={password}
                onChange={(e): void => {
                  setPassword(e.target.value);
                }}
                required
                disabled={isLoading}
                autoComplete={mode === 'signup' ? 'new-password' : 'current-password'}
                helperText={mode === 'signup' ? 'Choose a strong master password. You cannot recover it if lost!' : ''}
                slotProps={{
                  input: {
                    endAdornment: (
                      <InputAdornment position="end">
                        <IconButton
                          onClick={(): void => { setShowPassword(!showPassword); }}
                          edge="end"
                        >
                          {showPassword ? <VisibilityOff /> : <Visibility />}
                        </IconButton>
                      </InputAdornment>
                    ),
                  },
                }}
              />

              {mode === 'signup' && (
                <TextField
                  fullWidth
                  label="Confirm Master Password"
                  type={showPassword ? 'text' : 'password'}
                  value={confirmPassword}
                  onChange={(e): void => {
                    setConfirmPassword(e.target.value);
                  }}
                  required
                  disabled={isLoading}
                  autoComplete="new-password"
                  error={confirmPassword.length > 0 && password !== confirmPassword}
                  helperText={
                    confirmPassword.length > 0 && password !== confirmPassword
                      ? 'Passwords do not match'
                      : ''
                  }
                />
              )}

              <Button
                fullWidth
                type="submit"
                variant="contained"
                size="large"
                disabled={isLoading}
                startIcon={mode === 'signup' ? <PersonAdd /> : <Lock />}
              >
                {isLoading
                  ? (mode === 'signup' ? 'Creating Account...' : 'Unlocking...')
                  : (mode === 'signup' ? 'Create Account' : 'Unlock Vault')}
              </Button>

              {mode === 'login' && biometricEnabled && (
                <>
                  <Divider>
                    <Typography variant="body2" color="text.secondary">
                      OR
                    </Typography>
                  </Divider>

                  <Button
                    fullWidth
                    variant="outlined"
                    size="large"
                    onClick={handleBiometricLogin}
                    disabled={isLoading}
                    startIcon={<Fingerprint />}
                  >
                    Use Biometric
                  </Button>
                </>
              )}

              {/* Toggle between login and signup */}
              {hasExistingAccount !== null && (
                <Box sx={{ textAlign: 'center', mt: 2 }}>
                  <Typography variant="body2" color="text.secondary">
                    {mode === 'login' ? "Don't have an account? " : 'Already have an account? '}
                    <Link
                      component="button"
                      type="button"
                      onClick={(): void => {
                        setMode(mode === 'login' ? 'signup' : 'login');
                        setError(null);
                        setSuccess(null);
                        setPassword('');
                        setConfirmPassword('');
                      }}
                      sx={{ cursor: 'pointer' }}
                    >
                      {mode === 'login' ? 'Create one' : 'Sign in'}
                    </Link>
                  </Typography>
                </Box>
              )}
            </Stack>
          </form>

          <Box sx={{ mt: 4, textAlign: 'center' }}>
            <Typography variant="caption" color="text.secondary">
              🔒 End-to-end encrypted • Zero-knowledge architecture
            </Typography>
          </Box>
        </CardContent>
      </Card>
    </Box>
  );
}

/**
 * Password Generator Page Component
 * Dedicated page for generating secure passwords and passphrases
 */

import { useState, useCallback, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Box,
  AppBar,
  Toolbar,
  Typography,
  IconButton,
  Button,
  Card,
  CardContent,
  TextField,
  Slider,
  FormControlLabel,
  Checkbox,
  Tabs,
  Tab,
  Stack,
  Chip,
  Switch,
  Alert,
  Paper,
  Divider,
} from '@mui/material';
import {
  ArrowBack as ArrowBackIcon,
  Refresh as RefreshIcon,
  ContentCopy as CopyIcon,
  Check as CheckIcon,
} from '@mui/icons-material';
import {
  generatePassword,
  generatePronounceablePassword,
  type PasswordGeneratorOptions,
} from '@/features/vault/generator/passwordGenerator';
import {
  generatePassphrase,
  getDefaultPassphraseOptions,
  type PassphraseOptions,
} from '@/features/vault/generator/passphraseGenerator';
import { copyPassword } from '@/presentation/utils/clipboard';

type GeneratorType = 'password' | 'passphrase' | 'pronounceable';

export default function PasswordGeneratorPage() {
  const navigate = useNavigate();

  // Generator type selection
  const [generatorType, setGeneratorType] = useState<GeneratorType>('password');

  // Password generator state
  const [passwordOptions, setPasswordOptions] = useState<PasswordGeneratorOptions>({
    length: 20,
    includeUppercase: true,
    includeLowercase: true,
    includeNumbers: true,
    includeSymbols: true,
    excludeAmbiguous: false,
  });

  // Passphrase generator state
  const [passphraseOptions, setPassphraseOptions] = useState<PassphraseOptions>(
    getDefaultPassphraseOptions()
  );

  // Pronounceable password length
  const [pronounceableLength, setPronounceableLength] = useState(16);

  // Generated output
  const [generatedPassword, setGeneratedPassword] = useState('');
  const [entropy, setEntropy] = useState(0);
  const [strength, setStrength] = useState<'weak' | 'medium' | 'strong' | 'very-strong'>('weak');

  // Copy state
  const [copySuccess, setCopySuccess] = useState(false);

  // Generate password/passphrase
  const handleGenerate = useCallback(() => {
    let result;

    switch (generatorType) {
      case 'password':
        result = generatePassword(passwordOptions);
        break;
      case 'passphrase':
        result = generatePassphrase(passphraseOptions);
        break;
      case 'pronounceable':
        result = generatePronounceablePassword(pronounceableLength);
        break;
      default:
        result = generatePassword(passwordOptions);
    }

    setGeneratedPassword(result.password);
    setEntropy(result.entropy);
    setStrength(result.strength);
  }, [generatorType, passwordOptions, passphraseOptions, pronounceableLength]);

  // Generate initial password on mount
  useEffect(() => {
    handleGenerate();
  }, [handleGenerate]);

  // Handle copy to clipboard
  const handleCopy = async () => {
    const success = await copyPassword(generatedPassword, 30);
    if (success) {
      setCopySuccess(true);
      setTimeout(() => { setCopySuccess(false); }, 2000);
    }
  };

  // Update password options
  const updatePasswordOptions = (updates: Partial<PasswordGeneratorOptions>) => {
    setPasswordOptions((prev) => ({ ...prev, ...updates }));
  };

  // Update passphrase options
  const updatePassphraseOptions = (updates: Partial<PassphraseOptions>) => {
    setPassphraseOptions((prev) => ({ ...prev, ...updates }));
  };

  // Get strength color
  const getStrengthColor = () => {
    switch (strength) {
      case 'very-strong':
        return '#4caf50'; // Green
      case 'strong':
        return '#8bc34a'; // Light green
      case 'medium':
        return '#ff9800'; // Orange
      case 'weak':
        return '#f44336'; // Red
      default:
        return '#9e9e9e'; // Gray
    }
  };

  // Get strength label
  const getStrengthLabel = () => {
    switch (strength) {
      case 'very-strong':
        return 'Very Strong';
      case 'strong':
        return 'Strong';
      case 'medium':
        return 'Medium';
      case 'weak':
        return 'Weak';
      default:
        return 'Unknown';
    }
  };

  // Check if password options are valid
  const hasValidPasswordOptions =
    passwordOptions.includeUppercase ||
    passwordOptions.includeLowercase ||
    passwordOptions.includeNumbers ||
    passwordOptions.includeSymbols;

  return (
    <Box sx={{ minHeight: '100vh', bgcolor: 'background.default' }}>
      {/* Header */}
      <AppBar position="static" elevation={0}>
        <Toolbar>
          <IconButton
            edge="start"
            color="inherit"
            onClick={() => navigate('/dashboard')}
            aria-label="back"
          >
            <ArrowBackIcon />
          </IconButton>
          <Typography variant="h6" component="h1" sx={{ ml: 2, flexGrow: 1 }}>
            Password Generator
          </Typography>
        </Toolbar>
      </AppBar>

      {/* Main Content */}
      <Box sx={{ maxWidth: 800, mx: 'auto', p: 3 }}>
        {/* Generated Password Display */}
        <Card elevation={2} sx={{ mb: 3 }}>
          <CardContent>
            <TextField
              fullWidth
              value={generatedPassword}
              InputProps={{
                readOnly: true,
                sx: {
                  fontFamily: 'monospace',
                  fontSize: '1.2rem',
                  letterSpacing: '0.5px',
                  fontWeight: 500,
                },
              }}
              multiline
              maxRows={4}
              sx={{ mb: 2 }}
            />

            {/* Actions */}
            <Stack direction="row" spacing={2} sx={{ mb: 2 }}>
              <Button
                variant="contained"
                startIcon={copySuccess ? <CheckIcon /> : <CopyIcon />}
                onClick={handleCopy}
                color={copySuccess ? 'success' : 'primary'}
                fullWidth
              >
                {copySuccess ? 'Copied!' : 'Copy to Clipboard'}
              </Button>
              <Button
                variant="outlined"
                startIcon={<RefreshIcon />}
                onClick={handleGenerate}
                fullWidth
              >
                Regenerate
              </Button>
            </Stack>

            {/* Strength Indicator */}
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
              <Box sx={{ flex: 1 }}>
                <Typography variant="caption" color="text.secondary" gutterBottom>
                  Strength
                </Typography>
                <Box
                  sx={{
                    height: 8,
                    borderRadius: 4,
                    bgcolor: 'rgba(0, 0, 0, 0.1)',
                    overflow: 'hidden',
                  }}
                >
                  <Box
                    sx={{
                      height: '100%',
                      width: `${Math.min((entropy / 128) * 100, 100)}%`,
                      bgcolor: getStrengthColor(),
                      transition: 'width 0.3s ease',
                    }}
                  />
                </Box>
              </Box>
              <Chip
                label={getStrengthLabel()}
                size="small"
                sx={{
                  bgcolor: getStrengthColor(),
                  color: 'white',
                  fontWeight: 600,
                  minWidth: 100,
                }}
              />
            </Box>

            {/* Entropy Display */}
            <Typography variant="caption" color="text.secondary" sx={{ mt: 1, display: 'block' }}>
              Entropy: {entropy.toFixed(1)} bits
            </Typography>
          </CardContent>
        </Card>

        {/* Generator Type Tabs */}
        <Card elevation={1} sx={{ mb: 3 }}>
          <Tabs
            value={generatorType}
            onChange={(_, value) => {
              setGeneratorType(value as GeneratorType);
              handleGenerate();
            }}
            variant="fullWidth"
          >
            <Tab label="Password" value="password" />
            <Tab label="Passphrase" value="passphrase" />
            <Tab label="Pronounceable" value="pronounceable" />
          </Tabs>
        </Card>

        {/* Password Generator Options */}
        {generatorType === 'password' && (
          <Card elevation={1}>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                Password Options
              </Typography>

              {/* Length Slider */}
              <Box sx={{ mb: 3 }}>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                  <Typography variant="body2" color="text.secondary">
                    Length
                  </Typography>
                  <Typography variant="body2" fontWeight="600">
                    {passwordOptions.length} characters
                  </Typography>
                </Box>
                <Slider
                  value={passwordOptions.length}
                  onChange={(_, value) => {
                    updatePasswordOptions({ length: value as number });
                  }}
                  min={8}
                  max={128}
                  step={1}
                  marks={[
                    { value: 8, label: '8' },
                    { value: 32, label: '32' },
                    { value: 64, label: '64' },
                    { value: 128, label: '128' },
                  ]}
                />
              </Box>

              <Divider sx={{ my: 2 }} />

              {/* Character Types */}
              <Typography variant="body2" color="text.secondary" gutterBottom>
                Character Types
              </Typography>
              <Stack spacing={1} sx={{ mb: 2 }}>
                <FormControlLabel
                  control={
                    <Checkbox
                      checked={passwordOptions.includeUppercase}
                      onChange={(e) =>
                        { updatePasswordOptions({ includeUppercase: e.target.checked }); }
                      }
                      disabled={!hasValidPasswordOptions && passwordOptions.includeUppercase}
                    />
                  }
                  label="Uppercase (A-Z)"
                />
                <FormControlLabel
                  control={
                    <Checkbox
                      checked={passwordOptions.includeLowercase}
                      onChange={(e) =>
                        { updatePasswordOptions({ includeLowercase: e.target.checked }); }
                      }
                      disabled={!hasValidPasswordOptions && passwordOptions.includeLowercase}
                    />
                  }
                  label="Lowercase (a-z)"
                />
                <FormControlLabel
                  control={
                    <Checkbox
                      checked={passwordOptions.includeNumbers}
                      onChange={(e) => { updatePasswordOptions({ includeNumbers: e.target.checked }); }}
                      disabled={!hasValidPasswordOptions && passwordOptions.includeNumbers}
                    />
                  }
                  label="Numbers (0-9)"
                />
                <FormControlLabel
                  control={
                    <Checkbox
                      checked={passwordOptions.includeSymbols}
                      onChange={(e) => { updatePasswordOptions({ includeSymbols: e.target.checked }); }}
                      disabled={!hasValidPasswordOptions && passwordOptions.includeSymbols}
                    />
                  }
                  label="Symbols (!@#$...)"
                />
              </Stack>

              <Divider sx={{ my: 2 }} />

              {/* Additional Options */}
              <FormControlLabel
                control={
                  <Switch
                    checked={passwordOptions.excludeAmbiguous}
                    onChange={(e) =>
                      { updatePasswordOptions({ excludeAmbiguous: e.target.checked }); }
                    }
                  />
                }
                label="Exclude ambiguous characters (0, O, l, 1, I, |)"
              />

              {!hasValidPasswordOptions && (
                <Alert severity="warning" sx={{ mt: 2 }}>
                  Please select at least one character type
                </Alert>
              )}

              <Button
                variant="contained"
                fullWidth
                onClick={handleGenerate}
                disabled={!hasValidPasswordOptions}
                sx={{ mt: 2 }}
              >
                Generate Password
              </Button>
            </CardContent>
          </Card>
        )}

        {/* Passphrase Generator Options */}
        {generatorType === 'passphrase' && (
          <Card elevation={1}>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                Passphrase Options
              </Typography>

              {/* Word Count Slider */}
              <Box sx={{ mb: 3 }}>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                  <Typography variant="body2" color="text.secondary">
                    Number of Words
                  </Typography>
                  <Typography variant="body2" fontWeight="600">
                    {passphraseOptions.wordCount} words
                  </Typography>
                </Box>
                <Slider
                  value={passphraseOptions.wordCount}
                  onChange={(_, value) => {
                    updatePassphraseOptions({ wordCount: value as number });
                  }}
                  min={4}
                  max={8}
                  step={1}
                  marks
                />
              </Box>

              <Divider sx={{ my: 2 }} />

              {/* Separator */}
              <Typography variant="body2" color="text.secondary" gutterBottom>
                Word Separator
              </Typography>
              <Stack direction="row" spacing={1} sx={{ mb: 2 }}>
                <Chip
                  label="Dash (-)"
                  onClick={() => { updatePassphraseOptions({ separator: 'dash' }); }}
                  color={passphraseOptions.separator === 'dash' ? 'primary' : 'default'}
                  variant={passphraseOptions.separator === 'dash' ? 'filled' : 'outlined'}
                />
                <Chip
                  label="Space"
                  onClick={() => { updatePassphraseOptions({ separator: 'space' }); }}
                  color={passphraseOptions.separator === 'space' ? 'primary' : 'default'}
                  variant={passphraseOptions.separator === 'space' ? 'filled' : 'outlined'}
                />
                <Chip
                  label="Symbols"
                  onClick={() => { updatePassphraseOptions({ separator: 'symbol' }); }}
                  color={passphraseOptions.separator === 'symbol' ? 'primary' : 'default'}
                  variant={passphraseOptions.separator === 'symbol' ? 'filled' : 'outlined'}
                />
                <Chip
                  label="None"
                  onClick={() => { updatePassphraseOptions({ separator: 'none' }); }}
                  color={passphraseOptions.separator === 'none' ? 'primary' : 'default'}
                  variant={passphraseOptions.separator === 'none' ? 'filled' : 'outlined'}
                />
              </Stack>

              <Divider sx={{ my: 2 }} />

              {/* Capitalization */}
              <Typography variant="body2" color="text.secondary" gutterBottom>
                Capitalization
              </Typography>
              <Stack direction="row" spacing={1} sx={{ mb: 2 }}>
                <Chip
                  label="None"
                  onClick={() => { updatePassphraseOptions({ capitalize: 'none' }); }}
                  color={passphraseOptions.capitalize === 'none' ? 'primary' : 'default'}
                  variant={passphraseOptions.capitalize === 'none' ? 'filled' : 'outlined'}
                />
                <Chip
                  label="First"
                  onClick={() => { updatePassphraseOptions({ capitalize: 'first' }); }}
                  color={passphraseOptions.capitalize === 'first' ? 'primary' : 'default'}
                  variant={passphraseOptions.capitalize === 'first' ? 'filled' : 'outlined'}
                />
                <Chip
                  label="All"
                  onClick={() => { updatePassphraseOptions({ capitalize: 'all' }); }}
                  color={passphraseOptions.capitalize === 'all' ? 'primary' : 'default'}
                  variant={passphraseOptions.capitalize === 'all' ? 'filled' : 'outlined'}
                />
                <Chip
                  label="Random"
                  onClick={() => { updatePassphraseOptions({ capitalize: 'random' }); }}
                  color={passphraseOptions.capitalize === 'random' ? 'primary' : 'default'}
                  variant={passphraseOptions.capitalize === 'random' ? 'filled' : 'outlined'}
                />
              </Stack>

              <Divider sx={{ my: 2 }} />

              {/* Include Numbers */}
              <FormControlLabel
                control={
                  <Switch
                    checked={passphraseOptions.includeNumbers}
                    onChange={(e) => { updatePassphraseOptions({ includeNumbers: e.target.checked }); }}
                  />
                }
                label="Include numbers (2-4 digits)"
              />

              <Button variant="contained" fullWidth onClick={handleGenerate} sx={{ mt: 2 }}>
                Generate Passphrase
              </Button>
            </CardContent>
          </Card>
        )}

        {/* Pronounceable Password Options */}
        {generatorType === 'pronounceable' && (
          <Card elevation={1}>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                Pronounceable Password Options
              </Typography>

              <Alert severity="info" sx={{ mb: 3 }}>
                Pronounceable passwords use alternating consonants and vowels for easier
                memorization
              </Alert>

              {/* Length Slider */}
              <Box sx={{ mb: 3 }}>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                  <Typography variant="body2" color="text.secondary">
                    Length
                  </Typography>
                  <Typography variant="body2" fontWeight="600">
                    {pronounceableLength} characters
                  </Typography>
                </Box>
                <Slider
                  value={pronounceableLength}
                  onChange={(_, value) => {
                    setPronounceableLength(value as number);
                  }}
                  min={8}
                  max={32}
                  step={1}
                  marks={[
                    { value: 8, label: '8' },
                    { value: 16, label: '16' },
                    { value: 24, label: '24' },
                    { value: 32, label: '32' },
                  ]}
                />
              </Box>

              <Button variant="contained" fullWidth onClick={handleGenerate} sx={{ mt: 2 }}>
                Generate Pronounceable Password
              </Button>
            </CardContent>
          </Card>
        )}

        {/* Info Box */}
        <Paper elevation={0} sx={{ p: 2, mt: 3, bgcolor: 'action.hover' }}>
          <Typography variant="caption" color="text.secondary">
            <strong>Security Note:</strong> All passwords are generated using cryptographically
            secure random number generators. Passwords are not stored in history. When copied, they
            are automatically cleared from clipboard after 30 seconds.
          </Typography>
        </Paper>
      </Box>
    </Box>
  );
}

/**
 * Security Audit Page
 * Shows credential health dashboard with weak, reused, and old passwords
 */

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Box,
  Container,
  Typography,
  Paper,
  AppBar,
  Toolbar,
  IconButton,
  Card,
  CardContent,
  LinearProgress,
  Chip,
  List,
  ListItem,
  ListItemText,
  ListItemIcon,
  Alert,
  AlertTitle,
  Divider,
  Button,
  CircularProgress,
} from '@mui/material';
import {
  ArrowBack,
  Warning,
  CheckCircle,
  Error,
  Info,
  Security,
  ContentCopy,
  Schedule,
  Shield,
  Refresh,
  Visibility,
} from '@mui/icons-material';
import { useCredentialStore } from '../store/credentialStore';
import { analyzePasswordStrength } from '@/core/crypto/password';
import { checkPasswordBreach, isHibpEnabled } from '@/core/breach/hibpService';
import {
  saveBreachResult,
  getBreachStatistics,
  getAllBreachedCredentials,
} from '@/data/repositories/breachResultsRepository';
import type { BreachCheckResult } from '@/core/breach/breachTypes';
import BreachDetailsModal from '../components/BreachDetailsModal';

interface SecurityIssue {
  id: string;
  title: string;
  severity: 'critical' | 'high' | 'medium' | 'low';
  type: 'weak' | 'reused' | 'old' | 'no-password' | 'breached';
  credentialTitle: string;
  credentialId?: string;
  details: string;
  breachData?: BreachCheckResult;
}

export default function SecurityAuditPage() {
  const navigate = useNavigate();
  const { credentials } = useCredentialStore();
  const [loading, setLoading] = useState(true);
  const [securityScore, setSecurityScore] = useState(0);
  const [issues, setIssues] = useState<SecurityIssue[]>([]);
  const [breachScanning, setBreachScanning] = useState(false);
  const [breachStats, setBreachStats] = useState({
    total: 0,
    breached: 0,
    safe: 0,
    bySeverity: { critical: 0, high: 0, medium: 0, low: 0, safe: 0 },
  });
  const [selectedBreach, setSelectedBreach] = useState<{
    breaches: BreachCheckResult;
    title: string;
  } | null>(null);

  useEffect(() => {
    analyzeCredentials();
    loadBreachStats();
  }, [credentials]);

  const analyzeCredentials = async () => {
    setLoading(true);

    const foundIssues: SecurityIssue[] = [];
    const passwordMap = new Map<string, string[]>(); // password -> [credential titles]
    let totalScore = 0;
    const credentialCount = credentials.length;

    // Load breach data if available
    let breachedCredentials: Array<{
      credentialId: string;
      checkType: 'password' | 'email';
      severity: string;
      breachCount: number;
      breachNames: string[];
      checkedAt: number;
    }> = [];

    if (isHibpEnabled()) {
      try {
        breachedCredentials = await getAllBreachedCredentials();
      } catch (error) {
        console.error('Failed to load breach data:', error);
      }
    }

    // Analyze each credential
    credentials.forEach((cred) => {
      // Check for breaches first (highest priority)
      const breach = breachedCredentials.find(b => b.credentialId === cred.id && b.checkType === 'password');
      if (breach) {
        const severityMap: { [key: string]: 'critical' | 'high' | 'medium' | 'low' } = {
          critical: 'critical',
          high: 'high',
          medium: 'medium',
          low: 'low',
        };

        foundIssues.push({
          id: `${cred.id}-breached`,
          title: 'Password Found in Data Breach',
          severity: severityMap[breach.severity] || 'critical',
          type: 'breached',
          credentialTitle: cred.title,
          credentialId: cred.id,
          details: `This password has been seen ${breach.breachCount.toLocaleString()} time${breach.breachCount === 1 ? '' : 's'} in data breaches. Change it immediately!`,
          breachData: {
            breached: true,
            breaches: [],
            severity: breach.severity as any,
            checkedAt: breach.checkedAt,
            breachCount: breach.breachCount,
          },
        });
      }

      // Check if password exists
      if (!cred.password || cred.password.trim() === '') {
        foundIssues.push({
          id: `${cred.id}-no-password`,
          title: 'Missing Password',
          severity: 'medium',
          type: 'no-password',
          credentialTitle: cred.title,
          credentialId: cred.id,
          details: 'This credential has no password set.',
        });
        return;
      }

      // Check password strength
      const strength = analyzePasswordStrength(cred.password);

      if (strength.score < 60) {
        foundIssues.push({
          id: `${cred.id}-weak`,
          title: 'Weak Password',
          severity: strength.score < 40 ? 'critical' : 'high',
          type: 'weak',
          credentialTitle: cred.title,
          credentialId: cred.id,
          details: `Password strength: ${strength.strength}. ${strength.feedback.join(' ')}`,
        });
      }

      // Track for reuse detection
      if (passwordMap.has(cred.password)) {
        passwordMap.get(cred.password)!.push(cred.title);
      } else {
        passwordMap.set(cred.password, [cred.title]);
      }

      // Check password age (if updatedAt available)
      if (cred.updatedAt) {
        const daysSinceUpdate = Math.floor(
          (Date.now() - new Date(cred.updatedAt).getTime()) / (1000 * 60 * 60 * 24)
        );

        if (daysSinceUpdate > 365) {
          foundIssues.push({
            id: `${cred.id}-old`,
            title: 'Password Not Updated',
            severity: daysSinceUpdate > 730 ? 'high' : 'medium',
            type: 'old',
            credentialTitle: cred.title,
            credentialId: cred.id,
            details: `Password is ${daysSinceUpdate} days old. Consider updating for better security.`,
          });
        }
      }

      // Add to total score
      totalScore += strength.score;
    });

    // Check for reused passwords
    passwordMap.forEach((titles, password) => {
      if (titles.length > 1) {
        foundIssues.push({
          id: `reused-${password.substring(0, 8)}`,
          title: 'Reused Password',
          severity: 'high',
          type: 'reused',
          credentialTitle: titles.join(', '),
          details: `This password is used on ${titles.length} accounts: ${titles.join(', ')}`,
        });
      }
    });

    // Calculate overall security score (0-100)
    const avgPasswordScore = credentialCount > 0 ? (totalScore / credentialCount) * 20 : 100; // Convert 0-5 to 0-100
    const issuesPenalty = Math.min(foundIssues.length * 5, 50); // Max 50 point penalty
    const finalScore = Math.max(0, Math.min(100, avgPasswordScore - issuesPenalty));

    setSecurityScore(Math.round(finalScore));
    setIssues(foundIssues);
    setLoading(false);
  };

  const getScoreColor = (score: number) => {
    if (score >= 80) return 'success';
    if (score >= 60) return 'info';
    if (score >= 40) return 'warning';
    return 'error';
  };

  const getScoreLabel = (score: number) => {
    if (score >= 80) return 'Excellent';
    if (score >= 60) return 'Good';
    if (score >= 40) return 'Fair';
    return 'Needs Improvement';
  };

  const getSeverityColor = (severity: string) => {
    switch (severity) {
      case 'critical':
        return 'error';
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'info';
      default:
        return 'default';
    }
  };

  const getSeverityIcon = (severity: string) => {
    switch (severity) {
      case 'critical':
      case 'high':
        return <Error color="error" />;
      case 'medium':
        return <Warning color="warning" />;
      case 'low':
        return <Info color="info" />;
      default:
        return <Info />;
    }
  };

  const loadBreachStats = async () => {
    try {
      const stats = await getBreachStatistics();
      setBreachStats(stats);
    } catch (error) {
      console.error('Failed to load breach stats:', error);
    }
  };

  const scanForBreaches = async () => {
    if (!isHibpEnabled()) {
      alert('Breach detection is not enabled. Set VITE_HIBP_API_ENABLED=true in your environment configuration.');
      return;
    }

    setBreachScanning(true);

    try {
      let scannedCount = 0;
      const totalCount = credentials.length;

      for (const credential of credentials) {
        if (!credential.password || credential.password.trim() === '') {
          continue;
        }

        try {
          const result = await checkPasswordBreach(credential.password);
          await saveBreachResult(credential.id, 'password', result);

          if (result.breached) {
            console.log(`Breach detected for ${credential.title}: ${result.breachCount} times`);
          }

          scannedCount++;

          // Update progress
          if (scannedCount % 5 === 0) {
            console.log(`Scanned ${scannedCount}/${totalCount} credentials`);
          }
        } catch (error) {
          console.error(`Failed to check breach for ${credential.title}:`, error);
        }
      }

      // Reload stats and issues
      await loadBreachStats();
      await analyzeCredentials();

      alert(`Scan complete! Checked ${scannedCount} credentials.`);
    } catch (error) {
      console.error('Breach scan failed:', error);
      alert('Failed to complete breach scan. Please try again later.');
    } finally {
      setBreachScanning(false);
    }
  };

  const handleViewBreachDetails = (issue: SecurityIssue) => {
    if (issue.breachData) {
      setSelectedBreach({
        breaches: issue.breachData,
        title: issue.credentialTitle,
      });
    }
  };

  const issuesByType = {
    weak: issues.filter((i) => i.type === 'weak').length,
    reused: issues.filter((i) => i.type === 'reused').length,
    old: issues.filter((i) => i.type === 'old').length,
    noPassword: issues.filter((i) => i.type === 'no-password').length,
    breached: issues.filter((i) => i.type === 'breached').length,
  };

  return (
    <Box sx={{ minHeight: '100vh', backgroundColor: 'background.default', pb: 4 }}>
      {/* App Bar */}
      <AppBar position="static" elevation={1}>
        <Toolbar>
          <IconButton edge="start" color="inherit" onClick={() => navigate('/dashboard')}>
            <ArrowBack />
          </IconButton>
          <Security sx={{ ml: 2, mr: 1 }} />
          <Typography variant="h6" sx={{ flexGrow: 1 }}>
            Security Audit
          </Typography>
        </Toolbar>
      </AppBar>

      <Container maxWidth="md" sx={{ mt: 4 }}>
        {/* Security Score */}
        <Paper sx={{ p: 3, mb: 3, textAlign: 'center' }}>
          <Typography variant="h5" gutterBottom>
            Vault Security Score
          </Typography>

          {loading ? (
            <Box sx={{ my: 4 }}>
              <LinearProgress />
              <Typography variant="body2" color="text.secondary" sx={{ mt: 2 }}>
                Analyzing {credentials.length} credentials...
              </Typography>
            </Box>
          ) : (
            <>
              <Box sx={{ position: 'relative', display: 'inline-flex', my: 3 }}>
                <Box
                  sx={{
                    width: 150,
                    height: 150,
                    borderRadius: '50%',
                    border: `8px solid`,
                    borderColor: `${getScoreColor(securityScore)}.main`,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    flexDirection: 'column',
                  }}
                >
                  <Typography variant="h2" fontWeight="bold">
                    {securityScore}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    / 100
                  </Typography>
                </Box>
              </Box>

              <Typography variant="h6" color={`${getScoreColor(securityScore)}.main`} gutterBottom>
                {getScoreLabel(securityScore)}
              </Typography>

              <Typography variant="body2" color="text.secondary">
                {issues.length === 0
                  ? 'All credentials are secure! Great job maintaining strong passwords.'
                  : `${issues.length} security ${issues.length === 1 ? 'issue' : 'issues'} found across ${credentials.length} credentials.`}
              </Typography>
            </>
          )}
        </Paper>

        {/* Breach Detection Card */}
        {!loading && isHibpEnabled() && (
          <Paper sx={{ p: 3, mb: 3 }}>
            <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                <Shield color={breachStats.breached > 0 ? 'error' : 'success'} />
                <Typography variant="h6">Breach Detection</Typography>
              </Box>
              <Button
                variant="outlined"
                size="small"
                startIcon={breachScanning ? <CircularProgress size={16} /> : <Refresh />}
                onClick={scanForBreaches}
                disabled={breachScanning}
              >
                {breachScanning ? 'Scanning...' : 'Scan All'}
              </Button>
            </Box>

            <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr', sm: '1fr 1fr 1fr' }, gap: 2 }}>
              <Box>
                <Typography variant="h4" color={breachStats.breached > 0 ? 'error.main' : 'success.main'}>
                  {breachStats.breached}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Breached Passwords
                </Typography>
              </Box>
              <Box>
                <Typography variant="h4" color="success.main">
                  {breachStats.safe}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Safe Passwords
                </Typography>
              </Box>
              <Box>
                <Typography variant="h4" color="text.secondary">
                  {breachStats.total}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Total Checked
                </Typography>
              </Box>
            </Box>

            {breachStats.breached > 0 && (
              <Alert severity="error" sx={{ mt: 2 }}>
                <AlertTitle>Critical: Breached Passwords Detected</AlertTitle>
                {breachStats.breached} of your passwords have been found in data breaches.
                Change them immediately to protect your accounts.
              </Alert>
            )}
          </Paper>
        )}

        {/* Summary Cards */}
        {!loading && (
          <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr', sm: '1fr 1fr' }, gap: 2, mb: 3 }}>
            <Card variant="outlined">
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 1 }}>
                  <Warning color="error" />
                  <Typography variant="h6">{issuesByType.weak}</Typography>
                </Box>
                <Typography variant="body2" color="text.secondary">
                  Weak Passwords
                </Typography>
              </CardContent>
            </Card>

            <Card variant="outlined">
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 1 }}>
                  <ContentCopy color="error" />
                  <Typography variant="h6">{issuesByType.reused}</Typography>
                </Box>
                <Typography variant="body2" color="text.secondary">
                  Reused Passwords
                </Typography>
              </CardContent>
            </Card>

            <Card variant="outlined">
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 1 }}>
                  <Schedule color="warning" />
                  <Typography variant="h6">{issuesByType.old}</Typography>
                </Box>
                <Typography variant="body2" color="text.secondary">
                  Old Passwords (1+ year)
                </Typography>
              </CardContent>
            </Card>

            <Card variant="outlined">
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 1 }}>
                  <Info color="warning" />
                  <Typography variant="h6">{issuesByType.noPassword}</Typography>
                </Box>
                <Typography variant="body2" color="text.secondary">
                  Missing Passwords
                </Typography>
              </CardContent>
            </Card>
          </Box>
        )}

        {/* Issues List */}
        {!loading && issues.length > 0 && (
          <Paper sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>
              Security Issues
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              Review and fix these issues to improve your vault security score.
            </Typography>

            <Divider sx={{ mb: 2 }} />

            <List>
              {issues.map((issue) => (
                <ListItem
                  key={issue.id}
                  sx={{
                    border: 1,
                    borderColor: 'divider',
                    borderRadius: 1,
                    mb: 1,
                    alignItems: 'flex-start',
                  }}
                >
                  <ListItemIcon sx={{ mt: 1 }}>{getSeverityIcon(issue.severity)}</ListItemIcon>
                  <ListItemText
                    primary={
                      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 0.5, flexWrap: 'wrap' }}>
                        <Typography variant="subtitle2">{issue.title}</Typography>
                        <Chip
                          label={issue.severity.toUpperCase()}
                          size="small"
                          color={getSeverityColor(issue.severity) as any}
                        />
                        {issue.type === 'breached' && (
                          <Chip
                            label="BREACHED"
                            size="small"
                            color="error"
                            icon={<Shield />}
                          />
                        )}
                      </Box>
                    }
                    secondary={
                      <>
                        <Typography variant="body2" color="text.primary" sx={{ fontWeight: 600 }}>
                          {issue.credentialTitle}
                        </Typography>
                        <Typography variant="body2" color="text.secondary">
                          {issue.details}
                        </Typography>
                        {issue.type === 'breached' && issue.breachData && (
                          <Button
                            size="small"
                            variant="text"
                            color="error"
                            startIcon={<Visibility />}
                            onClick={() => { handleViewBreachDetails(issue); }}
                            sx={{ mt: 1 }}
                          >
                            View Breach Details
                          </Button>
                        )}
                      </>
                    }
                  />
                </ListItem>
              ))}
            </List>
          </Paper>
        )}

        {/* No Issues */}
        {!loading && issues.length === 0 && (
          <Alert severity="success" icon={<CheckCircle />}>
            <AlertTitle>All Clear!</AlertTitle>
            Your vault is secure. All passwords are strong, unique, and up to date.
          </Alert>
        )}

        {/* Recommendations */}
        {!loading && issues.length > 0 && (
          <Alert severity="info" sx={{ mt: 3 }}>
            <AlertTitle>Security Recommendations</AlertTitle>
            <ul style={{ margin: '8px 0', paddingLeft: '20px' }}>
              {issuesByType.breached > 0 && (
                <li>
                  <strong>Change breached passwords immediately:</strong> Passwords found in data breaches
                  are at high risk of being used by attackers. Update them right away.
                </li>
              )}
              {issuesByType.weak > 0 && (
                <li>
                  <strong>Strengthen weak passwords:</strong> Use the password generator to create strong,
                  random passwords (16+ characters with mixed case, numbers, and symbols).
                </li>
              )}
              {issuesByType.reused > 0 && (
                <li>
                  <strong>Use unique passwords:</strong> Never reuse passwords across different accounts.
                  If one site is compromised, all accounts with that password are at risk.
                </li>
              )}
              {issuesByType.old > 0 && (
                <li>
                  <strong>Update old passwords:</strong> Change passwords that haven't been updated in over
                  a year, especially for sensitive accounts (email, banking, etc.).
                </li>
              )}
              {issuesByType.noPassword > 0 && (
                <li>
                  <strong>Add missing passwords:</strong> Complete your credential entries by adding
                  passwords where they're missing.
                </li>
              )}
            </ul>
          </Alert>
        )}
      </Container>

      {/* Breach Details Modal */}
      {selectedBreach && (
        <BreachDetailsModal
          open={true}
          onClose={() => { setSelectedBreach(null); }}
          breaches={selectedBreach.breaches.breaches}
          credentialTitle={selectedBreach.title}
          severity={selectedBreach.breaches.severity}
          breachCount={selectedBreach.breaches.breachCount ?? 0}
        />
      )}
    </Box>
  );
}

/**
 * Settings Page
 * Comprehensive settings for user preferences and security
 */

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Box,
  Container,
  Typography,
  Paper,
  Divider,
  Button,
  Alert,
  CircularProgress,
  AppBar,
  Toolbar,
  IconButton,
} from '@mui/material';
import { ArrowBack, SystemUpdate, CheckCircle, Refresh } from '@mui/icons-material';
import { useAuthStore } from '../store/authStore';
import { useCredentialStore } from '../store/credentialStore';
import { userRepository } from '@/data/repositories/UserRepositoryImpl';
import AutoLockSettings from '../components/AutoLockSettings';
import ClipboardSettings from '../components/ClipboardSettings';
import ChangeMasterPasswordDialog from '../components/ChangeMasterPasswordDialog';
import ExportDialog from '../components/ExportDialog';
import ImportDialog from '../components/ImportDialog';
import BiometricSetupDialog from '../components/BiometricSetupDialog';
import ThemeToggle from '../components/ThemeToggle';
import { useServiceWorkerUpdate } from '../hooks/useServiceWorkerUpdate';

export default function SettingsPage() {
  const navigate = useNavigate();
  const { user, setUser } = useAuthStore();
  const { clearCredentials } = useCredentialStore();

  const [saving, setSaving] = useState(false);
  const [saveMessage, setSaveMessage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [changePasswordDialogOpen, setChangePasswordDialogOpen] = useState(false);
  const [exportDialogOpen, setExportDialogOpen] = useState(false);
  const [importDialogOpen, setImportDialogOpen] = useState(false);
  const [biometricDialogOpen, setBiometricDialogOpen] = useState(false);

  // Security settings state
  const [sessionTimeout, setSessionTimeout] = useState(
    user?.securitySettings?.sessionTimeoutMinutes ?? 15
  );
  const [clipboardClearSeconds, setClipboardClearSeconds] = useState(
    user?.securitySettings?.clipboardClearSeconds ?? 30
  );

  // Service Worker update management
  const {
    updateAvailable,
    updateChecking,
    currentVersion,
    availableVersion,
    checkForUpdate,
    error: updateError,
  } = useServiceWorkerUpdate();

  // Save settings to database
  const saveSettings = async () => {
    if (!user) return;

    setSaving(true);
    setError(null);
    setSaveMessage(null);

    try {
      // Update security settings
      await userRepository.updateSecuritySettings(user.id, {
        sessionTimeoutMinutes: sessionTimeout,
        clipboardClearSeconds: clipboardClearSeconds,
      });

      // Update user in store
      const updatedUser = {
        ...user,
        securitySettings: {
          ...user.securitySettings,
          sessionTimeoutMinutes: sessionTimeout,
          clipboardClearSeconds: clipboardClearSeconds,
        },
      };

      setUser(updatedUser);

      setSaveMessage('Settings saved successfully');
      setTimeout(() => { setSaveMessage(null); }, 3000);
    } catch (err) {
      console.error('Failed to save settings:', err);
      setError('Failed to save settings. Please try again.');
    } finally {
      setSaving(false);
    }
  };

  // Auto-save when settings change
  useEffect(() => {
    const timer = setTimeout(() => {
      if (user) {
        saveSettings();
      }
    }, 500); // Debounce 500ms

    return () => { clearTimeout(timer); };
  }, [sessionTimeout, clipboardClearSeconds]);

  const handleClearAllData = async () => {
    const firstConfirm = window.confirm(
      'Are you sure you want to clear all data? This action cannot be undone.'
    );

    if (!firstConfirm) return;

    const secondConfirm = window.confirm(
      'This will permanently delete ALL your credentials and account data. Are you absolutely sure?'
    );

    if (!secondConfirm) return;

    try {
      // Clear all data
      const { clearAllData } = await import('@/data/storage/debugUtils');
      await clearAllData();

      // Clear stores
      clearCredentials();
      useAuthStore.getState().signout();

      // Navigate to signup
      navigate('/signup', { replace: true });
    } catch (err) {
      console.error('Failed to clear data:', err);
      setError('Failed to clear data. Please try again.');
    }
  };

  if (!user) {
    return (
      <Box
        sx={{
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          minHeight: '100vh',
        }}
      >
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box sx={{ minHeight: '100vh', backgroundColor: 'background.default', pb: 4 }}>
      {/* App Bar */}
      <AppBar position="static" elevation={1}>
        <Toolbar>
          <IconButton edge="start" color="inherit" onClick={() => navigate('/dashboard')}>
            <ArrowBack />
          </IconButton>
          <Typography variant="h6" sx={{ flexGrow: 1, ml: 2 }}>
            Settings
          </Typography>
          {saving && <CircularProgress size={24} color="inherit" sx={{ mr: 1 }} />}
          <ThemeToggle />
        </Toolbar>
      </AppBar>

      <Container maxWidth="md" sx={{ mt: 4 }}>
        {/* Save message */}
        {saveMessage && (
          <Alert severity="success" sx={{ mb: 3 }}>
            {saveMessage}
          </Alert>
        )}

        {/* Error message */}
        {error && (
          <Alert severity="error" sx={{ mb: 3 }} onClose={() => { setError(null); }}>
            {error}
          </Alert>
        )}

        {/* Security Settings */}
        <Typography variant="h5" gutterBottom sx={{ mb: 2 }}>
          Security Settings
        </Typography>

        <AutoLockSettings
          sessionTimeoutMinutes={sessionTimeout}
          lockOnTabHidden={false}
          onSave={(settings: { sessionTimeoutMinutes: number; lockOnTabHidden: boolean }) => {
            setSessionTimeout(settings.sessionTimeoutMinutes);
          }}
        />

        <ClipboardSettings
          clipboardClearSeconds={clipboardClearSeconds}
          onSave={(seconds) => { setClipboardClearSeconds(seconds); }}
        />

        {/* Biometric Authentication */}
        <Paper sx={{ p: 3, mb: 3 }}>
          <Typography variant="h6" gutterBottom>
            Biometric Authentication
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            Use your fingerprint, face, or security key (YubiKey, Titan) to unlock TrustVault faster.
            Your master password is still required for initial setup and critical operations.
          </Typography>

          {user.biometricEnabled && user.webAuthnCredentials.length > 0 ? (
            <Alert severity="success" sx={{ mb: 2 }}>
              <Typography variant="body2">
                ✓ Biometric authentication is enabled ({user.webAuthnCredentials.length} {user.webAuthnCredentials.length === 1 ? 'device' : 'devices'} registered)
              </Typography>
            </Alert>
          ) : (
            <Alert severity="info" sx={{ mb: 2 }}>
              No biometric credentials registered yet
            </Alert>
          )}

          <Button
            variant="outlined"
            color="primary"
            onClick={() => { setBiometricDialogOpen(true); }}
          >
            Manage Biometric Devices
          </Button>
        </Paper>

        <Divider sx={{ my: 4 }} />

        {/* Display Settings */}
        <Typography variant="h5" gutterBottom sx={{ mb: 2 }}>
          Display Settings
        </Typography>

        <Paper sx={{ p: 3, mb: 3 }}>
          <Typography variant="h6" gutterBottom>
            Theme
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            Choose your preferred color theme. (Currently Dark theme only)
          </Typography>
          <Alert severity="info">
            Light theme and system theme will be available in a future update.
          </Alert>
        </Paper>

        {/* App Updates */}
        <Paper sx={{ p: 3, mb: 3 }}>
          <Typography variant="h6" gutterBottom sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <SystemUpdate />
            App Updates
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            Check for and install updates to TrustVault PWA. Updates include new features,
            security improvements, and bug fixes.
          </Typography>

          {updateError && (
            <Alert severity="error" sx={{ mb: 2 }} onClose={() => {}}>
              {updateError}
            </Alert>
          )}

          {updateAvailable && (
            <Alert
              severity="success"
              icon={<CheckCircle />}
              sx={{ mb: 2 }}
            >
              <Typography variant="body2" fontWeight={600}>
                Update Available
              </Typography>
              <Typography variant="caption">
                {currentVersion && `Current: ${currentVersion}`}
                {availableVersion && ` → New: ${availableVersion}`}
              </Typography>
              <Typography variant="caption" display="block" sx={{ mt: 0.5 }}>
                Click the notification at the bottom of the screen to install.
              </Typography>
            </Alert>
          )}

          {!updateAvailable && !updateError && !updateChecking && currentVersion && (
            <Alert severity="info" sx={{ mb: 2 }}>
              <Typography variant="body2">
                You're running the latest version ({currentVersion})
              </Typography>
            </Alert>
          )}

          <Box sx={{ display: 'flex', gap: 2, alignItems: 'center' }}>
            <Button
              variant="outlined"
              startIcon={updateChecking ? <CircularProgress size={16} /> : <Refresh />}
              onClick={() => void checkForUpdate()}
              disabled={updateChecking}
            >
              {updateChecking ? 'Checking...' : 'Check for Updates'}
            </Button>

            {currentVersion && !updateChecking && (
              <Typography variant="caption" color="text.secondary">
                Current: {currentVersion}
              </Typography>
            )}
          </Box>

          <Typography variant="caption" color="text.secondary" display="block" sx={{ mt: 2 }}>
            💡 Updates are automatically checked in the background. You'll see a notification
            when a new version is available.
          </Typography>
        </Paper>

        <Divider sx={{ my: 4 }} />

        {/* Password Generator Defaults */}
        <Typography variant="h5" gutterBottom sx={{ mb: 2 }}>
          Password Generator Defaults
        </Typography>

        <Paper sx={{ p: 3, mb: 3 }}>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            These settings are stored locally and will be remembered when you use the password
            generator.
          </Typography>
          <Alert severity="info">
            Password generator preferences are automatically saved when you use the generator.
          </Alert>
        </Paper>

        <Divider sx={{ my: 4 }} />

        {/* Data Management */}
        <Typography variant="h5" gutterBottom sx={{ mb: 2 }}>
          Data Management
        </Typography>

        <Paper sx={{ p: 3, mb: 3 }}>
          <Typography variant="h6" gutterBottom>
            Export & Import
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
            Backup your vault with encryption or import credentials from another device.
          </Typography>

          <Box sx={{ display: 'flex', gap: 2 }}>
            <Button
              variant="outlined"
              color="primary"
              onClick={() => { setExportDialogOpen(true); }}
            >
              Export Vault
            </Button>
            <Button
              variant="outlined"
              color="primary"
              onClick={() => { setImportDialogOpen(true); }}
            >
              Import Vault
            </Button>
          </Box>
        </Paper>

        <Paper sx={{ p: 3, mb: 3 }}>
          <Typography variant="h6" gutterBottom>
            Clear All Data
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            Permanently delete all credentials and account data from this device. This action cannot
            be undone.
          </Typography>

          <Alert severity="error" sx={{ mb: 2 }}>
            <Typography variant="body2" fontWeight={600}>
              Warning: This will delete everything
            </Typography>
            <Typography variant="caption">
              All your credentials, settings, and account information will be permanently removed.
              You will need to create a new account to use TrustVault again.
            </Typography>
          </Alert>

          <Button variant="contained" color="error" onClick={handleClearAllData}>
            Clear All Data
          </Button>
        </Paper>

        <Divider sx={{ my: 4 }} />

        {/* Account Information */}
        <Typography variant="h5" gutterBottom sx={{ mb: 2 }}>
          Account
        </Typography>

        <Paper sx={{ p: 3, mb: 3 }}>
          <Typography variant="h6" gutterBottom>
            Master Password
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            Change your master password. This will re-encrypt all credentials with the new password.
          </Typography>
          <Button
            variant="outlined"
            color="primary"
            onClick={() => { setChangePasswordDialogOpen(true); }}
          >
            Change Master Password
          </Button>
        </Paper>

        <Paper sx={{ p: 3, mb: 3 }}>
          <Typography variant="h6" gutterBottom>
            Account Information
          </Typography>

          <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Email
              </Typography>
              <Typography variant="body1">{user.email}</Typography>
            </Box>

            <Box>
              <Typography variant="caption" color="text.secondary">
                Account Created
              </Typography>
              <Typography variant="body1">
                {new Date(user.createdAt).toLocaleDateString('en-US', {
                  year: 'numeric',
                  month: 'long',
                  day: 'numeric',
                  hour: '2-digit',
                  minute: '2-digit',
                })}
              </Typography>
            </Box>

            <Box>
              <Typography variant="caption" color="text.secondary">
                Last Login
              </Typography>
              <Typography variant="body1">
                {user.lastLoginAt
                  ? new Date(user.lastLoginAt).toLocaleDateString('en-US', {
                      year: 'numeric',
                      month: 'long',
                      day: 'numeric',
                      hour: '2-digit',
                      minute: '2-digit',
                    })
                  : 'Never'}
              </Typography>
            </Box>
          </Box>
        </Paper>
      </Container>

      {/* Change Master Password Dialog */}
      <ChangeMasterPasswordDialog
        open={changePasswordDialogOpen}
        onClose={() => { setChangePasswordDialogOpen(false); }}
        onSuccess={() => {
          setSaveMessage('Master password changed successfully!');
          setChangePasswordDialogOpen(false);
        }}
      />

      {/* Export Dialog */}
      <ExportDialog
        open={exportDialogOpen}
        onClose={() => { setExportDialogOpen(false); }}
        onSuccess={() => {
          setSaveMessage('Vault exported successfully!');
          setExportDialogOpen(false);
        }}
      />

      {/* Import Dialog */}
      <ImportDialog
        open={importDialogOpen}
        onClose={() => { setImportDialogOpen(false); }}
        onSuccess={(count) => {
          setSaveMessage(`Successfully imported ${count} credentials!`);
          setImportDialogOpen(false);
        }}
      />

      {/* Biometric Setup Dialog */}
      <BiometricSetupDialog
        open={biometricDialogOpen}
        onClose={() => { setBiometricDialogOpen(false); }}
      />
    </Box>
  );
}

/**
 * Signin Page Component
 * Handles user authentication with master password and biometric
 */

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Box,
  Card,
  CardContent,
  TextField,
  Button,
  Typography,
  IconButton,
  InputAdornment,
  Alert,
  Stack,
  Divider,
  Link,
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Fingerprint,
  Lock,
  Shield,
} from '@mui/icons-material';
import { useAuthStore } from '../store/authStore';
import { isBiometricAvailable } from '@/core/auth/webauthn';
import { userRepository } from '@/data/repositories/UserRepositoryImpl';

export default function SigninPage() {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [biometricEnabled, setBiometricEnabled] = useState(false);

  const { setUser, setSession, setVaultKey } = useAuthStore();

  // Check biometric availability and redirect if no accounts exist
  useEffect(() => {
    isBiometricAvailable().then(setBiometricEnabled).catch(console.error);

    // Check if any users exist - redirect to signup if none
    userRepository.hasAnyUsers().then((hasUsers) => {
      if (!hasUsers) {
        navigate('/signup', { replace: true });
      }
    }).catch(console.error);
  }, [navigate]);

  const handleSignin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setIsLoading(true);

    try {
      // Authenticate with user repository
      const session = await userRepository.authenticateWithPassword(email, password);

      // Get user details
      const user = await userRepository.findByEmail(email);
      if (!user) {
        throw new Error('User not found');
      }

      setUser(user);
      setSession(session);
      setVaultKey(session.vaultKey);
      console.log('Login successful');

      // Navigate to dashboard
      navigate('/dashboard');
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Invalid email or password');
      console.error('Login failed:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleBiometricLogin = async (): Promise<void> => {
    setError(null);
    setIsLoading(true);

    try {
      // Get all users with biometric enabled
      const biometricUsers = await userRepository.getUsersWithBiometric();

      if (biometricUsers.length === 0) {
        setError('No biometric credentials found. Please sign in with your password first and enable biometric in Settings.');
        setIsLoading(false);
        return;
      }

      // For simplicity, use the first user with biometric (in production, show a user selector)
      const user = biometricUsers[0];
      if (!user) {
        throw new Error('No user found');
      }

      // Get the first biometric credential for this user
      const credentialId = await userRepository.getFirstBiometricCredential(user.id);
      if (!credentialId) {
        setError('No biometric credentials found for this user.');
        setIsLoading(false);
        return;
      }

      // Authenticate with biometric
      const session = await userRepository.authenticateWithBiometric(user.id, credentialId);

      // Set auth state
      setUser(user);
      setSession(session);
      setVaultKey(session.vaultKey);

      console.log('Biometric login successful');

      // Navigate to dashboard
      navigate('/dashboard');
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Biometric authentication failed');
      console.error('Biometric login failed:', err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'linear-gradient(135deg, #1a237e 0%, #0d47a1 100%)',
        padding: 3,
      }}
    >
      <Card sx={{ maxWidth: 450, width: '100%' }}>
        <CardContent sx={{ p: 4 }}>
          <Box sx={{ textAlign: 'center', mb: 4 }}>
            <Shield sx={{ fontSize: 64, color: 'primary.main', mb: 2 }} />
            <Typography variant="h4" component="h1" gutterBottom fontWeight={600}>
              Welcome Back
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Sign in to access your secure vault
            </Typography>
          </Box>

          {error && (
            <Alert severity="error" sx={{ mb: 3 }}>
              {error}
            </Alert>
          )}

          <form onSubmit={(e): void => { void handleSignin(e); }}>
            <Stack spacing={3}>
              <TextField
                fullWidth
                label="Email"
                type="email"
                value={email}
                onChange={(e): void => { setEmail(e.target.value); }}
                required
                disabled={isLoading}
                autoComplete="email"
