describe('Clipboard Manager (Advanced)', () => {
  class ClipboardManager {
    private timer: NodeJS.Timeout | null = null;
    private currentText: string | null = null;

    async copy(text: string, clearAfterMs: number = 30000): Promise<void> {
      await navigator.clipboard.writeText(text);
      this.currentText = text;

      if (this.timer) {
        clearTimeout(this.timer);
      }

      this.timer = setTimeout(() => this.autoClear(), clearAfterMs);
    }

    private async autoClear(): Promise<void> {
      const current = await navigator.clipboard.readText();
      if (current === this.currentText) {
        await navigator.clipboard.writeText('');
        this.currentText = null;
      }
      this.timer = null;
    }

    async clear(): Promise<void> {
      if (this.timer) {
        clearTimeout(this.timer);
        this.timer = null;
      }
      await navigator.clipboard.writeText('');
      this.currentText = null;
    }

    cancelAutoClear(): void {
      if (this.timer) {
        clearTimeout(this.timer);
        this.timer = null;
      }
    }

    getTimeRemaining(): number {
      // Mock implementation for testing
      return this.timer ? 30 : 0;
    }
  }

  beforeEach(() => {
    vi.useFakeTimers();
    vi.clearAllMocks();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  describe('Clipboard Manager Instance', () => {
    it('should create manager instance', () => {
      const manager = new ClipboardManager();

      expect(manager).toBeDefined();
    });

    it('should copy and track text', async () => {
      const manager = new ClipboardManager();

      await manager.copy('password');

      expect(navigator.clipboard.writeText).toHaveBeenCalledWith('password');
    });

    it('should cancel previous timer on new copy', async () => {
      const manager = new ClipboardManager();

      await manager.copy('first', 1000);
      await manager.copy('second', 1000);

      // Only second timer should be active
      await vi.advanceTimersByTimeAsync(1000);

      expect(navigator.clipboard.writeText).toHaveBeenCalledTimes(3); // first, second, clear
    });

    it('should allow manual clear', async () => {
      const manager = new ClipboardManager();

      await manager.copy('password', 5000);
      await manager.clear();

      expect(navigator.clipboard.writeText).toHaveBeenCalledWith('');
    });

    it('should cancel timer on manual clear', async () => {
      const manager = new ClipboardManager();
      vi.mocked(navigator.clipboard.readText).mockResolvedValue('password');

      await manager.copy('password', 5000);
      await manager.clear();

      // Advance time - should not trigger auto-clear
      await vi.advanceTimersByTimeAsync(5000);

      expect(navigator.clipboard.writeText).toHaveBeenCalledTimes(2); // copy + manual clear only
    });

    it('should allow canceling auto-clear', async () => {
      const manager = new ClipboardManager();

      await manager.copy('password', 1000);
      manager.cancelAutoClear();

      await vi.advanceTimersByTimeAsync(1000);

      // Should not auto-clear
      expect(navigator.clipboard.writeText).toHaveBeenCalledTimes(1); // Only initial copy
    });
  });
});

/**
 * Clipboard Utilities
 * Secure clipboard operations with auto-clear functionality
 * Enhanced with SecureClipboardManager for countdown notifications
 */

/**
 * Clipboard event callback types
 */
export type ClipboardCountdownCallback = (remaining: number) => void;
export type ClipboardClearCallback = () => void;

/**
 * Copy text to clipboard with auto-clear after specified duration
 * @param text - Text to copy to clipboard
 * @param clearAfterMs - Duration in milliseconds before clearing clipboard (default: 30000ms = 30s)
 * @returns Promise that resolves to true if successful, false otherwise
 */
export async function copyToClipboard(
  text: string,
  clearAfterMs: number = 30000
): Promise<boolean> {
  try {
    // Try modern Clipboard API first
    if (navigator.clipboard && navigator.clipboard.writeText) {
      await navigator.clipboard.writeText(text);

      // Schedule clipboard clear
      if (clearAfterMs > 0) {
        setTimeout(async () => {
          try {
            // Only clear if the clipboard still contains our text
            const currentClipboard = await navigator.clipboard.readText();
            if (currentClipboard === text) {
              await navigator.clipboard.writeText('');
            }
          } catch (error) {
            // Ignore errors when clearing (user might have denied permission)
            console.debug('Could not auto-clear clipboard:', error);
          }
        }, clearAfterMs);
      }

      return true;
    }

    // Fallback for older browsers
    return fallbackCopyToClipboard(text);
  } catch (error) {
    console.error('Failed to copy to clipboard:', error);
    // Try fallback method
    return fallbackCopyToClipboard(text);
  }
}

/**
 * Fallback clipboard copy method for older browsers
 * Creates a temporary textarea element to copy text
 */
function fallbackCopyToClipboard(text: string): boolean {
  try {
    const textArea = document.createElement('textarea');
    textArea.value = text;

    // Make the textarea invisible and position it off-screen
    textArea.style.position = 'fixed';
    textArea.style.top = '-9999px';
    textArea.style.left = '-9999px';
    textArea.style.opacity = '0';
    textArea.setAttribute('readonly', '');

    document.body.appendChild(textArea);

    // Select and copy
    textArea.select();
    textArea.setSelectionRange(0, text.length);

    const successful = document.execCommand('copy');

    // Clean up
    document.body.removeChild(textArea);

    return successful;
  } catch (error) {
    console.error('Fallback copy failed:', error);
    return false;
  }
}

/**
 * Copy password to clipboard with security features
 * - Auto-clears after 30 seconds (configurable)
 * - Returns success status
 * @param password - Password to copy
 * @param clearAfterSeconds - Duration in seconds before clearing (default: 30)
 */
export async function copyPassword(
  password: string,
  clearAfterSeconds: number = 30
): Promise<boolean> {
  return copyToClipboard(password, clearAfterSeconds * 1000);
}

/**
 * Copy username to clipboard
 * - Does not auto-clear (usernames are less sensitive)
 * @param username - Username to copy
 */
export async function copyUsername(username: string): Promise<boolean> {
  return copyToClipboard(username, 0); // No auto-clear for usernames
}

/**
 * Check if clipboard API is available
 */
export function isClipboardSupported(): boolean {
  return !!(navigator.clipboard && navigator.clipboard.writeText);
}

/**
 * Get remaining time before clipboard auto-clear
 * This is a helper for showing countdown timers
 * @param copiedAt - Timestamp when text was copied
 * @param clearAfterSeconds - Duration before clearing
 * @returns Remaining seconds, or 0 if already cleared
 */
export function getRemainingClearTime(
  copiedAt: number,
  clearAfterSeconds: number
): number {
  const elapsed = (Date.now() - copiedAt) / 1000;
  const remaining = Math.max(0, clearAfterSeconds - elapsed);
  return Math.ceil(remaining);
}

/**
 * Format remaining time as human-readable string
 * @param seconds - Remaining seconds
 * @returns Formatted string like "29s" or "1m 30s"
 */
export function formatRemainingTime(seconds: number): string {
  if (seconds <= 0) return '0s';

  if (seconds < 60) {
    return `${seconds}s`;
  }

  const minutes = Math.floor(seconds / 60);
  const remainingSeconds = seconds % 60;

  if (remainingSeconds === 0) {
    return `${minutes}m`;
  }

  return `${minutes}m ${remainingSeconds}s`;
}

/**
 * Secure Clipboard Manager
 * Manages clipboard operations with auto-clear timers and countdown notifications
 */
export class SecureClipboardManager {
  private clearTimer: NodeJS.Timeout | null = null;
  private countdownTimer: NodeJS.Timeout | null = null;
  private copiedText: string = '';
  private remaining: number = 0;
  private onCountdownCallback: ClipboardCountdownCallback | null = null;
  private onClearCallback: ClipboardClearCallback | null = null;

  /**
   * Copy text to clipboard with optional auto-clear
   * @param text - Text to copy
   * @param isSensitive - Whether this is sensitive data (passwords, etc.)
   * @param clearAfterSeconds - Duration before clearing (0 = no auto-clear)
   * @returns Promise that resolves to true if successful
   */
  async copy(
    text: string,
    isSensitive: boolean = false,
    clearAfterSeconds: number = 30
  ): Promise<boolean> {
    try {
      // Cancel any existing timers
      this.cancelTimers();

      // Copy to clipboard
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(text);
      } else {
        const success = fallbackCopyToClipboard(text);
        if (!success) return false;
      }

      // Store copied text for verification
      this.copiedText = text;

      // Start auto-clear timer if sensitive and clearAfterSeconds > 0
      if (isSensitive && clearAfterSeconds > 0) {
        this.startClearTimer(clearAfterSeconds);
      }

      return true;
    } catch (error) {
      console.error('Failed to copy to clipboard:', error);
      return false;
    }
  }

  /**
   * Start the auto-clear timer with countdown
   */
  private startClearTimer(seconds: number): void {
    this.remaining = seconds;

    // Notify initial countdown
    this.onCountdownCallback?.(this.remaining);

    // Start countdown timer (updates every second)
    this.countdownTimer = setInterval(() => {
      this.remaining--;
      this.onCountdownCallback?.(this.remaining);

      if (this.remaining <= 0) {
        this.clearClipboard();
      }
    }, 1000);

    // Failsafe: clear after exact duration
    this.clearTimer = setTimeout(() => {
      this.clearClipboard();
    }, seconds * 1000);
  }

  /**
   * Clear the clipboard
   */
  private async clearClipboard(): Promise<void> {
    try {
      // Only clear if clipboard still contains our text
      if (navigator.clipboard && navigator.clipboard.readText) {
        const current = await navigator.clipboard.readText();
        if (current === this.copiedText) {
          await navigator.clipboard.writeText('');
        }
      } else {
        // Fallback: just clear regardless
        await navigator.clipboard.writeText('');
      }
    } catch (error) {
      console.debug('Could not clear clipboard:', error);
    }

    this.cancelTimers();
    this.onClearCallback?.();
  }

  /**
   * Cancel all active timers
   */
  cancelTimers(): void {
    if (this.clearTimer) {
      clearTimeout(this.clearTimer);
      this.clearTimer = null;
    }

    if (this.countdownTimer) {
      clearInterval(this.countdownTimer);
      this.countdownTimer = null;
    }

    this.remaining = 0;
    this.copiedText = '';
  }

  /**
   * Set countdown callback
   */
  onCountdown(callback: ClipboardCountdownCallback): void {
    this.onCountdownCallback = callback;
  }

  /**
   * Set clear callback
   */
  onClear(callback: ClipboardClearCallback): void {
    this.onClearCallback = callback;
  }

  /**
   * Get remaining time
   */
  getRemaining(): number {
    return this.remaining;
  }

  /**
   * Check if there's an active timer
   */
  isActive(): boolean {
    return this.clearTimer !== null;
  }
}

/**
 * Singleton instance of SecureClipboardManager
 */
export const clipboardManager = new SecureClipboardManager();

/**
 * Performance Monitoring Utilities
 * 
 * Utilities for tracking and optimizing app performance
 */

/**
 * Measure and log component render time
 */
export function measureRender(componentName: string, startTime: number): void {
  const endTime = performance.now();
  const renderTime = endTime - startTime;

  if (renderTime > 16) { // More than one frame (60fps = 16.67ms per frame)
    console.warn(`${componentName} render took ${renderTime.toFixed(2)}ms`);
  }
}

/**
 * Debounce function for expensive operations
 */
export function debounce<T extends (...args: any[]) => any>(
  func: T,
  wait: number
): (...args: Parameters<T>) => void {
  let timeout: NodeJS.Timeout | null = null;

  return function executedFunction(...args: Parameters<T>) {
    const later = () => {
      timeout = null;
      func(...args);
    };

    if (timeout) {
      clearTimeout(timeout);
    }
    timeout = setTimeout(later, wait);
  };
}

/**
 * Throttle function for limiting execution frequency
 */
export function throttle<T extends (...args: any[]) => any>(
  func: T,
  limit: number
): (...args: Parameters<T>) => void {
  let inThrottle: boolean;

  return function executedFunction(...args: Parameters<T>) {
    if (!inThrottle) {
      func(...args);
      inThrottle = true;
      setTimeout(() => inThrottle = false, limit);
    }
  };
}

/**
 * Check if app is running in standalone mode (installed PWA)
 */
export function isStandalone(): boolean {
  return (
    window.matchMedia('(display-mode: standalone)').matches ||
    (window.navigator as any).standalone === true
  );
}

/**
 * Get performance metrics
 */
export function getPerformanceMetrics() {
  if (!window.performance || !window.performance.getEntriesByType) {
    return null;
  }

  const navigation = performance.getEntriesByType('navigation')[0] as PerformanceNavigationTiming;

  if (!navigation) {
    return null;
  }

  return {
    // Time to First Byte
    ttfb: navigation.responseStart - navigation.requestStart,

    // DOM Content Loaded
    domContentLoaded: navigation.domContentLoadedEventEnd - navigation.domContentLoadedEventStart,

    // Page Load Time
    loadTime: navigation.loadEventEnd - navigation.loadEventStart,

    // Total Page Load
    totalTime: navigation.loadEventEnd - navigation.fetchStart,

    // DNS Lookup
    dnsTime: navigation.domainLookupEnd - navigation.domainLookupStart,

    // Connection Time
    connectionTime: navigation.connectEnd - navigation.connectStart,
  };
}

/**
 * Log performance metrics to console (development only)
 */
export function logPerformanceMetrics(): void {
  if (import.meta.env.PROD) return;

  window.addEventListener('load', () => {
    setTimeout(() => {
      const metrics = getPerformanceMetrics();

      if (metrics) {
        // eslint-disable-next-line no-console
        console.group('⚡ Performance Metrics');
        // eslint-disable-next-line no-console
        console.log(`TTFB: ${metrics.ttfb.toFixed(2)}ms`);
        // eslint-disable-next-line no-console
        console.log(`DOM Content Loaded: ${metrics.domContentLoaded.toFixed(2)}ms`);
        // eslint-disable-next-line no-console
        console.log(`Page Load: ${metrics.loadTime.toFixed(2)}ms`);
        // eslint-disable-next-line no-console
        console.log(`Total Time: ${metrics.totalTime.toFixed(2)}ms`);
        // eslint-disable-next-line no-console
        console.log(`DNS Lookup: ${metrics.dnsTime.toFixed(2)}ms`);
        // eslint-disable-next-line no-console
        console.log(`Connection: ${metrics.connectionTime.toFixed(2)}ms`);
        // eslint-disable-next-line no-console
        console.groupEnd();
      }
    }, 0);
  });
}

/**
 * Preload critical resources
 */
export function preloadResource(href: string, as: string): void {
  const link = document.createElement('link');
  link.rel = 'preload';
  link.href = href;
  link.as = as;
  document.head.appendChild(link);
}

/**
 * Prefetch next page for faster navigation
 */
export function prefetchPage(path: string): void {
  const link = document.createElement('link');
  link.rel = 'prefetch';
  link.href = path;
  document.head.appendChild(link);
}

/**
 * Check if user prefers reduced motion
 */
export function prefersReducedMotion(): boolean {
  return window.matchMedia('(prefers-reduced-motion: reduce)').matches;
}

/**
 * Get connection speed estimate
 */
export function getConnectionSpeed(): 'slow' | 'medium' | 'fast' | 'unknown' {
  const connection = (navigator as any).connection || (navigator as any).mozConnection || (navigator as any).webkitConnection;

  if (!connection) {
    return 'unknown';
  }

  const effectiveType = connection.effectiveType;

  if (effectiveType === 'slow-2g' || effectiveType === '2g') {
    return 'slow';
  }

  if (effectiveType === '3g') {
    return 'medium';
  }

  return 'fast';
}

/**
 * Request idle callback wrapper with fallback
 */
export function requestIdleCallbackPolyfill(callback: () => void, timeout: number = 2000): void {
  if ('requestIdleCallback' in window) {
    (window as any).requestIdleCallback(callback, { timeout });
  } else {
    setTimeout(callback, 1);
  }
}

/**
 * Measure First Input Delay (FID)
 */
export function measureFID(): void {
  if (!('PerformanceObserver' in window)) return;

  try {
    const observer = new PerformanceObserver((list) => {
      for (const entry of list.getEntries()) {
        // Type assertion for first-input entry which has processingStart
        const fidEntry = entry as PerformanceEntry & { processingStart: number };
        if ('processingStart' in entry) {
          const fid = fidEntry.processingStart - entry.startTime;
          // eslint-disable-next-line no-console
          console.log(`First Input Delay: ${fid.toFixed(2)}ms`);
        }
      }
    });

    observer.observe({ type: 'first-input', buffered: true });
  } catch (e) {
    // PerformanceObserver not supported
  }
}

/**
 * Measure Largest Contentful Paint (LCP)
 */
export function measureLCP(): void {
  if (!('PerformanceObserver' in window)) return;

  try {
    const observer = new PerformanceObserver((list) => {
      const entries = list.getEntries();
      const lastEntry = entries[entries.length - 1];
      if (lastEntry) {
        // eslint-disable-next-line no-console
        console.log(`Largest Contentful Paint: ${lastEntry.startTime.toFixed(2)}ms`);
      }
    });

    observer.observe({ type: 'largest-contentful-paint', buffered: true });
  } catch (e) {
    // PerformanceObserver not supported
  }
}

/**
 * Measure Cumulative Layout Shift (CLS)
 */
export function measureCLS(): void {
  if (!('PerformanceObserver' in window)) return;

  let clsValue = 0;

  try {
    const observer = new PerformanceObserver((list) => {
      for (const entry of list.getEntries()) {
        if (!(entry as any).hadRecentInput) {
          clsValue += (entry as any).value;
          // eslint-disable-next-line no-console
          console.log(`Cumulative Layout Shift: ${clsValue.toFixed(4)}`);
        }
      }
    });

    observer.observe({ type: 'layout-shift', buffered: true });
  } catch (e) {
    // PerformanceObserver not supported
  }
}

/**
 * Initialize performance monitoring (development only)
 */
export function initPerformanceMonitoring(): void {
  if (import.meta.env.PROD) return;

  logPerformanceMetrics();
  measureFID();
  measureLCP();
  measureCLS();

  // eslint-disable-next-line no-console
  console.log('🚀 Performance monitoring enabled');
}

